INSERT INTO public.photos VALUES (24797, 'Centro deportivo azud 2008', 'Maqueta virtual del centro deportivo del azud, junto al puerto fluvial de Vadorrey (al fondo), anunciado en 2007 y previsto sucesivamente para 2008, 2009 y 2010. Proyecto de Luis Franco y Mariano Pem‚îú√≠n, con piscina, zona de spa, sala de fitness, nueve pistas de p‚îú√≠del en la azotea, servicios de est‚îú¬Ætica y nutrici‚îú‚îÇn, cuatro salas polivalentes, cafeter‚îú¬°a y aparcamiento, adem‚îú√≠s del Centro N‚îú√≠utico Municipal. No se construy‚îú‚îÇ. Fuente: Heraldo de Arag‚îú‚îÇn.', 2008, 2008, 2008, 'Siglo XXI', 'LAS FUENTES', 41.65306300, -0.85898400, '0101000020E610000044317903CC7CEBBF249D819197D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32838829005.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32838829005.webp', 'https://www.flickr.com/photos/zaragozaantigua/32838829005/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24335, 'P.‚î¨‚ïë de la Constituci‚îú‚îÇn 1983', 'Manifestaci‚îú‚îÇn contra la pol‚îú¬°tica econ‚îú‚îÇmica del Gobierno en una imagen capturada en el paseo de la Constituci‚îú‚îÇn, a la altura de las calles de Isaac Peral y de San Ignacio de Loyola, centrada en el cortejo de la primera Izquierda Unida de Arag‚îú‚îÇn, marca electoral del Movimiento Comunista de Arag‚îú‚îÇn (MCA) para las elecciones municipales de 1983. En el centro, Ricardo Berdi‚îú¬Æ, presidente de la Asociaci‚îú‚îÇn de Vecinos de San Jos‚îú¬Æ y cabeza de lista al Ayuntamiento. Adem‚îú√≠s: Ram‚îú‚îÇn G‚îú‚îÇrriz Esp‚îú¬Æs, sindicalista de Comisiones Obreras; la militante feminista Zoya G‚îú‚îÇrriz; el fil‚îú‚îÇsofo Jos‚îú¬Æ Luis Rodr‚îú¬°guez Garc‚îú¬°a; y Merche Gallizo (ex-MCA). Tras los magros resultados electorales obtenidos, en 1987 se sumar‚îú¬°an al nuevo proyecto de convergencia pol‚îú¬°tica impulsado por colectivos y partidos comunistas y radicales de la izquierda aragonesa: Convergencia Alternativa de Arag‚îú‚îÇn-Izquierda Unida, actual Izquierda Unida de Arag‚îú‚îÇn.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64478300, -0.87744700, '0101000020E61000005F251FBB0B14ECBF2502D53F88D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48631755536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48631755536.webp', 'https://www.flickr.com/photos/zaragozaantigua/48631755536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24537, 'Calle de Miguel Servet c.1945', 'Detalle de la entrada de la boter‚îú¬°a de Ram‚îú‚îÇn Mart‚îú¬°n, que posa junto a su hijo, en la calle de Miguel Servet n‚î¨‚ïë 5, local. Este veterano inmueble de dos alturas acog‚îú¬°a a los n‚îú‚ïëmeros 5, 7, 9 y 11 de la calle. Pocos a‚îú‚ñíos despu‚îú¬Æs ser‚îú¬°a derribado y sustituido por el actual bloque del n‚î¨‚ïë 11.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64825300, -0.87522600, '0101000020E6100000137CD3F4D901ECBF56444DF4F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50573506962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50573506962.webp', 'https://www.flickr.com/photos/zaragozaantigua/50573506962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25423, 'Puente de San Jos‚îú¬Æ c.1905', '"Puerta del Duque de la Victoria y Puente de San Jos‚îú¬Æ sobre el r‚îú¬°o Huerva", dibujo en postal coloreada. Transita un coche de la l‚îú¬°nea tranviaria del Bajo Arag‚îú‚îÇn reci‚îú¬Æn electrificada.', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19573341072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19573341072.webp', 'https://www.flickr.com/photos/zaragozaantigua/19573341072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25424, 'Puente de San Jos‚îú¬Æ 1978', 'Puente de San Jos‚îú¬Æ capturado poco antes de las elecciones sindicales de 1978. Este puente ha sido el hist‚îú‚îÇrico lugar por el que superar el cauce del Huerva, y acceder al camino del Bajo Arag‚îú‚îÇn y, por el camino de San Jos‚îú¬Æ, subir adem‚îú√≠s a Torrero. Su original ubicaci‚îú‚îÇn estaba unos 300 metros aguas abajo, donde en los ‚îú‚ïëltimos a‚îú‚ñíos del XVI se instal‚îú‚îÇ un convento carmelita descalzo bajo la advocaci‚îú‚îÇn de San Jos‚îú¬Æ, que termin‚îú‚îÇ transfiri‚îú¬Ændole la denominaci‚îú‚îÇn. La ruina de ese puente en piedra sillar llev‚îú‚îÇ, con el tiempo, a esta nueva ubicaci‚îú‚îÇn, que aceler‚îú‚îÇ la apertura de la plaza de San Miguel como v‚îú¬°a de ingreso a la ciudad, pues hasta entonces no lo era. En la imagen, aspecto del puente cuando junto a ‚îú¬Æl estaba, desde 1975, el acceso al Can‚îú‚îÇdromo Zaragoza, un lucrativo lugar donde 3000 personas ve‚îú¬°an correr perros. A su lado, el Garaje Solano. A la derecha, bajo el "Stop", las instalaciones del "Tenis", que ese mismo a‚îú‚ñío fueron cambiadas por unas nuevas en la carretera del Aeropuerto.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19799956374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19799956374.webp', 'https://www.flickr.com/photos/zaragozaantigua/19799956374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25433, 'Calle Miguel Servet c.1920', 'Calle de Miguel Servet en una imagen realizada desde la glorieta que daba inicio a este vial. A la izquierda y ante el puente de san Jos‚îú¬Æ, ingreso a los lavaderos de san Jos‚îú¬Æ y la f‚îú√≠brica de pastas para sopa de Pedro Maldonado. A la derecha, ingreso al lavadero Hondo as‚îú¬° llamado por estar a medio camino entre la altura de la calle y el cauce del r‚îú¬°o. Sobre el firme, la v‚îú¬°a doble tranviaria de la l‚îú¬°nea del Bajo Arag‚îú‚îÇn y conducente a las cocheras de la empresa. Al fondo destaca la torre de la iglesia de san Miguel de los Navarros. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24619426680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24619426680.webp', 'https://www.flickr.com/photos/zaragozaantigua/24619426680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25578, 'R. Z. C. Tenis 1958', 'El C. D. Iberia jug‚îú‚îÇ ese a‚îú‚ñío la fase de ascenso a la 1‚î¨¬¨ divisi‚îú‚îÇn del baloncesto, y lo hizo jugando de local en la cancha del R. Z. C. Tenis. Sus rivales fueron el Espa‚îú‚ñíol de Barcelona y el Espa‚îú‚ñíol de Valencia, y consigui‚îú‚îÇ su objetivo, convirti‚îú¬Ændose en el primer equipo amateur que consigui‚îú‚îÇ llegar hasta la m‚îú√≠xima categor‚îú¬°a del baloncesto espa‚îú‚ñíol. En la imagen, aspecto rebosante de p‚îú‚ïëblico de la cancha del "Tenis" en uno de los encuentros de esa fase de ascenso. Detr‚îú√≠s del muro, los ‚îú√≠rboles de la ribera del Huerva, y un poco m‚îú√≠s all‚îú√≠, la mole del "Gas", el complejo del Gas‚îú‚îÇmetro, entre el Huerva, Miguel Servet, y el Camino de las Torres. Fuente visual: www.lacasadelbaloncesto.es/Visor.asp?id=1114&Fon=384', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64784700, -0.87712500, '0101000020E6100000C520B0726811ECBFE6E786A6ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15264768479.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15264768479.webp', 'https://www.flickr.com/photos/zaragozaantigua/15264768479/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25584, 'Puente de San Jos‚îú¬Æ 1860', 'Vista del puente de San Jos‚îú¬Æ sobre el r‚îú¬°o Huerva, con la iglesia de San Miguel de los Navarros detr‚îú√≠s. Fuente: Mariano J‚îú‚ïëdez y Ortiz, 1859-1860. ‚îú√ºlbum de Andr‚îú¬Æs Mart‚îú¬°n e Ip‚îú√≠s. Col. Mariano Mart‚îú¬°n Casalderrey. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20486843881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20486843881.webp', 'https://www.flickr.com/photos/zaragozaantigua/20486843881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25587, 'Paseo de la Mina 1960', 'Vista a‚îú¬Ærea del paseo de la Mina y su entorno. Inmediatos, los edificios del arranque de Miguel Servet. A la izquierda, el gas‚îú‚îÇmetro y el solar del antiguo lavadero de la se‚îú‚ñíora Benita. Sobre la l‚îú¬°nea arbolada del r‚îú¬°o Huerva, las instalaciones del Tenis. Arriba a la izquierda, la harinera Samper y el colegio de Corazonistas. A la derecha, la plaza de Jos‚îú¬Æ Antonio y los edificios de la Exposici‚îú‚îÇn Hispano-Francesa de 1908. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64835000, -0.87654700, '0101000020E61000006C054D4BAC0CECBF492EFF21FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27561259233.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27561259233.webp', 'https://www.flickr.com/photos/zaragozaantigua/27561259233/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25590, 'Camino de las Torres 1960', 'Vista a‚îú¬Ærea sobrevolando el camino de las Torres en el tramo entre el antiguo paseo de los Pl‚îú√≠tanos, y hasta casi su desemboque en Miguel Servet, donde el colegio de la Salle Montemol‚îú¬°n. A la izquierda, el r‚îú¬°o Huerva serpentea en la zona del colegio del Sagrado Coraz‚îú‚îÇn del paseo de la Mina, y las antiguas harineras de Marcos Samper, y los hermanos Solsona. A ambos lados del camino de las Torres, un panorama de antiguas torres agr‚îú¬°colas, en el que destaca el descomunal dep‚îú‚îÇsito del "Gas". En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64597100, -0.87840100, '0101000020E61000001EC2F869DC1BECBF0C957F2DAFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31746764455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31746764455.webp', 'https://www.flickr.com/photos/zaragozaantigua/31746764455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25734, 'Pol‚îú¬°gono Miraflores 1976', 'Es abril, pero no verdea mucho la prolongaci‚îú‚îÇn de Marina Moreno, que digamos. Hay una especie dominante: los postes de madera de los tendidos el‚îú¬Æctricos (recuerdo de cuando este era ferial en octubre), y por debajo de ellos, poco recuerdo de los campos, huertos, riegos, sendas, torres. La imagen est‚îú√≠ capturada desde donde hoy se levanta el C.E.I.P. Miraflores, y presenta una interesante panor‚îú√≠mica de lo que la actual avenida de Ces‚îú√≠reo Alierta era entonces: una nada con nueve modernos carriles para tr‚îú√≠fico rodado que conduc‚îú¬°a a la avenida de San Jos‚îú¬Æ desde el camino de las Torres. De izquierda a derecha, en primer lugar, los edificios de la antigua calle de la Licorera (desde 1979 calle del Escultor Francisco Burriel), todos desaparecidos. Despu‚îú¬Æs, el edificio de la avenida de San Jos‚îú¬Æ derribado sobre el que en 1988 se levantaron el n‚î¨‚ïë 54 y 56 de la avenida. A continuaci‚îú‚îÇn, los ya veteranos bloques de los n‚îú‚ïëmeros 58 a 66 (1964), y el n‚î¨‚ïë 55 y 57 de Marina Moreno. Desde ah‚îú¬°, construcciones variopintas de la avenida de San Jos‚îú¬Æ (algunas sobreviven hoy, pendientes de acuerdos entre herederos para construir y urbanizar la zona), incluyendo la parroquia de San Agust‚îú¬°n, hasta la calle de Cartagena. Finalmente, y ante la ausencia de edificaciones en altura en los n‚îú‚ïëmeros pares de ese tramo de la avenida (adem‚îú√≠s, la actual calle de Illueca no exist‚îú¬°a), visual de los n‚îú‚ïëmeros 97 (derribado y reconstruido en 1985), 99 (de 1974) y 103 (de 1972). Fuente visual: AVV San Jos‚îú¬Æ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64055900, -0.87652400, '0101000020E61000006117450F7C0CECBF49145AD6FDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20249115782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20249115782.webp', 'https://www.flickr.com/photos/zaragozaantigua/20249115782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25762, 'F‚îú√≠brica de Pastas 1927', 'Membrete de factura de la F‚îú√≠brica de Pastas para Sopa de Pedro Maldonado (antigua Maldonado Hermanos), en la calle Miguel Servet 6. En el dibujo se ve la ubicaci‚îú‚îÇn de la factor‚îú¬°a, en la actual esquina con la calle de Co‚îú¬°mbra. En primer plano, el puente de San Jos‚îú¬Æ sobre el r‚îú¬°o Huerva. Fuente: www.todocoleccion.net', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64851700, -0.87570000, '0101000020E61000002F6EA301BC05ECBF34F3E49A02D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30827619735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30827619735.webp', 'https://www.flickr.com/photos/zaragozaantigua/30827619735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25794, 'Prolongaci‚îú‚îÇn de Marina Moreno 1976', 'Imagen capturada en el denominado "Pol‚îú¬°gono 12" del barrio de San Jos‚îú¬Æ donde la prolongaci‚îú‚îÇn del paseo de Marina Moreno se nos muestra tras su cruce con el camino de las Torres, y centrada en los edificios del ‚îú‚ïëltimo tramo de la calle de Manuel Lorenzo Pardo, en el que destacan los elevados inmuebles recayentes, a la izquierda, al camino de las Torres. En el centro de la escena se abre el entonces desemboque de la calle de la Reina Fabiola. En primer t‚îú¬Ærmino, calzada de la prolongaci‚îú‚îÇn del paseo de Marina Moreno y solares convertidos en presas codiciadas por la especulaci‚îú‚îÇn inmobiliaria de la ‚îú¬Æpoca que, a pesar de lo dispuesto en la legislaci‚îú‚îÇn de la zona, consigui‚îú‚îÇ que se practicara tambi‚îú¬Æn aqu‚îú¬° el "urbanismo a la carta" para elevar de forma notable la densidad residencial que el PGOU establec‚îú¬°a como m‚îú√≠ximo en 400 habitantes por metro cuadrado, para llegar a los 1263. Esta urbanizaci‚îú‚îÇn se hizo sin previsi‚îú‚îÇn de suelo para dotaciones de servicios y con el m‚îú¬°nimo de zonas verdes (que desde el Colegio de Arquitectos se calificaban con cierta retranca de "grandes macetas"), elevando tambi‚îú¬Æn, como derivada l‚îú‚îÇgica, la congesti‚îú‚îÇn del tr‚îú√≠fico rodado privado. Los solares de la imagen comenzar‚îú¬°an a edificarse poco despu‚îú¬Æs de la toma de esta fotograf‚îú¬°a, complet‚îú√≠ndose a finales de los a‚îú‚ñíos ochenta. Todas las viviendas de esta zona eran, por supuesto, de "libre acceso", o "libres".', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64431300, -0.87615800, '0101000020E6100000DE1E84807C09ECBF9EB12FD978D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54693514422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54693514422.webp', 'https://www.flickr.com/photos/zaragozaantigua/54693514422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22049, 'Calle de la Virtud 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. El nombre de esta calle fue sustituido en 1967 por el de "cantante Pilar Lorengar". Al fondo, la calle Tom‚îú√≠s Bret‚îú‚îÇn.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64383000, -0.89651200, '0101000020E6100000F4160FEF39B0ECBF83177D0569D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14883216687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14883216687.webp', 'https://www.flickr.com/photos/zaragozaantigua/14883216687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25861, 'Multicines Bu‚îú‚ñíuel 2007', 'Foto: Mar‚îú¬°a Torres-Solanot. Aspecto de la entrada de los Multicines Bu‚îú‚ñíuel en la calle de Francisco de Vitoria 30 de Zaragoza, dos d‚îú¬°as antes de su cierre el viernes 6 de julio de 2007. Estas cuatro salas de proyecci‚îú‚îÇn fueron inauguradas en abril de 1977, a iniciativa del Partido Comunista de Espa‚îú‚ñía, aunque desde 1980 pertenec‚îú¬°an a la empresa Lauren Films. Fuente visual: Colecci‚îú‚îÇn Particular.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.64483800, -0.87888600, '0101000020E610000033315D88D51FECBFE99B340D8AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21569064523.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21569064523.webp', 'https://www.flickr.com/photos/zaragozaantigua/21569064523/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26023, 'P.‚î¨‚ïë de Marina Moreno 1974', 'A‚îú¬Ærea visual capturada sobre la prolongaci‚îú‚îÇn del paseo de Marina Moreno. Destaca el estado constructivo en gestaci‚îú‚îÇn de la manzana correspondiente a los n‚îú‚ïëmeros 16-24 del paseo. En primer t‚îú¬Ærmino, el gran solar de la antigua f‚îú√≠brica de harinas de Solsona y de la torre de Labastida, delimitado entre el colegio del Sagrado Coraz‚îú‚îÇn, el r‚îú¬°o Huerva y las instalaciones de la f‚îú√≠brica de gas (hacia la derecha, fuera de plano). Fuente visual: Jos‚îú¬Æ Jaria Serrano, en AMZ.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64550800, -0.87790700, '0101000020E61000003CBEBD6BD017ECBF37A79201A0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28210579089.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28210579089.webp', 'https://www.flickr.com/photos/zaragozaantigua/28210579089/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20868, 'Ba‚îú‚ñíos jud‚îú¬°os s. XIII', 'Ayuntamiento de Zaragoza, c. 2000. La parte conservada de los ba‚îú‚ñíos jud‚îú¬°os de Zaragoza del siglo XIII se encuentra en la calle Coso 126-132. "Su emplazamiento quedaba frente a la Juder‚îú¬°a y especialmente frente a la fortaleza conocida por Castillo de los Jud‚îú¬°os, que estaba sobre el solar que actualmente ocupa el Seminario de San Carlos. Este Castillo de los Jud‚îú¬°os serv‚îú¬°a tambi‚îú¬Æn de c‚îú√≠rcel, sinagoga mayor, hospital y carnicer‚îú¬°a. Lo conservado es ‚îú‚ïënicamente una sala de planta ligeramente rectangular, organizada a modo de claustro, con cuatro tramos en las galer‚îú¬°as cortas y cinco en las largas, abovedados con crucer‚îú¬°a sencilla, con diez columnas para separarlos del espacio central tambi‚îú¬Æn rectangular y cubierto por b‚îú‚îÇveda esquifada." Fuente: www.zaragoza.es/ciudad/postales/medieval.htm', 1250, 1200, 1299, 'Siglo XIX', 'CENTRO', 41.65103300, -0.87554900, '0101000020E6100000C57421567F04ECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14804010000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14804010000.webp', 'https://www.flickr.com/photos/zaragozaantigua/14804010000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25540, 'Desembocadura r‚îú¬°o G‚îú√≠llego 2012', 'Imagen a‚îú¬Ærea de la desembocadura del r‚îú¬°o G‚îú√≠llego en el Ebro a la altura de la ciudad de Zaragoza, en 2012. Fuente: www.zaragoza.es', 2012, 2012, 2012, 'Siglo XXI', 'LAS FUENTES', 41.65100900, -0.84822500, '0101000020E610000086C954C1A824EBBF6A334E4354D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19909177002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19909177002.webp', 'https://www.flickr.com/photos/zaragozaantigua/19909177002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20885, 'Plaza de la Sinagoga 1250', 'Dibujo incorporado a uno de los libelos que divulgaron a finales del siglo XIX y principios del XX el fant‚îú√≠stico y difamatorio rapto y asesinato del infantico Dominguito de Val por los jud‚îú¬°os de la Zaragoza de mediados del siglo XIII. La escena recoger‚îú¬°a el imaginario momento en que uno de los jud‚îú¬°os recoge en una copa la sangre del infantico para beberla luego durante la Pascua de Sangre. Seg‚îú‚ïën esta retorcida creencia, este caso ser‚îú¬°a un ejemplo de los rituales secuestros de ni‚îú‚ñíos cristianos realizados para luego asesinarlos y beber su sangre y celebrar de esta enfermiza forma la liberaci‚îú‚îÇn del pueblo jud‚îú¬°o de la esclavitud a la que fue sometido durante su estancia en el antiguo Egipto. A la derecha del dibujo, representaci‚îú‚îÇn del ficticio Moss‚îú¬Æ Albayucet, rabino que, adem‚îú√≠s de protagonizar el rapto del infante, habr‚îú¬°a sido quien le clav‚îú‚îÇ a un muro interior de la Sinagoga mayor, inmediata al callizo del Talmud, como delata el martillo que a‚îú‚ïën lleva en su mano derecha. Mientras tanto y a la izquierda, otros jud‚îú¬°os parecen regodearse con el hecho, y uno de ellos porta una lanza que luego clavar‚îú¬°a en el costado del ni‚îú‚ñío. Esta rocambolesca y truculenta historieta, bien poco amable, era la zaragozana adaptaci‚îú‚îÇn de una leyenda inglesa inventada el siglo anterior, y conten‚îú¬°a una ominosa ramificaci‚îú‚îÇn orientada a la incitaci‚îú‚îÇn fan‚îú√≠tica al odio racial y religioso de las minor‚îú¬°as no cristianas residentes en la ciudad desde siglos antes. Fuente visual: padre-hernanvergara.com', 1250, 1250, 1250, 'Siglo XIX', 'CENTRO', 41.65135200, -0.87595400, '0101000020E6100000BF9CD9AED007ECBF941799805FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40033118203.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40033118203.webp', 'https://www.flickr.com/photos/zaragozaantigua/40033118203/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20933, 'Colegio de los Jesuitas 1585', 'La imagen reproduce el dibujo con la planta para el nuevo "Colegio de Zaragoza" de la Compa‚îú‚ñí‚îú¬°a de Jes‚îú‚ïës, proyectado en el terreno adquirido en 1555 por los jesuitas donde estuviera la antigua Sinagoga mayor de la ciudad, adem‚îú√≠s del "Castillo", el "Hospital", y la "Carnicer‚îú¬°a" de los jud‚îú¬°os, una compacta manzana entre la plaza de la Sinagoga (el "Septentri‚îú‚îÇn" del plano), la calle y puerta de la Carnicer‚îú¬°a de los Jud‚îú¬°os ("Poniente"), el Coso ("Medio Dia"), y la calle de la Cunequia ("Oriente"). Al poco de la compra de este terreno, a finales de 1555, aqu‚îú¬° fue erigida una iglesia provisional bajo la advocaci‚îú‚îÇn de la Inmaculada Concepci‚îú‚îÇn, y aunque este proyectado Colegio no se ejecut‚îú‚îÇ en su literalidad, ser‚îú√≠ la g‚îú¬Ænesis del enorme complejo jesu‚îú¬°tico que a comienzos del siglo XVII fue construido en la capital del reino de Arag‚îú‚îÇn. La incidencia de este Colegio de nueva planta en el nomencl‚îú√≠tor de Zaragoza fue tambi‚îú¬Æn importante: la antigua plaza de la Sinagoga se convirti‚îú‚îÇ en la calle del Horno de la Compa‚îú‚ñí‚îú¬°a, y la calle de la Cunequia, en la de la Compa‚îú‚ñí‚îú¬°a. Fuente visual: Biblioteca Nacional de Par‚îú¬°s.', 1585, 1585, 1585, 'Siglo XIX', 'CENTRO', 41.65118900, -0.87527000, '0101000020E6100000FC6F253B3602ECBFEA4141295AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25175912406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25175912406.webp', 'https://www.flickr.com/photos/zaragozaantigua/25175912406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20954, 'Seminario 1808', 'Ruinas del Seminario. Serie Ruinas de Zaragoza, de Juan G‚îú√≠lvez (dibujo) y Fernando Brambila (grabado), C‚îú√≠diz, 1812. Vista del Coso Bajo de Zaragoza, desde la actual calle de Romea, mirando hacia Las Piedras del Coso. A nuestra derecha, las ruinas del conjunto de construcciones del Seminario, incluyendo la actual calle de San Jorge, entre el edificio a‚îú‚ïën hoy en pie, con la torreta, y el que vemos en primer plano. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65130400, -0.87524300, '0101000020E610000096B1A19BFD01ECBF83E0F1ED5DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15248519736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15248519736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15248519736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20986, 'San Pedro Nolasco 1855', '"Patio de una casa en la plaza de San Pedro Nolasco de Zaragoza". Dibujo de Valent‚îú¬°n Carderera y Solano, realizado en 1855, con una vista del renancentista patio de una casa se‚îú‚ñíorial localizada en la plaza de San Pedro Nolasco, donde la iglesia parroquial de San Lorenzo M‚îú√≠rtir, y la iglesia del colegio de San Pedro Nolasco, definen un peque‚îú‚ñío espacio entre la calle Alta de San Pedro, y la de la Ense‚îú‚ñíanza. En el momento de realizaci‚îú‚îÇn del dibujo, se identifica a su propietario como "Lazatornil", posiblemente arrendatario del cercano molino de aceite del antiguo colegio de San Vicente. Cuando, al poco, se remodele el espacio de la plaza, con el derribo de la iglesia de San Lorenzo incluido (1866), este palacio renacentista ser‚îú√≠ derribado. Fuente visual: ceres.mcu.es/', 1855, 1855, 1855, 'Siglo XIX', 'CENTRO', 41.65258700, -0.87679100, '0101000020E610000019ABCDFFAB0EECBFBA6587F887D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24383138774.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24383138774.webp', 'https://www.flickr.com/photos/zaragozaantigua/24383138774/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21054, 'Palacio de los Morlanes 1872', 'A.M.Z. Sign. 0848. Ronda zaragozana. [1872]. El dibujo reproduce un cuadro de Nicol‚îú√≠s Ruiz de Valdivia, en el que una rondalla jotera efect‚îú‚ïëa un ritual amoroso en la madrugada de san Juan, entregando un ramo de flores en la ventana de la casa palacio de los Morlanes, sita en la confluencia de la plaza de san Carlos con la calle de San Jorge.', 1872, 1872, 1872, 'Siglo XIX', 'CENTRO', 41.65167200, -0.87569700, '0101000020E6100000EA9106B7B505ECBF05DCF3FC69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856448464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856448464.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856448464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21096, 'Coso Bajo c.1880', 'El Coso bajo desde las "Piedras del Coso". A la izquierda, esquinera con la calle Santo Dominguito de Val, la gran estructura de los Graneros de la ciudad, reconvertidos precariamente en 1899 en dos escuelas municipales, adem‚îú√≠s de acoger una escuela-asilo de la organizaci‚îú‚îÇn cat‚îú‚îÇlica de La Caridad y un espacio reservado como almac‚îú¬Æn municipal. Tras ellos, el Seminario de San Carlos Borromeo tras ser retranqueado. El Coso bajo, sin los ra‚îú¬°les de la l‚îú¬°nea de Circunvalaci‚îú‚îÇn. Fuente visual: Estudio Coyne, en DARA-AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.65091200, -0.87582800, '0101000020E61000008E791D71C806ECBF77499C1551D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14777094938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14777094938.webp', 'https://www.flickr.com/photos/zaragozaantigua/14777094938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21264, 'Seminario de San Carlos 1907', 'Postal. "Colecci‚îú‚îÇn Patria y Fe n‚îú‚ïëm. 20, Zaragoza 1908 - Centenario de los Sitios", 1907. "Destruido por la explosi‚îú‚îÇn del dep‚îú‚îÇsito de p‚îú‚îÇlvora, ocurrida el 27 de junio y que dej‚îú‚îÇ sin municiones a la ciudad. Contiguo a este edificio se levantaba el Colegio de la Compa‚îú‚ñí‚îú¬°a, destruido tambi‚îú¬Æn." Las destrucciones fueron parciales, como atestigua la fotograf‚îú¬°a de un siglo despu‚îú¬Æs, y el estado actual del edificio. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65127000, -0.87502200, '0101000020E6100000F4F928232E00ECBFD66EBBD05CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20770056885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20770056885.webp', 'https://www.flickr.com/photos/zaragozaantigua/20770056885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21446, 'Calle de la Yedra c.1911', 'Imagen capturada en el segundo y ‚îú‚ïëltimo tramo de la calle de la Yedra, desde la calle de los Graneros y con el fondo del ancho desemboque en la calle de Santo Dominguito de Val, donde destaca la portada de la antigua casa de los marqueses de Torrecilla. En primer t‚îú¬Ærmino y a la izquierda, el inmueble del n‚î¨‚ïë 11 de la calle de la Yedra. A la derecha, los edificios de los n‚îú‚ïëmeros 8 y 10. La notable presencia de obreros se debe a la celebraci‚îú‚îÇn de una reuni‚îú‚îÇn en la sede de la Federaci‚îú‚îÇn local de Sociedades Obreras ubicada en la denominada "casa de Santo Dominguito", antigua casa de los Salavert, Sora y Torrecilla, con ingreso desde la transversal calle de Santo Dominguito.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65163100, -0.87650200, '0101000020E61000006D1D1CEC4D0CECBFA70705A568D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49951686093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49951686093.webp', 'https://www.flickr.com/photos/zaragozaantigua/49951686093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21537, 'Calle San Jorge 1929', 'Dibujo de Ambrosio Ruste representando el tramo de la calle de San Jorge entre la plaza de San Pedro Nolasco y la actual calle de San Vicente de Pa‚îú‚ïël. Anteriormente, esta ubicaci‚îú‚îÇn era llamada calle de la Ense‚îú‚ñíanza, por albergar en ella el Convento de las Madres de la Ense‚îú‚ñíanza, religiosas de la Compa‚îú‚ñí‚îú¬°a de Jes‚îú‚ïës. Su templo anexo fue derribado en 1929. Al fondo, la torre de la iglesia de la Concepci‚îú‚îÇn, en el Seminario de San Carlos. Fuente: ‚î¨√≠Aqu‚îú¬°... Zaragoza!, Jos‚îú¬Æ Blasco Ijazo, 1954.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19834751165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19834751165.webp', 'https://www.flickr.com/photos/zaragozaantigua/19834751165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21565, 'Calle San Jorge 1929', 'Imagen de una calle San Jorge ins‚îú‚îÇlitamente amplia, como consecuencia del reciente derribo del antiguo colegio de "La Ense‚îú‚ñíanza" de la Compa‚îú‚ñí‚îú¬°a de Mar‚îú¬°a, que con su traslado a nuevas dependencias de la calle Bilbao posibilit‚îú‚îÇ reordenar el urbanismo de la zona. A la izquierda, el edificio esquinero con la calle de la Zarza se‚îú‚ñíala la tradicional anchura "de toda la vida" de la calle de la Compa‚îú‚ñí‚îú¬°a (luego San Jorge). Frente a ‚îú¬Æl, la mole del Real Seminario de San Carlos Borromeo de los PP. Jesuitas, la plaza de San Carlos, y una panor‚îú√≠mica como nunca se hab‚îú¬°a dado del renacentista palacio de los Morlanes. Unos a‚îú‚ñíos despu‚îú¬Æs, el edificio entre la calle de la Zarza y de los Estudios tambi‚îú¬Æn ser‚îú√≠ retranqueado, y sobre el solar de primer plano se construir‚îú¬°an nuevos edificios de vivienda, configurando este tramo de la calle tal y como ahora es. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65188100, -0.87565400, '0101000020E6100000199293895B05ECBF20F12BD670D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23047894346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23047894346.webp', 'https://www.flickr.com/photos/zaragozaantigua/23047894346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21674, 'Palacio Sora 1930', 'AHPZ-Archivo MORA. 1930. Imagen del Palacio Salabert, de Torrecilla, o Sora, sito en la calle del Lim‚îú‚îÇn (luego Sto. Dominguito de Val) hasta su derribo en abril de 1936. Se le considera original sede del Talmud de la Juder‚îú¬°a Vieja, por su proximidad a la Sinagoga Principal (actual Seminario de S. Carlos Borromeo). Tras la expulsi‚îú‚îÇn de jud‚îú¬°os y jud‚îú¬°as decretada en 1492 por los Reyes Cat‚îú‚îÇlicos, la juder‚îú¬°a fue "recalificada", y esta casa vendida al notario Domingo Salabert, a precio bajo de cristiano viejo. El Palacio fue levantado en el siglo XVI, en formas y estilo renacentista, pero a la zaragozana (en ladrillo). Reformado en el XVII, se le a‚îú‚ñíadi‚îú‚îÇ una portada en piedra de factura barroco-manierista. Desde 1869 esta zona qued‚îú‚îÇ incluida en un municipal plan de apertura de una nueva calle desde el Coso hasta el Paseo del Ebro, proyecto totalmente terminado en junio de 1951. La calle de La Yedra, y su continuaci‚îú‚îÇn de Villalobos, por las que se pod‚îú¬°a acceder al Palacio desde el Coso, fueron piqueteadas, como la calle del Lim‚îú‚îÇn, que era su direcci‚îú‚îÇn postal. Del Palacio sobrevive un retablo barroco en el Museo de la ciudad, y la barroca portada, que desde el derribo del Palacio andaba extraviada, hasta que se apareci‚îú‚îÇ en mortal piedra en 1941, y los hermanos Borobio la incrustaron en la fachada del nuevo Convento de monjas de la calle Salduba n‚î¨‚ïë 8. All‚îú¬° contin‚îú‚ïëa. En la imagen, la fachada y portada del Palacio de Sora desde la Calle del Lim‚îú‚îÇn. A su derecha, y al fondo, el edificio de factura modernista que, bajo la denominaci‚îú‚îÇn postal de "Santo Dominguito Val, n‚î¨‚ïë 11", perdura en nuestros d‚îú¬°as. El solar del Palacio hoy est‚îú√≠ ocupado por el n‚î¨‚ïë 8 de S. Vicente de Pa‚îú‚ïël, y por un pedazo de la calle del mismo nombre.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65152700, -0.87652900, '0101000020E6100000D3DB9F8B860CECBF02BB9A3C65D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14829858256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14829858256.webp', 'https://www.flickr.com/photos/zaragozaantigua/14829858256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21683, 'Palacio de Sora a‚îú‚ñíos 30', 'AHPZ-Archivo Fotogr‚îú√≠fico Jos‚îú¬Æ Galiay, (SF). Portada del Palacio de Sora o Salabert.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65155900, -0.87636800, '0101000020E6100000865968E7340BECBF0D350A4966D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887569135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887569135.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887569135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21690, 'Plaza San Pedro Nolasco a‚îú‚ñíos 30', 'Mercado al aire libre en la plaza San Pedro Nolasco, siguiendo la tradici‚îú‚îÇn del lugar. Al fondo, calle San Jorge hacia Don Jaime. Fuente: Heraldo de Arag‚îú‚îÇn.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65270400, -0.87697500, '0101000020E6100000711B0DE02D10ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15054814501.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15054814501.webp', 'https://www.flickr.com/photos/zaragozaantigua/15054814501/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21882, 'Calle de Santo Dominguito de Val 1930', 'Imagen capturada en la calle de la Yedra y centrada en la portada principal de la casa del siglo XVI de los Salavert o Sora, que a finales del siglo XVII fueron ennoblecidos con el t‚îú¬°tulo de marqueses de Torrecilla. Realizado en ese siglo destaca precisamente el barroco ingreso manierista a la casa, ‚îú‚ïënico resto p‚îú¬Ætreo de esta singular casa que perdura, en otra ubicaci‚îú‚îÇn, tras su derribo cuando la apertura de la nueva calle de San Vicente de Pa‚îú‚ïël.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65163900, -0.87652400, '0101000020E61000006117450F7C0CECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47850389482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47850389482.webp', 'https://www.flickr.com/photos/zaragozaantigua/47850389482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25970, 'Fernando el Cat‚îú‚îÇlico 1945', 'Desde la torre-mirador de la nueva Feria de Muestras (Regino y Jos‚îú¬Æ Borobio Ojeda, 1943), una vista panor‚îú√≠mica al estado de cosas en la nueva, arbolada (y poco m‚îú√≠s) Avenida de Fernando el Cat‚îú‚îÇlico. La acera izquierda, hasta casi llegar a la Plaza de San Francisco, es un erial a la espera de edificaciones. La gente pasea por caminos de tierra, atravesando los solares por la tangente. A la derecha, la Imprenta Luis Vives, y los bloques del Grupo de Viviendas "Francisco Caballero". La nueva Plaza de San Francisco, a‚îú‚ïën desprovista de sus caracter‚îú¬°sticos edificios con porches, como abierto espacio de carpas y atracciones. Al fondo, la c‚îú‚ïëpula de Santiago el Mayor, el Pilar con dos torres, y la Seo. A la derecha, al fondo, el monumental gas‚îú‚îÇmetro de Camino de las Torres.', 1945, 1945, 1945, 'Anos 40', 'UNIVERSIDAD', 41.63746400, -0.89863600, '0101000020E6100000A243E048A0C1ECBF4D309C6B98D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14927363991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14927363991.webp', 'https://www.flickr.com/photos/zaragozaantigua/14927363991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21955, 'Colegio del Pilar 1946', 'Dibujo del edificio del Colegio del Pilar de los Hermanos Maristas, con fachada principal a San Vicente de Pa‚îú‚ïël 11 al 17, inaugurado en 1946. A la izquierda, calle de San Jorge; a la derecha la de San Lorenzo; detr‚îú√≠s, la plaza de San Pedro Nolasco, a donde daba su patio. El edificio, obra de F‚îú¬Ælix Ortiz, tard‚îú‚îÇ tres a‚îú‚ñíos en construirse. Su orientaci‚îú‚îÇn respond‚îú¬°a a la apertura de la nueva calle de San Vicente de Pa‚îú‚ïël, cuyas obras se prolongaron entre 1936 y 1951. En 1981, los Maristas participaron en la no declarada "Operaci‚îú‚îÇn conventos y colegios privados", y‚îú¬Ændose a la periferia (calle de Rafael Alberti 5) y quedando el inmueble en propiedad municipal. Fue sede del Instituto Mixto n‚îú‚ïëmero 4 en 1986, pese a su estado de abandono, como alternativa al desplome de esta unidad educativa en la plaza del Portillo. Tras su posterior adquisici‚îú‚îÇn y restauraci‚îú‚îÇn por la Diputaci‚îú‚îÇn General de Arag‚îú‚îÇn, ahora alberga algunas de sus dependencias. Fuente: ‚î¨√≠Aqu‚îú¬°... Zaragoza!, Jos‚îú¬Æ Blasco Ijazo, 1953.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.65244700, -0.87599900, '0101000020E6100000BE840A0E2F08ECBFC9AF1F6283D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19866047971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19866047971.webp', 'https://www.flickr.com/photos/zaragozaantigua/19866047971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21994, 'Plaza San Pedro Nolasco c.1942', 'Acuarela de Ambrosio Ruste, que muestra la iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës (1942) en la plaza de San Pedro Nolasco. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.65251700, -0.87699800, '0101000020E61000007D09151C5E10ECBFC28A53AD85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627219583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627219583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627219583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22023, 'Iglesia del Sagrado Coraz‚îú‚îÇn 1944', 'Imagen capturada en el interior de la moderna iglesia del Sagrado Coraz‚îú‚îÇn dise‚îú‚ñíada por Jos‚îú¬Æ y Regino Borobio Ojeda y sita en la plaza de San Pedro Nolasco sobre el solar de la antigua y hom‚îú‚îÇnima iglesia que fue derribada para dar paso a un programa constructivo para la orden de los jesuitas que inclu‚îú¬°a esta iglesia y una residencia. La escena recoge la celebraci‚îú‚îÇn de la fiesta de la "Cruzada Eucar‚îú¬°stica" que desde su instauraci‚îú‚îÇn durante le pontificado de P‚îú¬°o X buscaba fomentar entre los escolares y desde la m‚îú√≠s temprana edad "la frecuente y digna recepci‚îú‚îÇn de la Sagrada Comuni‚îú‚îÇn" mediante la realizaci‚îú‚îÇn de cuatro consignas "ora, comulga, sacrif‚îú¬°cate, s‚îú¬Æ ap‚îú‚îÇstol". Al fondo, testero orientado hacia el sur con el altar que culminaba la visual de la nave central. Por encima sobresale levemente la cubierta con tracer‚îú¬°a neog‚îú‚îÇtica. A la izquierda, ventanales recayentes hacia la calle de Pedro Joaqu‚îú¬°n Soler, y a la derecha, hacia el fondo de saco de la calle de Zaporta.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.65228800, -0.87712500, '0101000020E6100000C520B0726811ECBF60C9552C7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50036946297.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50036946297.webp', 'https://www.flickr.com/photos/zaragozaantigua/50036946297/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22094, 'Calle San Vicente de Pa‚îú‚ïël 1953', 'Fotograf‚îú¬°a de la calle de San Vicente de Pa‚îú‚ïël de Zaragoza, tomada desde el Coso Medio en junio de 1953. Aunque el proyecto de arrasar esa zona de la ciudad, desde el Coso Medio a la altura de la calle de la Yedra hasta el paseo del Ebro data de 1869, con nuevos intentos en 1887 y 1905, las obras de demolici‚îú‚îÇn de edificios comenzaron en 1936. La "Prolongaci‚îú‚îÇn y ensanche de la calle de la Yedra" incluy‚îú‚îÇ tambi‚îú¬Æn la "Reforma de la barriada del Sepulcro", desapareciendo las calles del C‚îú¬ªngulo, Conde de Alperche, Chantre, Graneros, Laberinto, Lez‚îú√≠un, Red, Olivo y las plazuelas de la Le‚îú‚ñía, de la Cebada, del Reino y la de Tejedores. Se salv‚îú‚îÇ en parte la de la Rosa, y se cortaron las de Santo Dominguito de Val, San Jorge, San Lorenzo, Mayor, Don Juan de Arag‚îú‚îÇn, Palafox y Sepulcro. Entre los derribos, casas significativas, como el Palacio de Sora o Salabert. Aunque la destrucci‚îú‚îÇn m‚îú√≠s significativa se dio en la d‚îú¬Æcada de los 40, se termin‚îú‚îÇ en 15 a‚îú‚ñíos, en junio de 1951. Mide 550 metros de largo y 15 de ancho. Fuente: ‚î¨√≠Aqu‚îú¬°... Zaragoza!, Jos‚îú¬Æ Blasco Ijazo, 1953.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65100600, -0.87709300, '0101000020E6100000ED9DD1562511ECBFF9BF232A54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19862801055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19862801055.webp', 'https://www.flickr.com/photos/zaragozaantigua/19862801055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22500, 'Colegio de los Maristas 1964', 'Dominguera y decembrina imagen capturada en el patio del colegio de los Maristas durante el encuentro de balonmano de la Divisi‚îú‚îÇn de Honor disputado entre el Ademar (Asociaci‚îú‚îÇn de exalumnos Maristas) de Zaragoza y el Atl‚îú¬Ætico de Madrid, que termin‚îú‚îÇ con el tanteador 16-14 favorable a los locales. La peque‚îú‚ñía y abarrotada grada del fondo estaba encajada entre la irregular y dura pista de juego y la trasera de la fachada del cuerpo principal del colegio, recayente al fondo a la calle de San Vicente de Pa‚îú‚ïël. A la derecha, peque‚îú‚ñío edificio colegial lindante con la calle de San Jorge.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65237600, -0.87629900, '0101000020E6100000658F5033A40AECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49888190777.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49888190777.webp', 'https://www.flickr.com/photos/zaragozaantigua/49888190777/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22758, 'Pl. San Pedro Nolasco 1973', 'Imagen de la plaza de San Pedro Nolasco centrada en el monumento "Zaragoza a los Hermanos Argensola", obra de Jos‚îú¬Æ Bueno en 1923, que en 1951 volvi‚îú‚îÇ a esculpir la misma estatua femenina del centro, por su desgaste. Este monumento estaba ubicado en el centro de la plaza, antigua de San Lorenzo. En 1991, una remodelaci‚îú‚îÇn integral de la plaza desplaz‚îú‚îÇ el monumento hasta su lateral disposici‚îú‚îÇn actual (a la izquierda), y la figura femenina fue sustituida por otra nueva, completamente diferente de la original en forma y fondo, entre otros modernos cambios. Al fondo, la calle de Argensola, en direcci‚îú‚îÇn a la calle Mayor. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65278700, -0.87698400, '0101000020E61000003EB0E3BF4010ECBF812040868ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32813391002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32813391002.webp', 'https://www.flickr.com/photos/zaragozaantigua/32813391002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22943, 'Coso Bajo 1983', 'Foto: Juan Gonz‚îú√≠lez Misis. El 4 de mayo de 1983, dos j‚îú‚îÇvenes zaragozanos de 23 a‚îú‚ñíos iniciaron una huelga de hambre reivindicando puestos de trabajo. En la imagen, rodeados de mensajes alusivos, en su ubicaci‚îú‚îÇn reivindicativa: el acceso al local desocupado del Coso Bajo 118, en el Edificio Espartero, esquinero con la calle de La Cadena (izquierda, fuera de plano). Fuente: Heraldo de Arag‚îú‚îÇn.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.65077000, -0.87594700, '0101000020E610000020F0C000C207ECBFE59B6D6E4CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33453478406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33453478406.webp', 'https://www.flickr.com/photos/zaragozaantigua/33453478406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23116, 'Calle San Lorenzo 2006', 'Foto: Juan Carlos Arcos. Entrada del mercadillo San Lorenzo, en el n‚îú‚ïëmero 2 de la calle hom‚îú‚îÇnima, abierta a la plaza de San Pedro Nolasco. Este establecimiento estaba dando sus ‚îú‚ïëltimas bocanadas de vida, que acab‚îú‚îÇ con una pr‚îú‚îÇrroga en 2009 y 2010 como "Mercado provisional San Vicente de Pa‚îú‚ïël", mientras se reformaba ese otro cercano mercado. Fuente: Heraldo de Arag‚îú‚îÇn.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65279000, -0.87664400, '0101000020E61000000A82C7B7770DECBFF3936A9F8ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31022016544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31022016544.webp', 'https://www.flickr.com/photos/zaragozaantigua/31022016544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23159, 'Las Piedras del Coso 2007', 'Foto: Jos‚îú¬Æ Miguel Marco. Vista del derribo en octubre de 2007 del edificio del Coso 101, en la esquina frente a la plaza de San Miguel (al fondo). Este lugar, denominado hist‚îú‚îÇricamente Las Piedras del Coso, alberga restos de la muralla romana, usada como cantera de sillares. Fuente: Heraldo de Arag‚îú‚îÇn.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65081000, -0.87641900, '0101000020E61000000DFAD2DB9F0BECBF73F4F8BD4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32481641266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32481641266.webp', 'https://www.flickr.com/photos/zaragozaantigua/32481641266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23435, 'Casa de San Carlos 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C‚îú¬°a. 1874-1877. "Casa de la Plaza de San Carlos", o Casa de los Morlanes (1555).', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65167100, -0.87560700, '0101000020E6100000ECC1A4F8F804ECBF356090F469D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679833938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679833938.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679833938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23451, 'Palacio de Sora c.1891', '"Porte d''une ancienne maison ‚îú√° Saragosse", Hubert Vaffier, 1891. Fuente: gallica.bnf.fr/', 1891, 1891, 1891, 'Siglo XIX', 'CENTRO', 41.65154700, -0.87650000, '0101000020E61000003F355EBA490CECBF496760E465D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15126613880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15126613880.webp', 'https://www.flickr.com/photos/zaragozaantigua/15126613880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23456, 'Casa de los Morlanes 1918', 'Imagen de detalle de uno de los vanos de la planta noble de la antigua Casa de los Morlanes, del pleno s. XVI. Se trata de la segunda ventana desde la izquierda de la fachada principal. La Casa ejerce de vivienda ‚îú‚ïëtil, y dos de las residentes posan en blanco nuclear, enmarcadas por laterales est‚îú¬°pites y rematadas con semicircular front‚îú‚îÇn donde grutescos, angelotes y m‚îú√≠scaras acompa‚îú‚ñían escena del Juicio de Salom‚îú‚îÇn. La Casa de los Morlanes es una casa palaciega que responde a la tipolog‚îú¬°a del palacio aragon‚îú¬Æs renacentista, de la que se conserva la fachada en ladrillo y ornamentada. La imagen se ha capturado desde ventana del Real seminario de San Carlos Borromeo. Fuente: Instituto Amatller de Arte Hisp‚îú√≠nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65157500, -0.87579400, '0101000020E6100000880E81238106ECBF13F241CF66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15718458087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15718458087.webp', 'https://www.flickr.com/photos/zaragozaantigua/15718458087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23459, 'Jean Laurent y C‚îú¬°a c.1877', 'Imagen parcial de un probable autorretrato de la fotogr‚îú√≠fica sociedad francesa Jean Laurent y C‚îú¬°a. en la puerta de acceso a la denominada "Casa de la plaza de San Carlos" (palacio de los Morlanes) que, en el momento de esta captura visual, era sede de la "F‚îú√≠brica de pianos de Arilla, Menchaca y Compa‚îú‚ñí‚îú¬°a". Esta sociedad es responsable de buena parte de las m‚îú√≠s importantes im‚îú√≠genes de la Zaragoza de las d‚îú¬Æcadas de 1860-70. Es posible que su pertenencia al g‚îú¬Ænero "guirigabacho" siga haciendo dif‚îú¬°cil su ingreso en el altamente selecto nomencl‚îú√≠tor zaragozano. Salamanca ha encontrado un hueco para ‚îú¬Æl, no obstante las cosas. En la imagen, un feroz contraluz deja en penumbra a uno de los componentes de la "C‚îú¬°a" de este redomado capturainstantes, que no lo hac‚îú¬°a por filantrop‚îú¬°a: se ganaba la vida con ello, era un currante de lo visual. Por ello introduce intencionadamente en el campo fotogr‚îú√≠fico su imprescindible complemento: el carro de los abundantes materiales, productos y utensilios para el desempe‚îú‚ñío de su profesi‚îú‚îÇn. Y en el carro, la rotulaci‚îú‚îÇn comercial que le presenta y promociona: "Fotograf‚îú¬°a de J. Laurent y Cia. Madrid, Carrera de San Ger‚îú‚îÇnimo, 39. Paris, Rue Richelieu, 90".', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65157500, -0.87579400, '0101000020E6100000880E81238106ECBF13F241CF66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17641127963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17641127963.webp', 'https://www.flickr.com/photos/zaragozaantigua/17641127963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23462, 'Palacio de los Morlanes c.1927', 'Imagen, desde cierta altura del Real Seminario de San Carlos Borromeo, de la plaza de San Carlos, el antiguo palacio de los Morlanes y, al fondo, tras las calle de San Jorge, el antiguo colegio de "La Ense‚îú‚ñíanza" de la Compa‚îú‚ñí‚îú¬°a de Mar‚îú¬°a, y la calle de la Zarza. Poco tiempo despu‚îú¬Æs, el colegio cerrar‚îú¬°a por traslado a nuevas dependencias en la calle Bilbao, y el entorno ser‚îú¬°a radicalmente reformado: retranqueo de la calle de San Jorge, apertura de una calle paralela y particular denominada "Vicente de la Forga", apertura de una extensi‚îú‚îÇn de la calle la Yedra, y construcci‚îú‚îÇn de nuevas viviendas sobre el solar resultante de toda la manzana que antes ocupaba el colegio, su iglesia gemela de la de la Santa Cruz, y las casas del colegio. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65157500, -0.87579400, '0101000020E6100000880E81238106ECBF13F241CF66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21817962603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21817962603.webp', 'https://www.flickr.com/photos/zaragozaantigua/21817962603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23463, 'Palacio Morlanes 1972', 'Plaza de San Carlos: antiguo palacio de los Morlanes. Al fondo, la calle de San Jorge. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65159700, -0.87575200, '0101000020E6100000CD02ED0E2906ECBFFB95CE8767D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22775963559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22775963559.webp', 'https://www.flickr.com/photos/zaragozaantigua/22775963559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22114, '&quot;Casa Grande&quot; 1951', 'Imagen de la Residencia Sanitaria "Jos‚îú¬Æ Antonio" en su proceso de construcci‚îú‚îÇn. Dise‚îú‚ñíada por Fernando Garc‚îú¬°a Mercadal, las obras de este contempor‚îú√≠neo zigurat sociosanitario comenzaron en 1948, siendo terminadas en 1952. La imagen ha sido capturada desde un tranquilo y apacible paseo de Isabel la Cat‚îú‚îÇlica, sin tener que molestar demasiado a los veh‚îú¬°culos a motor rodantes, a la altura de los muretes del babil‚îú‚îÇnico en extensi‚îú‚îÇn "Colegio-Residencia Nuestra Se‚îú‚ñíora del Pilar para Hu‚îú¬Ærfanos e Hijos del Magisterio". Fuente visual: Archivo fotogr‚îú√≠fico ARRIBAS adquirido por el Archivo P‚îú‚ïëblico Municipal.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.63494800, -0.90007300, '0101000020E6100000496760E465CDECBF8F54DFF945D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22308592750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22308592750.webp', 'https://www.flickr.com/photos/zaragozaantigua/22308592750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23466, 'Casa de los Morlanes c.1970', 'La Casa de los Morlanes, de mediados del siglo XVI, fue as‚îú¬° denominada porque su fachada fue posiblemente labrada por el escultor Gil Morlanes El Joven, e incluso porque all‚îú¬° habr‚îú¬°a residido esta familia. En el ‚îú‚ïëltimo tercio del siglo XIX fue sede de la F‚îú√≠brica de pianos de Arilla, Menchaca y Compa‚îú‚ñí‚îú¬°a, y m‚îú√≠s recientemente el edificio pas‚îú‚îÇ a propiedad municipal, que lo rehabilit‚îú‚îÇ y dedic‚îú‚îÇ luego a diversos servicios sociales y culturales, incluyendo la Filmoteca de Zaragoza, y desde 1997 un nuevo espacio expositivo en el s‚îú‚îÇtano. La plaza de primer t‚îú¬Ærmino, antigua de la Sinagoga, fue luego plaza del Seminario y actual de San Carlos, por la inmediata presencia del Real Seminario de San Carlos Borromeo, a la derecha y en penumbra. Al fondo, la calle de San Jorge, en cuya esquina con de la Zarza estuviera hasta los a‚îú‚ñíos veinte el gran colegio de la Ense‚îú‚ñíanza.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65165400, -0.87573100, '0101000020E6100000F0FCA204FD05ECBF5F27F56569D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150983865.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150983865.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150983865/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23475, 'Casa Morlanes a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste con una vista de la casa palacio de los Morlanes en la plaza de San Carlos. Al fondo, el colegio de la Ense‚îú‚ñíanza, en la esquina de la calle de San Jorge con la de la Zarza. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65174800, -0.87568900, '0101000020E610000035F10EF0A405ECBFE09D7C7A6CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32289601392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32289601392.webp', 'https://www.flickr.com/photos/zaragozaantigua/32289601392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23478, 'Pl. de San Carlos 1890', 'Imagen centrada en la fachada de la antigua casa denominada de los Morlanes en la plaza de San Carlos. Al fondo, en la esquina de la calle de San Jorge con la de la Zarza, el antiguo colegio de "La Ense‚îú‚ñíanza" de la Compa‚îú‚ñí‚îú¬°a de Mar‚îú¬°a. Fuente visual: fototipia de Joarizti y Mariezcurrena, en √î√á¬£Zaragoza Art‚îú¬°stica, Monumental e Hist‚îú‚îÇrica√î√á√ò, Anselmo y Pedro Gasc‚îú‚îÇn de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65158500, -0.87585800, '0101000020E610000038143E5B0707ECBF36C8242367D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34508717891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34508717891.webp', 'https://www.flickr.com/photos/zaragozaantigua/34508717891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23495, 'Plaza de San Carlos c.1877', 'Imagen de la antigua casa del siglo XVI conocida como de los Morlanes sita en la plaza de San Carlos que, en el momento de esta captura visual acog‚îú¬°a entre otros establecimientos a la F‚îú√≠brica de pianos de Arilla, Menchaca y Compa‚îú‚ñí‚îú¬°a. En la penumbra del interior, traspasada la puerta, destaca el carro de los abundantes materiales, productos y utensilios fotogr‚îú√≠ficos de la sociedad J. Laurent y Cia., responsable de la factura de esta fotograf‚îú¬°a. En primer t‚îú¬Ærmino y a la izquierda, vista parcial del pilar izquierdo sobre el que se eleva la portada de ingreso a la iglesia de la Inmaculada Concepci‚îú‚îÇn de Mar‚îú¬°a del Real Seminario de San Carlos Borromeo.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65169500, -0.87571900, '0101000020E6100000DF8B2FDAE305ECBFBDFBE3BD6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54225419607.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54225419607.webp', 'https://www.flickr.com/photos/zaragozaantigua/54225419607/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23543, 'La Ense‚îú‚ñíanza c.1927', 'AHPZ. Jos‚îú¬Æ Galiay Sara‚îú‚ñíana. Imagen del Convento de La Ense‚îú‚ñíanza, en su antigua ubicaci‚îú‚îÇn de la calle de San Jorge, tomada desde la calle del C‚îú¬°ngulo. En el siglo XVII fue creada La Compa‚îú‚ñí‚îú¬°a de Mar‚îú¬°a N. S., primer instituto religioso de car‚îú√≠cter educativo para la mujer, denominado "La Ense‚îú‚ñíanza". En 1712, por orden de Felipe V, se fund‚îú‚îÇ en Zaragoza el √î√á¬£Real Refugio de Ni‚îú‚ñías Hu‚îú¬Ærfanas√î√á√ò. De 1740 es la construcci‚îú‚îÇn de la iglesia sita en la calle de San Jorge, gemela de la de la Santa Cruz. Su autor fue Ventura Rodr‚îú¬°guez. En 1744 se funda el convento de la Compa‚îú‚ñí‚îú¬°a de Mar‚îú¬°a. En marzo de 1928 el colegio se traslada a unas nuevas instalaciones en la calle Bilbao. El antiguo edificio de la calle San Jorge fue demolido inmediatamente, y reurbanizada toda la manzana. La apertura de la nueva calle de San Vicente de Pa‚îú‚ïël en los a‚îú‚ñíos 40 del siglo XX le conferir‚îú√≠ su ordenaci‚îú‚îÇn actual.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15326232965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15326232965.webp', 'https://www.flickr.com/photos/zaragozaantigua/15326232965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23552, 'Calle San Jorge a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste, mostrando la antigua calle de la Ense‚îú‚ñíanza, luego de San Jorge, con el Convento de La Ense‚îú‚ñíanza a la izquierda, que fue demolido en los a‚îú‚ñíos 30. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19865349275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19865349275.webp', 'https://www.flickr.com/photos/zaragozaantigua/19865349275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23555, 'Coso Bajo 14 de abril 1931', 'Imagen de la "inmensa riada humana, sobre la que flotan al viento las banderas de la Rep‚îú‚ïëblica y se alzan los retratos de Gal‚îú√≠n y de Garc‚îú¬°a Hern‚îú√≠ndez", encauzada por el Coso. El colectivo posado ha sido realizado un luminoso d‚îú¬°a de abril de 1931 en la confluencia de las antiguas "Piedras del Coso" (inmediatas a la izquierda), el arranque del Coso Bajo hacia la Magdalena (al frente), y la entrada a la plaza de San Miguel por la calle de Baldomero Espartero (a la derecha).', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65078100, -0.87620200, '0101000020E6100000C712D6C6D809ECBFD9EDB3CA4CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21701272528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21701272528.webp', 'https://www.flickr.com/photos/zaragozaantigua/21701272528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23556, 'Piedras del Coso 1931', 'Imagen de uno de los escenarios conflictuales durante la dura e intensa Huelga de Telef‚îú‚îÇnica desarrollada entre finales de agosto y primeros d‚îú¬°as de setiembre de ese a‚îú‚ñío. La captura se ha realizado en el punto de enlace del Coso Medio (al fondo), la calle de Espartero, y el arranque del tramo Bajo (hacia la derecha), antiguamente denominado "Las piedras del Coso" hasta la plaza de la Magdalena. Esto era as‚îú¬° porque durante mucho tiempo la romana muralla que cercaba la ciudad fue empleada, en este lugar, como cantera de precisos sillares que fueron reciclados en numerosas construcciones posteriores. Cuando a principios del siglo XIX se construyeron las casas de la esquina, en su fachada fue colocada una placa ideada por Miguel de Villalba y Aybar, a la saz‚îú‚îÇn Regente de la Real Audiencia de Arag‚îú‚îÇn, con un ex‚îú√≠metro latino que informaba "Saxevs Hac Mvrvs Veterisqve Hic Terminvs Vrbis" ("Este es el antiguo muro de piedra que daba t‚îú¬Ærmino a la ciudad"). Esta es la placa que aparece en la imagen, en sol y sombra, por la casual incidencia cenital del sol en ese momento. Mal que bien, edificio y placa llegaron al siglo XXI en su sitio, pero en un momento determinado, la placa fue arrancada justo antes del derribo del inmueble. Luego, el edificio fue demolido. La placa, en paradero desconocido. Tal vez donde la puerta del Duque. Fuente visual: foto Palacios, "Ahora. Diario gr‚îú√≠fico" (Madrid)', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22624917319.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22624917319.webp', 'https://www.flickr.com/photos/zaragozaantigua/22624917319/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23559, 'Calle del Gallo 1967', 'Calle del Gallo, sin salida, y con entrada desde la calle de los Estudios. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65182200, -0.87492600, '0101000020E61000006D718DCF64FFEBBF1B683EE76ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22753528639.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22753528639.webp', 'https://www.flickr.com/photos/zaragozaantigua/22753528639/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26035, 'Azud del Ebro 2006', 'Foto: Esther Casas. Obras de cimentaci‚îú‚îÇn del futuro azud Manuel Lorenzo Pardo sobre el r‚îú¬°o Ebro, en agosto de 2006. Esta presa se inaugur‚îú‚îÇ en 2008, construida a fin de que las embarcaciones de recreo pudieran contar con una l‚îú√≠mina de agua estable. No sirvi‚îú‚îÇ. Tampoco se puso en marcha nunca la central hidroel‚îú¬Æctrica que habr‚îú¬°a alimentado. Ni se conoce el paso de barca alguna por las esclusas de que est‚îú√≠ provista la que, en suma, es una costos‚îú¬°sima pasarela peatonal. Algo es algo. A la derecha de la imagen, orillas del Ebro en Vadorrey. Tras el puente de la Uni‚îú‚îÇn, vista de las construcciones de la antigua ciudad. Fuente: Heraldo de Arag‚îú‚îÇn.', 2006, 2006, 2006, 'Siglo XXI', 'LAS FUENTES', 41.65285100, -0.85678700, '0101000020E61000001A6A1492CC6AEBBF98141F9F90D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31192780334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31192780334.webp', 'https://www.flickr.com/photos/zaragozaantigua/31192780334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23562, 'Calle San Jorge c.1927', 'Imagen de la calle San Jorge con visual parcial de los antiguos aleros del colegio de "La Ense‚îú‚ñíanza" de la Compa‚îú‚ñí‚îú¬°a de Mar‚îú¬°a. La captura se ha realizado desde la altura del n‚î¨‚ïë 28 de esa calle, justo enfrente, un peculiar edificio que conformaba extra‚îú‚ñía esquina con la calle C‚îú¬°ngulo. A la derecha, galer‚îú¬°a de arquillos cegados y alero del gran edificio principal del colegio, entre la calle San Jorge y la de la Zarza. El alero m‚îú√≠s inmediato, e inferior de altura, formaba parte de unas dependencias que configuraban un patio interior del complejo colegial. Si alguien necesita urgentemente hacer una comparativa con el tiempo m‚îú√≠s cercano, que siempre ser‚îú√≠ pasado, tendr‚îú¬°a que situarse justo en la confluencia de las actuales calles de San Vicente de Pa‚îú‚ïël, y de San Jorge, pero poco rato. ‚îú√ºnimo. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23097774451.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23097774451.webp', 'https://www.flickr.com/photos/zaragozaantigua/23097774451/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23571, 'Iglesia de San Carlos a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste mostrando la puerta de la iglesia del Seminario de San Carlos, en la plaza hom‚îú‚îÇnima. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65169200, -0.87558200, '0101000020E6100000B3EBDE8AC404ECBF4C88B9A46AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629310463.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629310463.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629310463/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23577, 'Calle de San Jorge 1931', 'Imagen del antiguo Convento de la Ense‚îú‚ñíanza durante su derribo. Sus primeras instalaciones fueron inauguradas como colegio en los ‚îú‚ïëltimos a‚îú‚ñíos del siglo XVII en la entonces calle de la Compa‚îú‚ñí‚îú¬°a. Desde 1712 fue Real Refugio de Ni‚îú‚ñías Hu‚îú¬Ærfanas, y en 1744 ya funcion‚îú‚îÇ como Real Colegio de la Compa‚îú‚ñí‚îú¬°a de Mar‚îú¬°a. Tras su traslado a una nueva, mayor y m‚îú√≠s moderna ubicaci‚îú‚îÇn en la calle de Bilbao, el antiguo convento-colegio fue derribado y sobre su solar se construy‚îú‚îÇ una nueva manzana edilicia, dejando espacio para la prevista prolongaci‚îú‚îÇn de la calle de la Yedra desde el Coso hasta el paseo de la Ribera, proyecto que a‚îú‚ñíos m‚îú√≠s tarde se concretar‚îú√≠ en la apertura de la nueva calle de San Vicente de Pa‚îú‚ïël. Despu‚îú¬Æs del derribo del colegio, este tramo de la calle de San Jorge fue tambi‚îú¬Æn ensanchado unos metros. En la imagen, a la derecha, fachada principal del antiguo colegio, en la que destaca bajo los rayos de sol el ingreso a la iglesia colegial dise‚îú‚ñíada por el arquitecto Ventura Rodr‚îú¬°guez Tiz‚îú‚îÇn. La inmediata zona recayente a la calle de la Zarza ya ha sido derribada. Al fondo, angular zona de encuentro de la calle de San Jorge con la calle del C‚îú¬°ngulo. A la izquierda, fachada de la Casa de los Morlanes, con entrada principal desde la plaza de San Carlos. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65192900, -0.87576100, '0101000020E61000009A97C3EE3B06ECBF3128D36872D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34498969853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34498969853.webp', 'https://www.flickr.com/photos/zaragozaantigua/34498969853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23597, 'Plazuela de San Carlos 1929', 'Imagen capturada en la plazuela de San Carlos a la puerta del hom‚îú‚îÇnimo Seminario Sacerdotal con un grupal posado de caballeros y damas de la nobil‚îú¬°sima Real Maestranza de Caballer‚îú¬°a de Zaragoza a la salida del oficio religioso realizado en la barroca iglesia del seminario en honor de su patrono el se‚îú‚ñíor San Jorge. En el centro de la escena y en segundo plano, el destacado caballero Luis Gonzaga de Azara y L‚îú‚îÇpez Fern‚îú√≠ndez de Heredia, marqu‚îú¬Æs de Nibbiano.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65143000, -0.87585900, '0101000020E61000004F081D740907ECBF0FD1E80E62D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52153195619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52153195619.webp', 'https://www.flickr.com/photos/zaragozaantigua/52153195619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23598, 'Plazuela de San Carlos c.1925', 'In‚îú¬Ædita imagen capturada desde la segunda planta de la municipal escuela "los Graneros" habilitada en el antiguo Almud‚îú¬° de la ciudad y con entrada por la calle de Santo Dominguito de Val (actual Centro P‚îú‚ïëblico de Educaci‚îú‚îÇn para Adultos "Concepci‚îú‚îÇn Arenal"). Centra la escena la empedrada plazuela de San Carlos (antigua del Seminario), dominada por la rotunda fachada barroca del Real Seminario de San Carlos del que emerge la esbelta torre emplazada a la derecha de la puerta de ingreso a la iglesia de la Inmaculada adosada al Seminario. A la izquierda, primeros n‚îú‚ïëmeros de la plazuela, donde destaca el inmueble del n‚î¨‚ïë 2, tras el cual queda el n‚î¨‚ïë 3, antigua casa de los Morlanes entonces con funciones de sucursal de la f‚îú√≠brica de aguardientes "la Industrial Licorera Espa‚îú‚ñíola S.A. Cooperativa". Al fondo y tras la calle de San Jorge, leve vista de la manzana de casas delimitada entre las calles de la Zarza, el Espino y los Estudios. A‚îú‚ñíos m‚îú√≠s tarde esa manzana ser‚îú¬°a retranqueada para homologar la anchura de ese tramo de la calle de San Jorge hasta entonces bien recoleto, y lo mismo se har‚îú¬°a con sus fachadas recayentes a las calles de la Zarza y del Espino.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65146200, -0.87592300, '0101000020E6100000FE0DDAAB8F07ECBF1B4B581B63D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53231312979.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53231312979.webp', 'https://www.flickr.com/photos/zaragozaantigua/53231312979/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23607, 'Coso Medio c.1884', 'Tramo medio del Coso, entre "Las piedras del Coso" (esquina de la derecha) hasta la actual plaza de Espa‚îú‚ñía (con la fuente de la Princesa, al fondo). A la izquierda y delimitada por las calles del Agua y de Flandro, la dieciochesca casa de Juan Bautista Casabona, proyectada por el arquitecto Agust‚îú¬°n Sanz.', 1884, 1884, 1884, 'Siglo XIX', 'CENTRO', 41.65068000, -0.87657500, '0101000020E6100000E9B7AF03E70CECBFA514747B49D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974349567.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974349567.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974349567/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23615, 'Coso Medio 1902', 'Imagen del tramo medio del Coso zaragozano, entre "Las piedras del Coso" (esquina de la derecha) hasta la plaza de la Constituci‚îú‚îÇn al fondo, donde sigue Neptuno. En los laterales de la calzada, los nuevos carriles de v‚îú¬°a necesarios para el cambio a la tracci‚îú‚îÇn el‚îú¬Æctrica. A finales de a‚îú‚ñío ya estar‚îú√≠ terminada la electrificaci‚îú‚îÇn de las l‚îú¬°neas que por aqu‚îú¬° pasan: la del Bajo Arag‚îú‚îÇn, y la de Circunvalaci‚îú‚îÇn. Mientras, la original tracci‚îú‚îÇn, a propulsi‚îú‚îÇn de sangre, sigue prestando servicio. A la izquierda y delimitada por las calles del Agua y de Flandro, la dieciochesca casa de Juan Bautista Casabona, proyectada por el arquitecto Agust‚îú¬°n Sanz y remodelada a finales de la d‚îú¬Æcada de 1880.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18938622113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18938622113.webp', 'https://www.flickr.com/photos/zaragozaantigua/18938622113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25124, 'Cementerio de La Cartuja 1947', 'Camposanto del hospital, acuarela sobre papel, Guillermo P‚îú¬Ærez Bailo, Diputaci‚îú‚îÇn de Zaragoza, 1947. Fuente: web.dpz.es/arscatalogi.es/', 1947, 1947, 1947, 'Anos 40', NULL, 41.62937200, -0.85387600, '0101000020E610000083DBDAC2F352EBBF5182FE428FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15876354265.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15876354265.webp', 'https://www.flickr.com/photos/zaragozaantigua/15876354265/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23620, 'Calle Flandro 1874', '"Zaragoza. Aspecto de la calle de Flandro el 4 del actual, momentos antes de la lucha". Grabado de Rico sobre dibujo de Dom‚îú¬Æc. Ante el golpe de Estado del general Pav‚îú¬°a del 3 de enero de 1874, los republicanos organizaron protestas en diversas localidades espa‚îú‚ñíolas. En Zaragoza se construyeron barricadas y se tomaron algunas calles, como la de Mateo Flandro, entre el Coso Medio y la calle de San Miguel. La revuelta fue sofocada a bayoneta. Fuente: "La ilustraci‚îú‚îÇn espa‚îú‚ñíola y americana", 15 de enero de 1874.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65062600, -0.87692300, '0101000020E6100000D386C3D2C00FECBFB2F677B647D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29569064422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29569064422.webp', 'https://www.flickr.com/photos/zaragozaantigua/29569064422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23621, 'Coso Medio 1937', 'Foto: Mar‚îú¬°n Chivite. Febrero de 1937. Desfile de las tropas de los sublevados, procedente de la calle de Baldomero Espartero. Al fondo a la izquierda, el Coso Bajo. La columna militar se dirige por el Coso Medio hacia la plaza de Espa‚îú‚ñía. Fuente visual: Heraldo de Arag‚îú‚îÇn.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65069800, -0.87632200, '0101000020E6100000707D586FD40AECBF4BC972124AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30920188294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30920188294.webp', 'https://www.flickr.com/photos/zaragozaantigua/30920188294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23629, 'Coso Medio 1887', 'Dibujo de la fachada principal recayente al tramo medio del Coso, en la manzana comprendida entre las calles de la Imprenta (a la izquierda) y del Agua (a la derecha), de la gran casa proyectada por el arquitecto Agust‚îú¬°n Sanz en 1768-69 para el pr‚îú‚îÇcer local Juan Bautista Casabona. Poco despu‚îú¬Æs de ser realizado este dibujo, la fachada fue recompuesta al gusto finisecular, permitiendo la supervivencia del inmueble hasta que en la prodigiosa d‚îú¬Æcada de los a‚îú‚ñíos sesenta del siglo XX, fue derribado y sobre su solar, delimitado entre las actuales calles de los Hermanos Ibarra y de Mateo Flandro, fue construido el moderno y descontextualizado edificio que desde entonces hermosea este tramo del Coso. Este es otro de los innumerables casos de p‚îú¬Ærdidas patrimoniales que en la ciudad no pueden ser achacadas a los asedios franceses de 1808-1809.', 1887, 1887, 1887, 'Siglo XIX', 'CENTRO', 41.65071700, -0.87689900, '0101000020E6100000B1A4DC7D8E0FECBFC2F9D4B14AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50071296187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50071296187.webp', 'https://www.flickr.com/photos/zaragozaantigua/50071296187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24006, 'Coso Medio 1988', 'Manifestaci‚îú‚îÇn sindical unitaria el 14 de diciembre de 1988, d‚îú¬°a de huelga general en Espa‚îú‚ñía contra la pol‚îú¬°tica antisocial del gobierno del PSOE. Al fondo, esquina del Coso Bajo con la calle de Baldomero Espartero (derecha). Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Arag‚îú‚îÇn", UGT, 2000.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23760225719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23760225719.webp', 'https://www.flickr.com/photos/zaragozaantigua/23760225719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24043, 'Coso Medio 1986', 'Foto: Juan Gonz‚îú√≠lez Misis. Entre junio y noviembre de 1986, los trabajadores de Transportes Urbanos de Zaragoza (TUZSA), la empresa de los autobuses urbanos, mantuvieron una huelga. En la imagen, manifestaci‚îú‚îÇn de la plantilla en huelga a su paso por el Coso Medio. Al fondo, calle de Baldomero Espartero. Fuente: Heraldo de Arag‚îú‚îÇn.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65069800, -0.87648300, '0101000020E6100000BDFF8F13260CECBF4BC972124AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30923152334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30923152334.webp', 'https://www.flickr.com/photos/zaragozaantigua/30923152334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24905, 'Coso 99, 2001', 'Tras el derribo de los inmuebles de la calle del Coso de Zaragoza a la altura del 99 y el 101, aparecieron restos de la muralla y su torre‚îú‚îÇn de ‚îú¬Æpoca romana (s. III). El chirriante edificio del n‚îú‚ïëmero 99 ocupa el solar de la foto, tomada desde su interior. En el 101, lugar conocido como "las piedras del Coso", persiste un solar con los restos, donde el Coso Medio hace esquina con el Coso Bajo. Fuente: Cr‚îú‚îÇnica de Zaragoza. Ayuntamiento de Zaragoza, 2001.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18547615678.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18547615678.webp', 'https://www.flickr.com/photos/zaragozaantigua/18547615678/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25059, 'Plaza de San Pedro Nolasco c.1971', 'En la plaza de San Lorenzo, luego abierta e inclusa en la de san Pedro Nolasco, se levantaba el edificio del fondo a la derecha, colegio nuevo de los hermanos Maristas construido en 1946 y abandonado por ‚îú¬Æstos en 1981 (con entrada principal por San Vicente de Pa‚îú‚ïël 13). A su izquierda, la fonda El Descanso y el mercado San Lorenzo. Las personas que aparecen en la foto son Feliciano Romeo, que se encarg‚îú‚îÇ de los cuidados del fot‚îú‚îÇgrafo Aurelio Grasa hasta su fallecimiento; Emilio Grasa, hermano menor de Aurelio y que estuvo tambi‚îú¬Æn al cuidado de Feliciano en su residencia en el Seminario de San Carlos; y Teresa Grasa, pintora y restauradora, hija de Aurelio y sobrina de Emilio, al que coge del brazo. Fuente: Colecci‚îú‚îÇn Antonio Tausiet.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65279200, -0.87679200, '0101000020E6100000309FAC18AE0EECBF938B31B08ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14915071231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14915071231.webp', 'https://www.flickr.com/photos/zaragozaantigua/14915071231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25682, 'Pl. San Pedro Nolasco 1923', 'In‚îú¬Ædita imagen capturada desde la calle de San Jorge, a espaldas de la barroca iglesia de San Pedro Nolasco (desaparecida), y centrada en la hom‚îú‚îÇnima plaza que hacia el fondo conduce a la calle de San Juan y San Pedro (izquierda), y a la de los Hermanos Argensola (centro). A la derecha del antiguo inmueble del n‚î¨‚ïë 2 de esa calle, acceso a las calles de San Lorenzo y del Laberinto. En el centro de esta plaza y a finales de a‚îú‚ñío se instalar‚îú¬°a el Monumento a los Hermanos Argensola, obra de Jos‚îú¬Æ Bueno Gimeno. Esta plaza todav‚îú¬°a era conocida como de San Lorenzo, en referencia a la antigua iglesia del mismo nombre que hab‚îú¬°a sido derribada en el ‚îú‚ïëltimo cuarto del siglo XIX.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65276900, -0.87698500, '0101000020E610000055A4C2D84210ECBFDB6B41EF8DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51284598446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51284598446.webp', 'https://www.flickr.com/photos/zaragozaantigua/51284598446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25686, 'Iglesia de San Lorenzo 1864', 'Imagen de la desaparecida iglesia de San Lorenzo cuyo derribo en 1868 alumbr‚îú‚îÇ la aparici‚îú‚îÇn de una nueva plaza donde estaba previsto construir un mercado que s‚îú‚îÇlo estuvo listo en 1876. El aspecto que muestra la iglesia se corresponde con la traza que adquiri‚îú‚îÇ tras la gran reforma barroca de que fue objeto en el siglo XVII.', 1864, 1864, 1864, 'Siglo XIX', 'CENTRO', 41.65256900, -0.87685700, '0101000020E6100000F6984869360FECBF14B1886187D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387131345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387131345.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387131345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25903, 'Coso Medio 1902', 'Postal "Agust‚îú¬°n Allu‚îú¬Æ", de la Serie "Zaragoza", n‚î¨‚ïë 26 "Vista del Coso". Imagen del Coso Medio, entre las "Piedras del Coso" (inmediato edificio de la esquina derecha) y la plaza de la Constituci‚îú‚îÇn (al fondo). Las l‚îú¬°neas del tranv‚îú¬°a "Circunvalaci‚îú‚îÇn", y "Bajo Arag‚îú‚îÇn" ya est‚îú√≠n electrificadas. Fuente visual: maestrogozalbo.com/', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20610242121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20610242121.webp', 'https://www.flickr.com/photos/zaragozaantigua/20610242121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25977, 'Iglesia del Sagrado Coraz‚îú‚îÇn 1985', 'Vista de Zaragoza desde la torre de la Magdalena, dentro del programa de actividades de las fiestas del Pilar "Visita a la ciudad desconocida". Preside la imagen la iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës en la plaza de San Pedro Nolasco, construida en 1942 sobre el solar de la de San Lorenzo, derribada en 1930. Es un edificio neog‚îú‚îÇtico de Regino Borobio, utilizado hoy como almac‚îú¬Æn expositivo del Rosario de Cristal, colecci‚îú‚îÇn de faroles y carrozas que desfilan en octubre por la ciudad desde 1889. Fuente: Archivo municipal del Ayuntamiento de Zaragoza, 7/10/85.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65226300, -0.87706000, '0101000020E6100000FE261422E010ECBF07B29E5A7DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15191728375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15191728375.webp', 'https://www.flickr.com/photos/zaragozaantigua/15191728375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26076, 'Barrio de la Magdalena c.1895', 'Imagen capturada desde la altura de la torrecilla de la iglesia de San Carlos Borromeo y orientada hacia el noreste urbano, que incluye los inmediatos tejados del caser‚îú¬°o del barrio de la Magdalena en las calles de la Zarza, Espino, Gallo, San Lorenzo, Mayor... Sobre ellas emerge rotunda y en primer t‚îú¬Ærmino la torre de la parroquia de santa Mar‚îú¬°a Magdalena, y a la izquierda y al fondo, la de san Nicol‚îú√≠s de Bari. Al otro lado del r‚îú¬°o Ebro se nos muestra una interesante vista de la torre del antiguo convento de Jes‚îú‚ïës.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65236000, -0.87488200, '0101000020E6100000857D3B8908FFEBBFFA9B508880D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52210025192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52210025192.webp', 'https://www.flickr.com/photos/zaragozaantigua/52210025192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20890, 'Caesaraugusta s. III', 'Plano de la red viaria y los espacios p‚îú‚ïëblicos de la Zaragoza romana, seg‚îú‚ïën P. Galve (Ayto. de Zaragoza). Fuente visual: "La calle Alfonso I de Zaragoza", Mar‚îú¬°a Pilar Galve, Ayto. Zaragoza, 2007', 250, 200, 299, 'Siglo XIX', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16162890168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16162890168.webp', 'https://www.flickr.com/photos/zaragozaantigua/16162890168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20901, 'Calle Urrea 2010', 'Vista de la excavaci‚îú‚îÇn arqueol‚îú‚îÇgica del solar de la calle Urrea 10, una vez derribado en noviembre de 2009 el edificio que lo ocupaba. Se encontraron restos del siglo 1 despu‚îú¬Æs de la Era. La cloaca romana que se muestra ya hab‚îú¬°a sido documentada en los solares del Coso 86 (2005) y de la calle Urrea 3-21 (2007). Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.65083400, -0.87802800, '0101000020E6100000FC1C1F2DCE18ECBFFC8F4C874ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32215215112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32215215112.webp', 'https://www.flickr.com/photos/zaragozaantigua/32215215112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20927, 'Casa de Zaporta 1560', '"Famosa escalera del Palacio de la Infanta, que existi‚îú‚îÇ en Zaragoza. Actualmente se halla colocado en Par‚îú¬°s". Ilustraci‚îú‚îÇn de la obra "Arte y Decoraci‚îú‚îÇn En Espa‚îú‚ñía" (Volumen 2), de V‚îú¬°ctor de Falg‚îú√≠s y J. Sacs, editada entre 1917 y 1928 (a raz‚îú‚îÇn de un volumen por a‚îú‚ñío) por "Casellas Moncanut Hermanos editores", Barcelona. Este dibujo representa una recreaci‚îú‚îÇn mucho m‚îú√≠s elaborada que el apuntado a l‚îú√≠piz y plumilla por Valent‚îú¬°n Carderera en 1840, de las escaleras y c‚îú‚ïëpula del antiguo Palacio de Zaporta. El apunte del soldado haciendo guardia, como parte del "atrezzo" esc‚îú¬Ænico. Fuente visual: Colecci‚îú‚îÇn Jos‚îú¬Æ Luis Cintora.', 1560, 1560, 1560, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24324714884.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24324714884.webp', 'https://www.flickr.com/photos/zaragozaantigua/24324714884/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20928, 'Casa de Zaporta 1545', 'Dibujo de Valent‚îú¬°n Carderera y Solano, por ‚îú¬Æl titulado "Casa de Zaporta (1545) Zaragoza", realizado sobre 1840, en el que representa una vista desde el ingreso a esta casa palaciega por la calle Alta de San Pedro, tras haber cruzado el umbral de su puerta, con el estallido de toda la magnificencia de su singular patio. A la derecha, las escaleras de acceso a la planta principal, en el lado oeste. Los ideales personajes de "‚îú¬Æpoca" ambientan una recreaci‚îú‚îÇn conjuntada con el entorno. Fuente visual: ceres.mcu.es/', 1545, 1545, 1545, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24328938673.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24328938673.webp', 'https://www.flickr.com/photos/zaragozaantigua/24328938673/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20931, 'Casa de Zaporta 1560', '(Zaragoza, La Casa de la Infanta, Secci‚îú‚îÇn a trav‚îú¬Æs del patio y escalera). Ilustraci‚îú‚îÇn de Andrew Noble Prentice para la obra "Renaissance Architecture and Ornament in Spain. A serie of examples selected from the purest works executed between the years 1500-1560, measured and drawn, together with short descriptive text" (Arquitectura y ornamento del Renacimiento en Espa‚îú‚ñía. Una serie de ejemplos seleccionados entre las obras m‚îú√≠s puras realizadas entre los a‚îú‚ñíos 1500-1560, medidos y dibujados, junto con un breve texto descriptivo). Publicada en New York (1915), por la "Architectural Book Publishing Co." de Paul Wenzel & Maurice Krakow. Esta l‚îú√≠mina reproduce, adem‚îú√≠s de una peque‚îú‚ñía planta, una interesante secci‚îú‚îÇn del patio y la caja de las escaleras de acceso a la planta principal, incluyendo el remate mediante una octogonal c‚îú‚ïëpula de media naranja sobre tambor, tallada en madera, en formas mud‚îú¬Æjares. La vista ser‚îú¬°a desde el ingreso al Palacio por la calle Alta de San Pedro (luego, de San Jorge). Tras el derribo anunciado, en los comienzos del siglo XX, el Patio fue vendido a un anticuario parisino, y la c‚îú‚ïëpula, desmontada y extraviada. Fuente visual: www.bildindex.de/', 1560, 1560, 1560, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24927586666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24927586666.webp', 'https://www.flickr.com/photos/zaragozaantigua/24927586666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20942, 'San Pedro Ap‚îú‚îÇstol 1563', 'Vista parcial de la vista de Zaragoza realizada en 1663 por el dibujante Anton van der Wyngaerde/Antonio de las Vi‚îú‚ñías, centrada en la iglesia de San Pedro Ap‚îú‚îÇstol, que aparece destacada. En torno a ella figuran a la izquierda las iglesias de San Juan el Viejo y San Andr‚îú¬Æs Ap‚îú‚îÇstol, a la derecha la iglesia de San Gil Abad, y por encima la iglesia del convento de San Francisco. Se ubicaba en la esquina entre las calles Alta y Baja de San Pedro, actual calle de Don Jaime I.', 1563, 1563, 1563, 'Siglo XIX', 'CENTRO', 41.65324400, -0.87830800, '0101000020E6100000DB15FA60191BECBF7427D87F9DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387421958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387421958.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387421958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24044, 'Plaza de Salamero 1985', 'Imagen capturada en la plaza de Salamero (antigua de Santa Fe), durante la Huelga General del 20 de junio de ese a‚îú‚ñío, convocada por el sindicato Comisiones Obreras (con Marcelino Camacho Abad como Secretario General), y sindicatos con menos afiliaci‚îú‚îÇn, como CNT y USO, como muestra de rechazo a la reforma de las pensiones prevista por el ejecutivo socialista encabezado por Felipe Gonz‚îú√≠lez M‚îú√≠rquez. Todav‚îú¬°a no se hab‚îú¬°a inventado el concepto "huelga pol‚îú¬°tica", y esta se qued‚îú‚îÇ s‚îú‚îÇlo en "huelga econ‚îú‚îÇmica", como protesta por la primera de las sucesivas reformas a la baja del sistema p‚îú‚ïëblico de pensiones. Ni UGT, ni otras centrales sindicales de orientaci‚îú‚îÇn varia secundaron la huelga, que fue considerada un "fracaso", pues el Gobierno sac‚îú‚îÇ adelante la reforma sin demasiados agobios populares, o parlamentarios. En el editorial del d‚îú¬°a despu‚îú¬Æs a esta huelga, el director del Diario 16, Pedro J. Ram‚îú¬°rez, se refiri‚îú‚îÇ a los convocantes en estos t‚îú¬Ærminos: "Algunos comunistas son capaces de pasarse por el arco del triunfo todas las reglas de la democracia y sustituirlas por las de una implacable, fetichista, ensotanada y curil inquisici‚îú‚îÇn (..) este es, irresponsable, fr‚îú¬°volo, anticuado, Marcelino Camacho." En la imagen, pancarta de la Federaci‚îú‚îÇn del Metal de CCOO Arag‚îú‚îÇn (que incluye el coloquial palabro "G‚îú‚ïùelga", en lugar de Huelga), y canto de la Internacional (comunista). Al fondo, las fachadas de algunos de los edificios impares de la antigua calle de la Biblioteca, ya integrados en el entorno de la nueva plaza de Salamero tras el derribo de los antiguos n‚îú‚ïëmeros pares, aunque su futuro estaba cantado: los n‚îú‚ïëmeros 9, 11 y 13 ya hab‚îú¬°an sido derribados, y los n‚îú‚ïëmeros 3, 5 y 7 estaban en tr‚îú√≠nsito hacia el mismo final. En el gran solar resultante ser‚îú¬°a construido poco despu‚îú¬Æs el gran bloque moderno del n‚î¨‚ïë 30 de la avenida de C‚îú¬Æsar Augusto, de nombre "Verdi". S‚îú‚îÇlo perdura el esquinero edificio del actual n‚î¨‚ïë 50 de la calle de Azoque. A la derecha, el chaflanero nuevo bloque recayente a l', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65223400, -0.88408700, '0101000020E61000003733FAD1704AECBF6DAB59677CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30938338851.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30938338851.webp', 'https://www.flickr.com/photos/zaragozaantigua/30938338851/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20963, 'Coso Medio 1853', 'Perspectiva de la casa del Excmo. Sr. Conde de Aranda a la calle del Coso de Zaragoza. Estado en que qued‚îú‚îÇ despu‚îú¬Æs de los Sitios. Tinta y acuarela. Eusebio Blasco y Taula, 1853. Archivo Municipal de Zaragoza. Seg‚îú‚ïën se ve, ‚îú¬Æste fue el domicilio del Conde de Aranda (1718-1798) en Zaragoza. Y parece ser que su estado semiesquel‚îú¬Ætico se debe a la acci‚îú‚îÇn de las batallas de los Sitios (1808-1809). La esquina con la calle Santa Catalina que reproduce el curioso dibujo corresponde con el actual n‚îú‚ïëmero 84 del Coso Medio, y llega hasta el 86. El edificio original, de 1512, fue palacio de Miguel Vel‚îú√≠zquez Climent. Algunos de sus restos reposan en el interior del hotel que hoy ocupa el n‚îú‚ïëmero 86 de esa calle zaragozana: www.flickr.com/photos/zaragozaantigua/15768063741/', 1853, 1853, 1853, 'Siglo XIX', 'CENTRO', 41.65119800, -0.87836000, '0101000020E61000007AAA436E861BECBF3D9CC0745AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661782775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661782775.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661782775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21027, 'Casa de Zaporta 1868', 'Foto: Robert Peters Napper "Patio de la casa de Zaporta o de la Infanta", imagen n‚î¨‚ïë 54 para la edici‚îú‚îÇn de Francis Frith & Co. (1863-1870) del ‚îú√≠lbum "Spanish Photographs". Desde la galer‚îú¬°a este, se ha capturado el lado oeste, el de las escaleras de acceso desde el patio inferior. Cubriendo esas escaleras se encontraba una singular y perdida c‚îú‚ïëpula. tallada en madera y formas mud‚îú¬Æjares. Fuente: Fototeca del Patrimonio Hist‚îú‚îÇrico (www.mcu.es/)', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22566288301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22566288301.webp', 'https://www.flickr.com/photos/zaragozaantigua/22566288301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21038, 'Insurreci‚îú‚îÇn republicana 1869', 'Dibujo titulado "Una calle de Zaragoza despu‚îú¬Æs del combate", como ilustraci‚îú‚îÇn de los breves e intensos combates habidos tras la insurrecci‚îú‚îÇn republicana federal iniciada el 6 de octubre de ese a‚îú‚ñío en la ciudad, duramente contestada un par de d‚îú¬°as despu‚îú¬Æs por las tropas regulares del gobierno provisional (1869-71) del Sexenio Democr‚îú√≠tico (1868-1874), con Prim como presidente, y Serrano como regente. La gen‚îú¬Ærica localizaci‚îú‚îÇn del dibujo presenta como referencia urbana, al fondo, la Torre Nueva, cuya inclinaci‚îú‚îÇn hacia el SW ubicar‚îú¬°a la imagen, aproximadamente, en el entorno de la calle de Don Jaime I con el cruce de la calle Torre Nueva. Fuente visual: revista El Museo Universal (Madrid, 31/10/1869).', 1869, 1869, 1869, 'Siglo XIX', 'CENTRO', 41.65334800, -0.87855100, '0101000020E610000071C79BFC161DECBF197442E8A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36443956765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36443956765.webp', 'https://www.flickr.com/photos/zaragozaantigua/36443956765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21043, 'Coso Medio 1860', 'Imagen realizada durante la estancia en Zaragoza de la reina Isabel II en octubre de ese a‚îú‚ñío. La escena reproduce el ef‚îú¬°mero "obelisco" o torre‚îú‚îÇn "de gusto ‚îú√≠rabe", dedicado a SS.MM. y decorado con alegor‚îú¬°as relacionadas con la agricultura, la industria y el comercio, temporalmente ubicado en el tramo medio del Coso, que aparece profusamente decorado a base de maderos clavados en el terroso suelo y resaltados con bandas bicolores. A la izquierda, manzanas entre la plaza de la Constituci‚îú‚îÇn, al fondo, en cuya esquina destaca la gran fachada recayente al Coso de la Fonda de Europa de Gaudencio Zoppetti, la calle de la Soledad, luego de los Sitios, y la reciente calle de Blancas, originalmente trazada para llegar hasta cerca del antiguo monasterio de Santa Engracia, si bien se detendr‚îú¬°a en el cruce con la calle de San Miguel. A la derecha, tramo entre las calles del Refugio, luego del Teatro, de San Crist‚îú‚îÇbal del Coso, luego del Romero, y de la Subida de la Ver‚îú‚îÇnica, luego de San Pedro Nolasco, donde se destaca tal vez la ‚îú‚ïënica fotograf‚îú¬°a donde aparece la fachada de la antigua casa de Baltasar P‚îú¬Ærez de Nueros. podo despu‚îú¬Æs derribada y donde se erigir‚îú¬°a la casa del marqu‚îú¬Æs de Fuente Olivar', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65140000, -0.87895800, '0101000020E610000099D711876C20ECBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46459247052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46459247052.webp', 'https://www.flickr.com/photos/zaragozaantigua/46459247052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21109, 'Casa de Zaporta 1889', '"Saragosse. La maison de l''Infante. La cour". En el patio de la antigua casa de Gabriel Zaporta, realquilado a particulares, acoge en esta imagen el taller de carpinter‚îú¬°a de Ezequiel Gonz‚îú√≠lez y el taller de ebanister‚îú¬°a de Hip‚îú‚îÇlito Loscos. En la primera planta estaba la f‚îú√≠brica de pianos de pared de P‚îú¬°o Perales.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22551642760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22551642760.webp', 'https://www.flickr.com/photos/zaragozaantigua/22551642760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21114, 'Casa de Zaporta 1889', '"Zaragoza, Casa de los Infantes (Casa Zaporta)". El ‚îú‚ïëltimo tercio del siglo XIX fue muy movido para el antiguo Palacio de Zaporta, de la calle de San Jorge, antigua Alta de San Pedro. Tras un incendio en 1864, fue restaurado y multiarrendado a diversas actividades industriosas. En una de las dependencias de la primera planta se ubic‚îú‚îÇ la "F‚îú√≠brica de Pianos de P‚îú¬°o Perales", de donde sal‚îú¬°an notables pianos de pared, y en la planta baja se montaron talleres de carpinter‚îú¬°a y ebanister‚îú¬°a. Con tanta madera, salt‚îú‚îÇ la chispa, y a poco de finalizar el siglo un nuevo incendio dej‚îú‚îÇ al Palacio en muy malas condiciones. De ah‚îú¬°, al derribo, fue todo un natural. Dicen. En la imagen, captura fotogr‚îú√≠fica previa a ese ‚îú‚ïëltimo incendio, con vista parcial del lado oeste del palaciego patio, que daba acceso a las escaleras de subida al primer piso, donde unos tabiques delimitan la "F‚îú√≠brica de Pianos de P‚îú¬°o Perales". Tal vez el se‚îú‚ñíor que se asoma, curioso, fuera el propio P‚îú¬°o. Tras el incendio, se mudar‚îú¬°a a la cercana calle de Don Jaime I.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24650941310.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24650941310.webp', 'https://www.flickr.com/photos/zaragozaantigua/24650941310/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21136, 'Casa de Zaporta 1894', 'A.M.Z. Sign. 0859. Patio de la Infanta procedente de la desaparecida Casa de Zaporta, Zaragoza. [1894] Reproducci‚îú‚îÇn de fotograf‚îú¬°a de Laurent del patio de la Infanta, perteneciente a la casa de Zaporta, sita en la calle San Jorge (actual Monte de Piedad). Las piedras se pueden ver, remontadas hoy, dentro del rascacielos de la sede central del banco Ibercaja, en la plaza de Basilio Para‚îú¬°so.', 1894, 1894, 1894, 'Siglo XIX', 'CENTRO', 41.65270200, -0.87771000, '0101000020E6100000BCE82B483316ECBF530438BD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672230010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672230010.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672230010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21144, 'Casa de Zaporta c.1890', 'Colecci‚îú‚îÇn Antonio Arguas, finales del XIX. Portada completa, con ventana superior, del palacio de Zaporta. En su interior, el patio de la Infanta. El edificio se derrib‚îú‚îÇ en 1903.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65266300, -0.87754700, '0101000020E6100000417E3672DD14ECBF952710768AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14984883827.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14984883827.webp', 'https://www.flickr.com/photos/zaragozaantigua/14984883827/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21171, 'Casa de Zaporta 1893', 'Acuarela de Andrew N. Prentice, copia del ‚îú‚îÇleo "Celebrada Casa de la Infanta de Zaragoza. La salida del combate", pintado por Pablo Gonzalvo en 1868 y en paradero desconocido. Fuente: Caja de Ahorros de Zaragoza, 1951.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.65274200, -0.87765300, '0101000020E6100000AC8F87BEBB15ECBFE25CC30C8DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29677097665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29677097665.webp', 'https://www.flickr.com/photos/zaragozaantigua/29677097665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21178, 'Don Jaime I 1893', 'Imagen promocional del comercio "Ultramarinos Coloniales" de Emilio Oliete (que posa en la puerta), sito en la calle de Don Jaime I n‚î¨‚ïë 10, esquinero con la calle de la Ver‚îú‚îÇnica (a la izquierda), y confrontando con la puerta de acceso a la iglesia parroquial de San Gil Abad. Esta tienda estaba bien surtida de comestibles y "bebestibles" de altas calidades. La manzana en la que estaba radicada esta finca fue demolida en los a‚îú‚ñíos 60 del pasado siglo XX. Fuente visual: revista Semanario Ilustrado.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.65257100, -0.87921600, '0101000020E610000084D6C3978922ECBFB5A84F7287D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33502394474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33502394474.webp', 'https://www.flickr.com/photos/zaragozaantigua/33502394474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21180, 'San Juan y San Pedro 1890', 'Imagen centrada en la antigua torre parroquial mud‚îú¬Æjar de San Juan y San Pedro, capturada desde la esquina de las calles del Refugio y de San Juan. Originalmente denominada de San Juan Bautista o San Juan "el Viejo", para diferenciarla de la iglesia de San Juan del Puente, a‚îú‚ñíadi‚îú‚îÇ en su denominaci‚îú‚îÇn la referencia a San Pedro cuando esa vecina iglesia parroquial fue desacralizada y derribada. Estaba considerada la quinta gran torre mud‚îú¬Æjar de la ciudad, tras la de Mar‚îú¬°a Magdalena, San Miguel de los Navarros, San Pablo Ap‚îú‚îÇstol, y San Gil Abad. Perdi‚îú‚îÇ esa consideraci‚îú‚îÇn tras ser demolida en la prodigiosa d‚îú¬Æcada de los a‚îú‚ñíos 60. Fuente visual: "Torre de la iglesia de San Juan y San Pedro", fototipia de Joarizti y Mariezcurrena, en √î√á¬£Zaragoza Art‚îú¬°stica, Monumental e Hist‚îú‚îÇrica√î√á√ò, Anselmo y Pedro Gasc‚îú‚îÇn de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65335300, -0.87755500, '0101000020E6100000F71E2E39EE14ECBF2BDF3312A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33739117814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33739117814.webp', 'https://www.flickr.com/photos/zaragozaantigua/33739117814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21379, 'Caja de Ahorros 1913', 'Reci‚îú¬Æn construido edificio central de la Caja de Ahorros de Zaragoza, con entrada al chafl‚îú√≠n de San Jorge con San Andr‚îú¬Æs. En primer plano, solar preparado para la construcci‚îú‚îÇn del n‚îú‚ïëmero 9 de la calle de San Andr‚îú¬Æs. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65285400, -0.87797400, '0101000020E610000030A017EE5C18ECBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15824501216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15824501216.webp', 'https://www.flickr.com/photos/zaragozaantigua/15824501216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21394, 'Iglesia de San Gil 1913', 'Foto: Lorenzo Almarza. Iglesia y torre de San Gil de Zaragoza, vista desde la calle de Don Jaime I. Fuente: Archivo de la Diputaci‚îú‚îÇn Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21280893210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21280893210.webp', 'https://www.flickr.com/photos/zaragozaantigua/21280893210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21401, 'Coso Medio c.1915', 'Imagen en colores pintados un tanto estomagantes, del Coso Medio en direcci‚îú‚îÇn hacia la plaza de la Constituci‚îú‚îÇn (al fondo).', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65150100, -0.87910000, '0101000020E6100000363CBD529621ECBFD927806264D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23034500685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23034500685.webp', 'https://www.flickr.com/photos/zaragozaantigua/23034500685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21420, 'Coso Medio c.1915', 'Imagen capturada desde cierta altura, y convertida en postal comercial que reproduce una vista del tramo medio del Coso, con la plaza de la Constituci‚îú‚îÇn al fondo. A la derecha, el Teatro Principal, y el edificio del Banco de Espa‚îú‚ñía. Encaminada hacia la plaza de la Constituci‚îú‚îÇn, una ins‚îú‚îÇlita composici‚îú‚îÇn tranviaria formada, posiblemente, por una unidad motora de la serie "Primitivos", tirando de dos de los antiguos y peque‚îú‚ñíos remolques. Fuente visual: www.ebay.es/', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65166500, -0.87932300, '0101000020E610000005DCF3FC6923ECBF53793BC269D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31433637536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31433637536.webp', 'https://www.flickr.com/photos/zaragozaantigua/31433637536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21439, 'Gabriel Faci Abad c.1910', 'Imagen del qu‚îú¬°mico Gabriel Faci Abad posiblemente capturada por su hermano Miguel en el laboratorio de la botica que regentaba en el n‚î¨‚ïë 94 del tramo medio del Coso. Paralelamente, Gabriel ejerc‚îú¬°a de fiel contraste en la joyer‚îú¬°a de sus hermanos Miguel y Pedro, estampando con un punz‚îú‚îÇn personalizado la marca que garantizaba la genuina procedencia del art‚îú¬°culo en cuesti‚îú‚îÇn. Gabriel tambi‚îú¬Æn era fot‚îú‚îÇgrafo aficionado, si bien no se prodig‚îú‚îÇ tanto como su hermano Miguel, y fue junto a ‚îú¬Æl miembro del grupo fundador de la Sociedad Fotogr‚îú√≠fica de Zaragoza. Fuente visual: Archivo Gabriel Faci Abad, en AHPZ', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65140000, -0.87895800, '0101000020E610000099D711876C20ECBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45493144901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45493144901.webp', 'https://www.flickr.com/photos/zaragozaantigua/45493144901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21482, 'Vista parcial 1925', 'Postal, 1925. Fotograf‚îú¬°a de parte de la antigua ciudad, tomada desde la torre de San Gil.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14958326126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14958326126.webp', 'https://www.flickr.com/photos/zaragozaantigua/14958326126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21524, 'Coso Medio 1926', 'Imagen de la casa de Mariano Garc‚îú¬°a (actual Coso n‚î¨‚ïë 51-53), dise‚îú‚ñío de Regino Borobio sobre el solar de dos antiguos edificios piqueteados, en formas similares a los que en la imagen le flanquean. En su momento esta moderna casa destacaba por su altura, aunque el posterior piqueteo de su vecino de la derecha, y sustituci‚îú‚îÇn por la cosa que hoy se levanta ah‚îú¬° (Coso n‚î¨‚ïë 55), le ha dejado casi como una referencia cl‚îú√≠sica en esa parte del Coso. Tampoco ‚îú¬Æl se ha librado de las "reformas", como su parte inferior actual (planta calle), que parece haber sido abducida por el horror de su derecha. Fuente visual: "Una mirada a trav‚îú¬Æs de la arquitectura: Regino y Jos‚îú¬Æ Borobio Ojeda", Daniel Estab‚îú¬Æn Boldova.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65173400, -0.87958300, '0101000020E61000001EC3633F8B25ECBF7BD80B056CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16971021878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16971021878.webp', 'https://www.flickr.com/photos/zaragozaantigua/16971021878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21550, 'Coso Medio 1926', 'Instalaci‚îú‚îÇn de l‚îú¬°nea telef‚îú‚îÇnica en la redacci‚îú‚îÇn del Diario de Avisos, comprado por Heraldo de Arag‚îú‚îÇn y luego sede de su imprenta, en el Coso Medio de Zaragoza, esquina con la calle de Santa Catalina (izquierda). A la derecha, el colegio de las Hermanas de la Caridad de Santa Ana. Fuente visual: Fundaci‚îú‚îÇn Telef‚îú‚îÇnica.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65142900, -0.87866000, '0101000020E610000020B58993FB1DECBF3F55850662D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20749387638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20749387638.webp', 'https://www.flickr.com/photos/zaragozaantigua/20749387638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21557, 'Calle Porcell 1926', 'Instalaci‚îú‚îÇn de la l‚îú¬°nea telef‚îú‚îÇnica en el Coso Medio, a la altura de la calle de Juan Porcell. Bajo las escaleras, la bomboner‚îú¬°a-cafeter‚îú¬°a-chocolater‚îú¬°a "Cesaraugusta". Al fondo, tras el hotel restaurant Florida, entrada por el Coso del colegio de las Hermanas de la Caridad de Santa Ana. Fuente visual : Fundaci‚îú‚îÇn Telef‚îú‚îÇnica.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65150100, -0.87910000, '0101000020E6100000363CBD529621ECBFD927806264D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21584275702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21584275702.webp', 'https://www.flickr.com/photos/zaragozaantigua/21584275702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21607, 'San Gil c.1926', 'Imagen de la iglesia parroquial del Se‚îú‚ñíor San Gil Abad, capturada a cierta altura, posiblemente desde el antiguo n‚î¨‚ïë 3 de la calle Ossau. Desde este emplazamiento el fot‚îú‚îÇgrafo ha conseguido una buena visual del lado norte del templo, recayente a la calle de los Est‚îú¬Æbanes, con la destacada y emergente f‚îú√≠brica mud‚îú¬Æjar de la torre. Al principio del diez y ocho siglo, la orientaci‚îú‚îÇn de la iglesia fue modificada para que la entrada principal recayese en la "calle nueba de San Gil", luego don Jaime I. Fuente visual: Estudio Coyne (AHPZ-DARA)', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65287200, -0.87950800, '0101000020E6100000744012F6ED24ECBFB03C484F91D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28436949991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28436949991.webp', 'https://www.flickr.com/photos/zaragozaantigua/28436949991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21639, 'Coso Medio 1923', 'Fotograf‚îú¬°a editada como postal promocional del dueto art‚îú¬°stico "Adriana y su Charlot", hijas del reputado acr‚îú‚îÇbata se‚îú‚ñíor Borza e integrantes del Circo Americano de Madrid, durante su paso por Zaragoza en el Teatrto Circo. La captura se ha realizado en Photo Greco, en el n‚î¨‚ïë 61 del tramo medio del Coso, junto al Teatro Principal, donde daba sus primeros pasos el estudio fotogr‚îú√≠fico de Manuel Mar‚îú¬°n Chivite.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65193500, -0.87962500, '0101000020E6100000D9CEF753E325ECBF130F289B72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50911850992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50911850992.webp', 'https://www.flickr.com/photos/zaragozaantigua/50911850992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21643, 'Miguel Primo de Rivera 1927', 'Imagen capturada en la puerta del Teatro Principal a la salida del marqu‚îú¬Æs de Estella, general Miguel Primo de Rivera que en su calidad de presidente del Consejo de ministros visit‚îú‚îÇ Zaragoza y otros municipios aragoneses en el mes de agosto de 1927. Junto al marqu‚îú¬Æs-general-presidente-dictador posa el alcalde Miguel Allu‚îú¬Æ Salvador, que en nombre del Ayuntamiento le hab‚îú¬°a obsequiado con un "refresco" al que asistieron las principales autoridades religiosas, militares y civiles de la ciudad. Antes del refresco, hab‚îú¬°a sido informado de varios proyectos urban‚îú¬°sticos: el abastecimiento de aguas a la Academia General Militar, el Gran Hotel y el ensanche de la ciudad.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65186300, -0.87952800, '0101000020E61000003B527DE71725ECBF793C2D3F70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51211956799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51211956799.webp', 'https://www.flickr.com/photos/zaragozaantigua/51211956799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21701, 'Colegio del Pilar a‚îú‚ñíos 30', 'Colegio Polit‚îú¬Æcnico Nuestra Se‚îú‚ñíora del Pilar. Detalle de la portada. En 1930 aparece domiciliado en M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez 36 de Zaragoza, con "Alumnos internos, medio-pensionistas, y vigilados", de "gran confort", e incluso con director espiritual. Internado a cargo de "Reverendos Sacerdotes". En 1968 se concede autorizaci‚îú‚îÇn para impartir ense‚îú‚ñíanza a un centro de la misma denominaci‚îú‚îÇn en la avenida Clav‚îú¬Æ 43-53, que ya funcionaba como tal desde finales de los a‚îú‚ñíos cincuenta. Fuente visual: www.todocoleccion.net/', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65325000, -0.87875500, '0101000020E6100000904946CEC21EECBF560E2DB29DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15676405255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15676405255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15676405255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21931, 'Jefe del Estado 1946', 'Ayuntamiento de Zaragoza/Ortiz. Calle Cruz, 16 (Madrid). 15 de diciembre de 1946. "El Jefe del Estado, Francisco Franco, dirige la palabra desde el balc‚îú‚îÇn del Teatro Principal." Al fondo de la imagen, en la Plaza de Espa‚îú‚ñía, destaca el vac‚îú¬°o donde deber‚îú¬°a estar la DPZ. Un a‚îú‚ñío antes se hab‚îú¬°a piqueteado el edificio levantado a mediados del XIX. Teodoro R‚îú¬°os present‚îú‚îÇ un proyecto para sustituirlo. En 1950 fue anunciada (y celebrada con campanas) su finalizaci‚îú‚îÇn, aunque las obras no terminaron hasta 1952. Al fondo de la Plaza de Espa‚îú‚ñía, la c‚îú‚ïëpula de Santiago el Mayor.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.65180700, -0.87939400, '0101000020E6100000548EC9E2FE23ECBFE5266A696ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14936159321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14936159321.webp', 'https://www.flickr.com/photos/zaragozaantigua/14936159321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21989, 'Coso Medio 1946', 'Imagen capturada en el balc‚îú‚îÇn del Teatro Principal durante la visita de Su Excelencia el Jefe del Estado, General‚îú¬°simo Franco, Victorioso Caudillo de los Ej‚îú¬Ærcitos de Tierra, Mar y Aire, el 15 de diciembre de 1946. Esta visual del tramo medio del Coso nos ofrece una buena perspectiva de c‚îú‚îÇmo de provinciana y poco moderna era su fachada desde la casa de la Asociaci‚îú‚îÇn de Labradores de Zaragoza, a la izquierda, junto al ferrolano, hasta casi la calle de los Sitios, pasando por los emboques a las calles de Santa Catalina, Juan Porcell, y Jer‚îú‚îÇnimo Blancas. El posterior "Desarrollismo", y "post-Desarrollismo", enmendaron esto. Fuente visual: Ortiz, AMZ, sig. 12933', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.65150100, -0.87910000, '0101000020E6100000363CBD529621ECBFD927806264D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30318701771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30318701771.webp', 'https://www.flickr.com/photos/zaragozaantigua/30318701771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22050, 'Calle de Zabala 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Zabala." Esta calle conectaba Don Jaime I con la calle de Ver‚îú‚îÇnica, por las traseras del Teatro Principal. Con el derribo de la manzana de viviendas entre esta calle, la de Ver‚îú‚îÇnica, y Don Jaime I, en 1966 la calle Zabala desapareci‚îú‚îÇ y dio lugar a la Plaza de "Sinu‚îú¬Æs Urbiola". En la imagen, aspecto de la calle tomada desde Don Jaime I. El Teatro Principal se encuentra a la derecha. A la izquierda, un poco m‚îú√≠s adelante, la calle de San Andr‚îú¬Æs. Al fondo, la calle de Ver‚îú‚îÇnica.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65240800, -0.87944200, '0101000020E61000009752978C6324ECBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14883251457.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14883251457.webp', 'https://www.flickr.com/photos/zaragozaantigua/14883251457/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25972, 'Feria de Muestras 1975', 'Recinto de la Feria de Muestras, en una vista a‚îú¬Ærea con sus espacios y pabellones en plena ocupaci‚îú‚îÇn durante la Feria Internacional de Maquinaria Agr‚îú¬°cola, que se celebraba desde 1964. Desde la edici‚îú‚îÇn de 1970 se utilizaban los exteriores del recinto, por superarse su capacidad en el interior. La FIMA de 1975 tuvo una fuerte orientaci‚îú‚îÇn a la explotaci‚îú‚îÇn ganadera. En 1987 pas‚îú‚îÇ a celebrarse en las m‚îú√≠s amplias instalaciones de la nueva Feria de Muestras, inauguradas el a‚îú‚ñío anterior en la carretera de Madrid, frente a la Venta de los Caballos. Al fondo y a la derecha, vista del cuartel de Palafox, edificado en 1926 y que pas‚îú‚îÇ a propiedad municipal en 1979 durante la Operaci‚îú‚îÇn Cuarteles, en un proceso que culmin‚îú‚îÇ en 1985, siendo utilizado luego como sede de las escuelas municipales de M‚îú‚ïësica, Danza y Teatro, el archivo de la Filmoteca o el centro c‚îú¬°vico Universidad.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.63751500, -0.89931400, '0101000020E6100000DCB75A272EC7ECBFCFDA6D179AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15084794911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15084794911.webp', 'https://www.flickr.com/photos/zaragozaantigua/15084794911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22065, 'Coso Medio 1953', 'Fachada del Banco de Santander, sito en la calle del Coso. A finales del XVIII se edific‚îú‚îÇ en esta ubicaci‚îú‚îÇn la casa de Sim‚îú‚îÇn Ignacio Tarazona, con dise‚îú‚ñío de Agust‚îú¬°n Sanz Al‚îú‚îÇs, que despu‚îú¬Æs acogi‚îú‚îÇ el edificio de la Capitan‚îú¬°a General, y desde 1875 fue sede de la sucursal del Banco de Espa‚îú‚ñía en Zaragoza. Cuando el Banco de Espa‚îú‚ñía se traslad‚îú‚îÇ a su actual ubicaci‚îú‚îÇn, el edificio fue derribado en 1940, y sobre el solar se edific‚îú‚îÇ, seg‚îú‚ïën proyecto del arquitecto Teodoro R‚îú¬°os Balaguer, la sede del que se llam‚îú‚îÇ Banco Aragon‚îú¬Æs de Cr‚îú¬Ædito, inaugurado el 2 de octubre de 1945. En 1951 el Banco de Santander compr‚îú‚îÇ la finca instalando all‚îú¬° su sucursal, reform‚îú√≠ndose el edificio en 1953 con proyecto de Regino Borobio. Est‚îú√≠ construido con fachada a dos calles y chafl‚îú√≠n curvo, con ladrillo visto y revocado, aplacado de piedra, y es una muestra del eclecticismo de lenguaje clasicista de los edificios destinados a sedes bancarias en los a‚îú‚ñíos veinte del siglo idem. En la imagen, chafl‚îú√≠n del banco desde el Coso Medio. A la izquierda, la calle Eusebio Blasco, por donde se mete el tranv‚îú¬°a de la l‚îú¬°nea 13 "San Jos‚îú¬Æ" para dar la vuelta. M‚îú√≠s al fondo, la estrecha calle de la Ver‚îú‚îÇnica.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65175100, -0.87911000, '0101000020E610000019C5724BAB21ECBF5111A7936CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061455910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061455910.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061455910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22066, 'Calle de la Ver‚îú‚îÇnica 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Ver‚îú‚îÇnica." En la imagen, aspecto de la calle de Ver‚îú‚îÇnica cuando, al objeto de ensanchar la calle, empezaban los derribos de los n‚îú‚ïëmeros de la izquierda. Esta calle desembocaba, al fondo, en la Plaza de la Ver‚îú‚îÇnica.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65193500, -0.87819800, '0101000020E610000016342DB1321AECBF130F289B72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15069672062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15069672062.webp', 'https://www.flickr.com/photos/zaragozaantigua/15069672062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22104, 'Calle de Valent‚îú¬°n Zabala 1955', 'Tranv‚îú¬°a de la l‚îú¬°nea 1 Bajo Arag‚îú‚îÇn, a su paso por la calle de Valent‚îú¬°n Zabala de Zaragoza, en 1955. Proviene de la calle Ver‚îú‚îÇnica. A la derecha toldo en las traseras del Teatro Principal. La manzana de la izquierda ser‚îú√≠ derribada en 1966 para dar paso a la plaza de Jos‚îú¬Æ Sinu‚îú¬Æs y Urbiola.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65230400, -0.87912600, '0101000020E6100000850662D9CC21ECBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20716420481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20716420481.webp', 'https://www.flickr.com/photos/zaragozaantigua/20716420481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22118, 'Don de Don Jaime I c.1955', 'Imagen granulada de operaciones de asfaltado en la calle Don Jaime I, con vistas a su conversi‚îú‚îÇn en una mini-autov‚îú¬°a de acceso para el tr‚îú√≠fico rodado, desde el puente de Piedra y hasta el centro de la ciudad. A la derecha, emboque a la calle San Jorge, con visual de los edificios entre la calle Refugio y Don Jaime I que, un par de d‚îú¬Æcadas despu‚îú¬Æs ser‚îú¬°an derribados y sustituidos, por otras cosas m‚îú√≠s modernas y menos provincianas. A la izquierda, la calle de Casto M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez. Al fondo, la plaza de Ari‚îú‚ñío. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65319400, -0.87848700, '0101000020E6100000C2C1DEC4901CECBFC2F869DC9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22500524178.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22500524178.webp', 'https://www.flickr.com/photos/zaragozaantigua/22500524178/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22121, 'Calle Est‚îú¬Æbanes 1956', 'Ricardo Garc‚îú¬°a, joven botijero de Salvatierra de los Barros (Badajoz), expone su mercanc‚îú¬°a junto a la iglesia de San Gil, en mayo de 1956. Es el hijo de Manuel, que lleva 18 primaveras viajando a pie a Zaragoza con los botijos en el borrico. Al fondo, el cine Latino, en el 29 de la calle Est‚îú¬Æbanes, inaugurado en febrero de 1954, especializado en reestrenos y cerrado en agosto de 1979. Fuente: Heraldo de Arag‚îú‚îÇn.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22538515441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22538515441.webp', 'https://www.flickr.com/photos/zaragozaantigua/22538515441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22209, 'Calle de la Ver‚îú‚îÇnica 1951', 'Imagen capturada en el tramo medio del final de la calle de la Ver‚îú‚îÇnica y orientada hacia las calles de Pardo Sastr‚îú‚îÇn, primero, y de Eusebio Blasco, al fondo, desde donde la luz del sol ilumina levemente esta recoleta y antigua calle asociada a la "mala vida" de tascas y prostituci‚îú‚îÇn de las clases bajas. La "mala vida" de las clases altas, refinada, adinerada y radicada en otras zonas de la ciudad, no ten‚îú¬°a la misma prensa y apenas visibilidad social. Las peque‚îú‚ñías viviendas de la derecha manten‚îú¬°an oculto, como suced‚îú¬°a desde la Alta Edad Media, el que fuera teatro romano de la ciudad. Tras ellas finalizaba en fondo de saco la zigzagueante calle de Gabriel Zaporta, con inicio en la de San Jorge. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65186500, -0.87798200, '0101000020E6100000E6400FB56D18ECBF1A34F44F70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41362743101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41362743101.webp', 'https://www.flickr.com/photos/zaragozaantigua/41362743101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22210, 'Calle de la Ver‚îú‚îÇnica 1951', 'Imagen capturada entre las tinieblas del tramo final de la recoleta calle de la Ver‚îú‚îÇnica, que flanqueado por un par de pardales que posan entre claroscuros se corresponde con el de los antiguos n‚îú‚ïëmeros 41 a 47 (izquierda) y 40 a 46 (derecha). La curva hacia la izquierda del final de la calle se ajusta bastante con el semicircular perfil de la cavea o grader‚îú¬°o del subterr‚îú√≠neo teatro romano, sepultado e ignoto desde la Alta Edad Media. Al fondo, luminosa, la plazuela de la Ver‚îú‚îÇnica, con vista parcial del inmueble del n‚îú‚ïëmero 5. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65175300, -0.87770300, '0101000020E61000001D3C139A2416ECBFF2086EA46CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42710629965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42710629965.webp', 'https://www.flickr.com/photos/zaragozaantigua/42710629965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22240, 'Coso Medio, 1953', 'Imagen capturada en la recepci‚îú‚îÇn del Banco de Santander sito en la calle Coso n‚î¨‚ïë 59 donde estuviera la ilustrada casa de Sim‚îú‚îÇn Ignacio Tarazona, que despu‚îú¬Æs acogi‚îú‚îÇ el edificio de la Capitan‚îú¬°a General y desde 1875 fue sucursal del Banco de Espa‚îú‚ñía. Cuando el Banco de Espa‚îú‚ñía se traslad‚îú‚îÇ a su actual sede, la antigua casa fue derribada y sobre su solar se edific‚îú‚îÇ seg‚îú‚ïën proyecto del arquitecto Teodoro R‚îú¬°os Balaguer, la sede del Banco Aragon‚îú¬Æs de Cr‚îú¬Ædito, inaugurado el 2 de octubre de 1945. En 1951 el Banco de Santander compr‚îú‚îÇ la finca instalando all‚îú¬° su sucursal principal, reform‚îú√≠ndose el edificio en 1953 con proyecto de Regino Borobio. Tras la puerta giratoria del fondo, entrada desde el Coso. A la derecha, la esquina con la calle Eusebio Blasco.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65174300, -0.87918500, '0101000020E6100000C347C4944822ECBFCF328B506CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51022502263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51022502263.webp', 'https://www.flickr.com/photos/zaragozaantigua/51022502263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22253, 'Iglesia de San Juan y San Pedro 1966', 'Espectral imagen de la torre mud‚îú¬Æjar de la antigua Iglesia de San Juan y San Pedro, tomada desde la esquina de la calle Refugio con la calle San Juan y San Pedro. Levantada en el siglo XIV, casi enfrente a las antiguas Termas Romanas, de factura modesta, en ladrillo y tapial, pero con una envidiable decoraci‚îú‚îÇn mud‚îú¬Æjar. Cuando se tom‚îú‚îÇ esta imagen, la iglesia ya estaba abandonada y cerrada, a la espera de la piqueta, que lleg‚îú‚îÇ este a‚îú‚ñío 1966. Era la quinta torre mud‚îú¬Æjar de la ciudad, tras la Magdalena, San Miguel, San Pablo, y San Gil. Hoy es s‚îú‚îÇlo otro bloque de viviendas m‚îú√≠s.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65330600, -0.87756500, '0101000020E6100000DBA7E3310315ECBFEA23F0879FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14663965189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14663965189.webp', 'https://www.flickr.com/photos/zaragozaantigua/14663965189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22397, 'San Gil 1966', 'Puerta de la iglesia parroquial de San Gil, en la calle Don Jaime I. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22834691510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22834691510.webp', 'https://www.flickr.com/photos/zaragozaantigua/22834691510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22604, 'Calle Santa Catalina 1973', 'Foto Monge, 1973. Imagen tomada con motivo del inminente derribo del edificio del Coso 84, esquina con la calle de Santa Catalina. La empresa encargada de levantar el monstruoso bloque que lo sustituye se denominaba, muy adecuadamente, "Marvel". Este emplazamiento, que vemos aqu‚îú¬° desde la calle de Santa Catalina, con el Coso Medio al fondo, fue domicilio del Conde de Aranda, en una edificaci‚îú‚îÇn anterior. Fuente: Diario Amanecer, 17 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65122100, -0.87857400, '0101000020E61000007CB5A338471DECBFF5BBB0355BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18782958384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18782958384.webp', 'https://www.flickr.com/photos/zaragozaantigua/18782958384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22624, 'Santa Catalina 1978', 'Imagen del arranque de la calle Santa Catalina desde el Coso Medio (al fondo), con interesante visual de la original anchura de esta calle, similar a la de sus vecinas de la antigua Juder‚îú¬°a Nueva, todas reincidentes en el poco ojo de quienes las trazaron, sin pensar en las necesidades de movilidad de la circulaci‚îú‚îÇn rodada a motor de explosi‚îú‚îÇn. Otro elemento de inter‚îú¬Æs son las traseras del antiguo n‚î¨‚ïë 100 del Coso, edificio de viviendas con notable patio interior tipo "corrala", y que en sus bajos albergara las imprentas de algunos diarios de la ciudad, el ‚îú‚ïëltimo, el m‚îú√≠s antiguo de la regi‚îú‚îÇn aragonesa. Justo a su izquierda estaba el n‚î¨‚ïë 96-98, que daba acceso al colegio de las Hijas de la Caridad de Santa Ana, que vemos a la izquierda, en lo que fue su primera ampliaci‚îú‚îÇn realizada en 1929, que llegaba hasta la mitad de la calle Santa Catalina, ya alineada con la que ser‚îú¬°a la nueva anchura de toda la calle. A finales de los a‚îú‚ñíos 50, este colegio se ampliar‚îú¬°a una vez m‚îú√≠s, hasta la calle San Miguel. Como ya no ten‚îú¬°a sitio para m‚îú√≠s ampliaciones, un a‚îú‚ñío antes de esta imagen dej‚îú‚îÇ este enclave, y se fue junto al Canal Imperial, a un espacio de algo m‚îú√≠s de 4 Ha. de extensi‚îú‚îÇn. Al fondo, la fachada del Coso Medio correspondiente a los n‚îú‚ïëmeros 75-85, en la manzana entre las calles Pardo Sastr‚îú‚îÇn (izquierda) y Pedro Joaqu‚îú¬°n Soler (derecha), est‚îú√≠ viviendo su propia "transici‚îú‚îÇn" de edificaciones. A la derecha, un pedacito del met‚îú√≠lico revestimiento de la balconada del recient‚îú¬°simo y modern‚îú¬°simo edificio n‚î¨‚ïë 84 del Coso, edificado en parte de lo que fuera la casa-palacio de los Climentes, luego de Aranda.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65122100, -0.87857400, '0101000020E61000007CB5A338471DECBFF5BBB0355BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19803380318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19803380318.webp', 'https://www.flickr.com/photos/zaragozaantigua/19803380318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22748, 'Caja de Zaragoza 1970', 'Imagen publicitaria de la sede central de la Caja de Ahorros y Monte de Piedad de Zaragoza, Arag‚îú‚îÇn y Rioja, en el chafl‚îú√≠n entre las calles de San Jorge y San Andr‚îú¬Æs. Fue levantada en 1913 seg‚îú‚ïën proyecto de Ram‚îú‚îÇn Cort‚îú√≠zar y Luis Elizalde de 1910. En 1980, la sede central de la entidad pas‚îú‚îÇ a la plaza de Para‚îú¬°so, quedando este inmueble como agencia urbana. Fuente visual: fondohistorico.ceca.es/', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65291000, -0.87800700, '0101000020E61000001E17D522A218ECBF9D9D0C8E92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32534486640.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32534486640.webp', 'https://www.flickr.com/photos/zaragozaantigua/32534486640/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22783, 'Calle de M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez 1979', 'Imagen capturada desde el arranque de la calle de San F‚îú¬Ælix y centrada en los restos de la portada del antiguo edificio donde estuviera ubicado el Colegio Polit‚îú¬Æcnico Virgen del Pilar, en la calle de Casto M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez n‚î¨‚ïë 36, luego n‚î¨‚ïë 34. Como indica la fotograf‚îú¬°a, la portada de ingreso perduraba todav‚îú¬°a como reliquia de una singular casona dieciochesca ya derribada. A‚îú‚ñíos despu‚îú¬Æs, a finales de la d‚îú¬Æcada de los ochenta, esta zona ser‚îú¬°a reedificada integralmente con modernos edificios de vivienda. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65349300, -0.87898000, '0101000020E61000008DD13AAA9A20ECBF1C959BA8A5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37898747514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37898747514.webp', 'https://www.flickr.com/photos/zaragozaantigua/37898747514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22809, 'Calle de Santa Catalina 1973', 'In‚îú¬Ædita imagen capturada tras el derribo del antiguo inmueble del n‚î¨‚ïë 84 del tramo medio del Coso, con una gran zona recayente a la calle de Santa Catalina, desde donde se ha tomado la fotograf‚îú¬°a. En primer t‚îú¬Ærmino, ingreso al garito que con el nombre de "El Cortijo", formaba parte de la original "senda de los elefantes" junto con establecimientos como la cervecer‚îú¬°a alemana Heidelberg, y bares como La Patata Brava, el Chip‚îú¬Æn y el San Miguel, toda una mini-zona de la ‚îú¬Æpoca en este entorno entre el Coso y la calle de San Miguel. Este gran solar form‚îú‚îÇ parte en su tiempo de la gran casa de los Climent, luego propiedad del conde de Aranda. Al fondo, vista parcial del Coso donde a la izquierda se nos muestra parcialmente el antiguo inmueble del n‚î¨‚ïë 75, luego derribado para conformar un enorme bloque tan moderno como descontextualizado, tal y como suceder‚îú¬°a con el edificio aqu‚îú¬° levantado por la constructora Marvel, que hoy nos sigue recordando c‚îú‚îÇmo se hac‚îú¬°an las cosas en Zaragoza, urban‚îú¬°sticamente hablando, en la terrible d‚îú¬Æcada de los a‚îú‚ñíos 70. Sobre ella y al fondo, emerge el bloque del n‚î¨‚ïë 77 del Coso, que ya antes hab‚îú¬°a sustituido a la antigua gran casa de los P‚îú¬Ærez de Nueros, marqueses de Campo Olivar.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65092500, -0.87878800, '0101000020E61000007FC00303081FECBF0C93A98251D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51538852010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51538852010.webp', 'https://www.flickr.com/photos/zaragozaantigua/51538852010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21235, 'Molino de Goicoechea 1907', 'Postal. "Colecci‚îú‚îÇn Patria y Fe n‚îú‚ïëm. 14, Zaragoza 1908 - Centenario de los Sitios", 1907. "Situado en la ronda, junto a la margen izquierda del Huerva, fue punto muy estrat‚îú¬Ægico para contener el movimiento merodeador de los franceses. En la jornada sangrienta del 27 de enero de 1809, las tropas enemigas lograron apoderarse del molino." Molino de aceite de Juan de Goicoechea (1789), en los terrenos del actual Parque Bruil, donde se conservan algunos de sus restos. Fuente: www.pasapues.es', 1907, 1907, 1907, 'Anos 1900', 'LAS FUENTES', 41.64921700, -0.86857500, '0101000020E610000041F163CC5DCBEBBFED80EB8A19D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19581115365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19581115365.webp', 'https://www.flickr.com/photos/zaragozaantigua/19581115365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22811, 'Coso Medio 1973', 'Imagen centrada en la esquina del tramo medio del Coso con la calle Eusebio Blasco, donde destaca un estacional puesto de casta‚îú‚ñíera instalado junto al tel‚îú¬Æfono de la parada de "autom‚îú‚îÇviles de punto" o taxis tradicionalmente all‚îú¬° ubicada desde hac‚îú¬°a d‚îú¬Æcadas. Sobre el adoquinado firme perdura el antiguo trazado de la tranviaria l‚îú¬°nea 13 "San Jos‚îú¬Æ", que desde 1945 transit‚îú‚îÇ por ‚îú¬Æl hasta que en 1967 se refundi‚îú‚îÇ con la l‚îú¬°nea 11 "Parque". Una ligera lluvia ha dejado su huella reflectante en el adoquinado y en los baldosines de la acera. Al fondo, la plaza de Espa‚îú‚ñía.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65171100, -0.87922800, '0101000020E6100000954737C2A222ECBFC3B81B446BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51548607831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51548607831.webp', 'https://www.flickr.com/photos/zaragozaantigua/51548607831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22853, 'Coso Medio c.1988', 'Calle del Coso en su tramo entre plaza de Espa‚îú‚ñía y Espartero, que en esta recopilaci‚îú‚îÇn hemos dado en bautizar "Coso Medio", para diferenciarlo del Alto (C‚îú¬Æsar Augusto-Plaza de Espa‚îú‚ñía) y el Bajo (Espartero-Tener‚îú¬°as). A la izquierda, el Teatro Principal y el Banco de Santander. A la derecha, cubierto por vallas publicitarias, el edificio del Colegio de Santa Ana, ya abandonado y a la espera de derribo y sustituci‚îú‚îÇn por el Hotel Reino de Arag‚îú‚îÇn. Fuente: www.facebook.com/photo.php?fbid=1577428155818748&set=...', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65167100, -0.87948300, '0101000020E61000003C6A4C88B924ECBF356090F469D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295663888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295663888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295663888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22863, 'San Gil 1987', 'Luis M‚îú¬°nguez. 1987. Imagen hacia el Oeste, desde la torre de la Iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës m‚îú√≠s cercana al Teatro Romano, en la plaza de San Pedro Nolasco. La visual se centra en la torre de la iglesia de San Gil Abad (la iglesia, en Don Jaime I; la torre, en Est‚îú¬Æbanes), antes de su restauraci‚îú‚îÇn, con un aspecto muy deslucido. Un poco antes, a la izquierda, uno de los remates del tejado de la que fue sede central de una entidad local de ahorro, entre la calle San Andr‚îú¬Æs y San Jorge. A la derecha, un poco m‚îú√≠s adelante, la galer‚îú¬°a de arquillos de las traseras del Casino Mercantil, en la calle Cuatro de Agosto. Al fondo, dos identificativos edificios de la plaza San Roque, junto al Coso Alto: el edificio de la "Adri‚îú√≠tica de Seguros" (1948), a la derecha, y el torre‚îú‚îÇn del entonces Banco Central, que en 1970 hab‚îú¬°a absorbido al Banco de Arag‚îú‚îÇn (1945), cuya sede central era esa.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15659392618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15659392618.webp', 'https://www.flickr.com/photos/zaragozaantigua/15659392618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22872, 'Teatro romano 1987', 'Luis M‚îú¬°nguez. 1987. Imagen hacia el Sur desde la torre de la Iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës m‚îú√≠s cercana al Teatro Romano, en la plaza de San Pedro Nolasco. En 1972, este espacio estaba destinado a ser la sede central de una entidad local de ahorro, pero la publicidad del descubrimiento de los restos del Teatro torcieron el destino, y desde entonces el solar qued‚îú‚îÇ en estas condiciones, tras las primeras excavaciones arqueol‚îú‚îÇgicas. A la derecha, tejado del edificio de San Jorge 12-14, que fue casa palaciega renacentista del Justicia Mayor en el s.XVI, muy reformada a mediados del s.XVIII. A‚îú‚ñíos despu‚îú¬Æs de tomar esta imagen (1995) la Comisi‚îú‚îÇn Provincial de Patrimonio Cultural acord‚îú‚îÇ demolerla para ampliar la zona arqueol‚îú‚îÇgica, y conservar la fachada, luego integrada en el nuevo espacio muse‚îú¬°stico inaugurado en mayo de 2003. Tras la casa, estado de los restos del Teatro romano, con la rampa de bajada de la calle de la Ver‚îú‚îÇnica. Pasada la calle, aspecto del dieciochesco edificio esquina con la calle Pardo Sastr‚îú‚îÇn.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15818617806.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15818617806.webp', 'https://www.flickr.com/photos/zaragozaantigua/15818617806/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26019, 'Isabel la Cat‚îú‚îÇlica 1962', 'Imagen en altura del entorno de la Feria de Muestras, a cuya vera fue instalado un Arco de triunfo conmemorativo del "D‚îú¬°a de la Hispanidad" durante las Fiestas del Pilar de ese a‚îú‚ñío, justo en el arranque del paseo de Isabel la Cat‚îú‚îÇlica. Desde este punto de vista, tomado a la altura de la torre de la Editorial Vives, el naturalizado Arco nos ofrece sus cuartos traseros. En su parte frontal, conviv‚îú¬°an en hispana armon‚îú¬°a una macedonia de ic‚îú‚îÇnicas representaciones con C‚îú¬Æsar Augusto, Alfonso I, Col‚îú‚îÇn, sus Cat‚îú‚îÇlicas majestades, las tres carabelas, y un amplio y surtido despliegue de banderas americanas. Una imagen para postal de la Editorial Arribas. Fuente: www.delcampe.es/', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.63732000, -0.89852900, '0101000020E6100000213EB0E3BFC0ECBF1A8BA6B393D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24040723341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24040723341.webp', 'https://www.flickr.com/photos/zaragozaantigua/24040723341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22878, 'Calle Porcell 1989', 'Tras el 18 de julio de 1936 el fallido golpe de estado triunfa en Zaragoza, que queda metida en el saco de municipios del Arag‚îú‚îÇn franquista. En 1937, como arma y propaganda de guerra del "Movimiento", aparecen nuevos medios escritos controlados por Falange, entre ellos, el diario "Amanecer", que hasta su desaparici‚îú‚îÇn en junio de 1979 mantuvo una l‚îú¬°nea editorial de centro liberal, entre la derecha, y la extrema derecha. En mayo de 1989 el inmueble del diario, situado en la calle Porcel n‚î¨‚ïë 1, segu‚îú¬°a en desuso y fue ocupado por el reciente COZ ("Colectivo Okupa de Zaragoza"). Este acto dur‚îú‚îÇ doce d‚îú¬°as, durante los cuales se comenz‚îú‚îÇ a adecentar el local, hasta el desalojo realizado por antidisturbios de la Polic‚îú¬°a Nacional. No hubo detenidos ni multas. En la imagen, aspecto parcial de la fachada del diario ocupado, en la calle Porcell. Fuente: www.zaragozarebelde.org/', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.65136600, -0.87908800, '0101000020E610000025CB49287D21ECBFF9DC09F65FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17232817905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17232817905.webp', 'https://www.flickr.com/photos/zaragozaantigua/17232817905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22933, 'Plaza Jos‚îú¬Æ Sinu‚îú¬Æs 1981', 'Imagen capturada desde la calle Don Jaime I, y centrada en las traseras del Teatro Principal con el aspecto que les hab‚îú¬°a dado Ricardo Magdalena a finales del siglo XIX, rematadas en un espectacular front‚îú‚îÇn con el escudo municipal, y las representaciones realizadas por Francisco Rallo de las musas Terps‚îú¬°core y Euterpe. Pocos a‚îú‚ñíos despu‚îú¬Æs, P‚îú¬Ærez Latorre remodelar‚îú¬°a esta fachada, despoj‚îú√≠ndola del front‚îú‚îÇn, y las musas fueron reubicadas en la fachada principal del Coso. Como una sana a‚îú‚ñíadidura, la plaza fue peatonalizada, y el monumento a Jos‚îú¬Æ Sinu‚îú¬Æs y Urbiola dej‚îú‚îÇ de ser rotonda entre el tr‚îú√≠fico rodado. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65234600, -0.87917300, '0101000020E6100000B2D6506A2F22ECBF95D6DF1280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31853815772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31853815772.webp', 'https://www.flickr.com/photos/zaragozaantigua/31853815772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22974, 'Teatro Romano a‚îú‚ñíos 90', 'F. A. Escudero. Foto a‚îú¬Ærea del Teatro Romano de Zaragoza. A‚îú‚ñíos 90 del siglo XX. El Teatro Romano de Caesaraugusta fue uno de los mayores de toda Hispania (capacidad para 6.000 espectadores en una urbe de unos 18.000 habitantes). Edificado en ‚îú¬Æpoca de Tiberio (14-37) y finalizado en ‚îú¬Æpoca de Claudio (41-54), siguiendo el modelo del Teatro Marcelo de Roma. Su estructura, formada por anillos conc‚îú¬Æntricos reforzados por muros radiales, est‚îú√≠ construida en aglomerado de hormig‚îú‚îÇn de cal y canto y recubierta con placas de piedra caliza. Al no apoyar su grader‚îú¬°o en ninguna colina, se cre‚îú‚îÇ un sistema de galer‚îú¬°as abovedadas que permite la circulaci‚îú‚îÇn interior. Es el ‚îú‚ïënico teatro peninsular con una fosa bajo el escenario para acceso de los actores en ciertos momentos de la obra. Conserva buena parte de sus estructuras, como la cavea, la orchestra, el balteus, hyposcenium, la cripta y los espacios entre los muros radiales de la cavea. Su ‚îú¬Æpoca de mayor esplendor corresponde a las dinast‚îú¬°as Julio-Claudia y Flavia (siglo I). En el siglo III es abandonado, expoliado y sus ruinas se reaprovechan como cimientos de viviendas posteriores, e incluso aparecen restos de una necr‚îú‚îÇpolis visig‚îú‚îÇtica. Como teatro, permaneci‚îú‚îÇ oculto bajo el urbanismo de la ciudad. Fue redescubierto en 1972, cuando un vecino alert‚îú‚îÇ a la prensa de la existencia de restos arqueol‚îú‚îÇgicos en una obra en construcci‚îú‚îÇn. En la imagen aparece sin la estructura que lo cubre hoy, colocada en 2003. Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65198200, -0.87767800, '0101000020E6100000E4654D2CF015ECBF53CA6B2574D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15067104262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15067104262.webp', 'https://www.flickr.com/photos/zaragozaantigua/15067104262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22982, 'Teatro Romano 1992', 'Desde la torre de la Iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës imagen del Teatro Romano. A la izquierda, pegado a la iglesia, las construcciones de la Hermandad del Santo Refugio dise‚îú‚ñíadas por Jos‚îú¬Æ de Yarza en 1908. A la derecha, patio y tejado de la que fue casa palaciega renacentista del Justicia Mayor en el s.XVI, muy reformada a mediados del s.XVIII. Tras la casa, estado de los restos del Teatro romano, con la rampa de bajada de la calle de la Ver‚îú‚îÇnica, con su muro y sus frondosos ‚îú√≠rboles. Fuente: "Zaragoza barrio a barrio"', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15945592091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15945592091.webp', 'https://www.flickr.com/photos/zaragozaantigua/15945592091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23015, 'Calle San Jorge a‚îú‚ñíos 90', 'Vista del edificio del n‚îú‚ïëmero 12 de la calle de San Jorge, desde la plaza de San Pedro Nolasco. El inmueble, propiedad de Arturo Guill‚îú¬Æn y Urz‚îú√≠iz, fue rehabilitado como Museo del Teatro Romano de Zaragoza en 2003. Fuente: www.eszaragoza.eu/2017/06/opiniones-de-zaragozanos-de-198...', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65258200, -0.87733900, '0101000020E6100000C72B103D2913ECBFA9FA95CE87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35705560164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35705560164.webp', 'https://www.flickr.com/photos/zaragozaantigua/35705560164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22145, 'Paseo Isabel la Cat‚îú‚îÇlica a‚îú‚ñíos 50', 'Foto: Colecci‚îú‚îÇn Sergio Joven. Grupo de muchachas apostadas en el pretil del r‚îú¬°o Huerva, junto al quiosco esquinero con el puente del 13 de Septiembre de acceso al parque Primo de Rivera, desde el que est‚îú√≠ tomada la foto. Al fondo, edificios de la Feria de Muestras. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1950, 1950, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63740700, -0.89810100, '0101000020E61000001C28F04E3EBDECBFE99E758D96D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26300037300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26300037300.webp', 'https://www.flickr.com/photos/zaragozaantigua/26300037300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22150, 'Parque Primo de Rivera 1956', 'Foto: Jos‚îú¬Æ Antonio Duce. Febrero de 1956. Aspecto helado del estanque conocido como "la piscina del huevo", sito en el parque Primo de Rivera, junto a la pista de patinaje equipada con un mapa de Espa‚îú‚ñía en relieve. Fuente: www.gozazaragoza.com/', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63399900, -0.89736000, '0101000020E610000049A297512CB7ECBF2E5915E126D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27604751734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27604751734.webp', 'https://www.flickr.com/photos/zaragozaantigua/27604751734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23020, 'Calle de San Jorge 1990', 'Imagen capturada en la plaza de San Pedro Nolasco y centrada en la fachada del n‚î¨‚ïë 12-14 de la calle de San Jorge, que fuera original casona renacentista del Justicia Mayor del reino de Arag‚îú‚îÇn a finales del siglo XVI, muy reformada a mediados del XVIII, y nuevamente remozada a mediados del XIX. A‚îú‚ñíos despu‚îú¬Æs de esta toma fotogr‚îú√≠fica, el solar de la casa fue derribado durante las obras de despeje de la "scaena" del inmediato teatro romano de Caesaraugusta, conservando la fachada integrada en un nuevo edificio destinado a diversos servicios del Museo del Teatro de Caesaragusta e inaugurado en 2003. En primer t‚îú¬Ærmino, la plaza de San Pedro Nolasco en la ‚îú¬Æpoca de la hegemon‚îú¬°a del tr‚îú√≠fico rodado en estado de reposo. Hacia la izquierda queda la iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës (donde antes estuviera la iglesia del colegio de San Pedro Nolasco). Hacia la derecha queda la antigua calle de Gabriel Zaporta, perenne recuerdo de la monumental y derribada casa hom‚îú‚îÇnima. Fuente visual: AMZ.', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.65258200, -0.87733900, '0101000020E6100000C72B103D2913ECBFA9FA95CE87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42289206005.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42289206005.webp', 'https://www.flickr.com/photos/zaragozaantigua/42289206005/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23065, 'Calle del Refugio 1997', 'Imagen centrada en el ingreso al singular local El Monaguillo, en los bajos del inmueble del n‚î¨‚ïë 4-6 de la calle del Refugio. Este bar, ubicado en las bodegas de esta antigua casa del siglo XVII, fue hasta su cierre un emblem‚îú√≠tico y recoleto espacio conocido por la nocturna programaci‚îú‚îÇn de conciertos en directo. Este inmueble ser‚îú¬°a rehabilitado integralmente pocos a‚îú‚ñíos despu‚îú¬Æs, conservando las bodegas y la colorista fachada con su ajedrezado cer‚îú√≠mico.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.65331400, -0.87773600, '0101000020E61000000BB3D0CE6916ECBF6D020CCB9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50512217313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50512217313.webp', 'https://www.flickr.com/photos/zaragozaantigua/50512217313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23449, 'Montserrat Caball‚îú¬Æ 1973', 'Archivo Municipal Zaragoza. Jos‚îú¬Æ Jaria Serrano. 26/05/1973. Imagen del Teatro Principal durante la representaci‚îú‚îÇn de la ‚îú‚îÇpera "Il Trovatore" de Verdi, a cargo de (por orden esc‚îú¬Ænico) Franco Bordoni, Bianca Berini, Montserrat Caball‚îú¬Æ y Bernab‚îú¬Æ Mart‚îú¬°. "El trovador" (Il trovatore) es una ‚îú‚îÇpera en cuatro actos con m‚îú‚ïësica de Giuseppe Verdi y libreto en italiano de Salvatore Cammarano, basada en la obra de teatro "El trovador" (1836) de Antonio Garc‚îú¬°a Guti‚îú¬Ærrez. La trama -intrincada y novelesca- se desarrolla entre Vizcaya y Arag‚îú‚îÇn en el marco de la revuelta de Jaime de Urgel, a principios del siglo XV, contra Fernando de Antequera, tras el Compromiso de Caspe. El castillo de La Aljafer‚îú¬°a es marco esc‚îú¬Ænico central de la trama. Montserrat Caball‚îú¬Æ y Bernab‚îú¬Æ Mart‚îú¬° eran tambi‚îú¬Æn pareja sentimental desde hac‚îú¬°a m‚îú√≠s de diez a‚îú‚ñíos, y Bernab‚îú¬Æ era ma‚îú‚ñío. Ella, catalana.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65203000, -0.87945400, '0101000020E6100000A8C30AB77C24ECBF650113B875D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15076424110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15076424110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15076424110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23499, 'Coso y pavos 1861', 'Calle del Coso y plaza de la Constituci‚îú‚îÇn. "Vista de la calle del Coso en direcci‚îú‚îÇn a la plaza de la Constituci‚îú‚îÇn, que quedar‚îú¬°a a la derecha de la imagen. Aunque a nuestros ojos resulta pr‚îú√≠cticamente imperceptible, la mancha oscura que queda en el centro de la calzada, no es sino un reba‚îú‚ñío de pavos junto a su vendedor. Durante el siglo XIX y primera mitad del siglo XX, los vendedores de pavos procedentes de pueblos cercanos, se acercaban hasta el centro de la ciudad para ofrecer su producto en la cercan‚îú¬°a de las fechas navide‚îú‚ñías, por lo que podemos conjeturar que la fotograf‚îú¬°a pudo ser realizada en las Navidades de 1860-1861." Jos‚îú¬Æ Antonio Hern‚îú√≠ndez Latas. Fuente: Mariano J‚îú‚ïëdez y Ortiz. ‚îú√ºlbum de Andr‚îú¬Æs Mart‚îú¬°n e Ip‚îú√≠s. Colecci‚îú‚îÇn Mariano Mart‚îú¬°n Casalderrey. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.65133400, -0.87849300, '0101000020E61000004A7A185A9D1CECBFED629AE95ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14874371526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14874371526.webp', 'https://www.flickr.com/photos/zaragozaantigua/14874371526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23600, 'L‚îú¬°nea 13 Tranv‚îú¬°a 1945', 'L‚îú¬°nea 13 de los Tranv‚îú¬°as de Zaragoza. El Coche 201 en la parada de principio de L‚îú¬°nea, situada en la calle Eugenio Blasco. El edificio tras el tranv‚îú¬°a es el del Teatro Principal, y la calle del fondo, la de Ver‚îú‚îÇnica, que entonces era bastante m‚îú√≠s estrecha de lo que ahora es, hasta que se derribaron los edificios de los n‚îú‚ïëmeros impares. A ra‚îú¬°z de eso, a‚îú‚ñíos despu‚îú¬Æs, saldr‚îú¬°a a la luz el Teatro Romano... La L‚îú¬°nea 13 se conoc‚îú¬°a como "la de S. Jos‚îú¬Æ", pues comunicaba "el centro" son este Barrio por medio del tranv‚îú¬°a, siguiendo el trayecto de ida-vuelta Eugenio Blasco-Coso-Espartero-Pza. S. Miguel-Miguel Servet-Avda. J. Jos‚îú¬Æ, terminando al lado del Cine Rialto. Proyectada desde 1927, fue realidad en 1945. En 1967 se unific‚îú‚îÇ con la L‚îú¬°nea 11, "Parque", tomando su numero, y creando la denominaci‚îú‚îÇn "Parque-S. Jos‚îú¬Æ". Tras ser tristemente clausurada el 23 de enero de 1976, la l‚îú¬°nea se transfigur‚îú‚îÇ en el recorrido "de toda la vida" del Autob‚îú‚ïës Urbano n‚î¨‚ïë 40. Fuente: "Los tranv‚îú¬°as de Zaragoza", J. Pe‚îú‚ñía/J. M. Valero, DPZ, 1985.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.65194300, -0.87899700, '0101000020E610000010070951BE20ECBF96ED43DE72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14673965999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14673965999.webp', 'https://www.flickr.com/photos/zaragozaantigua/14673965999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23601, 'Teatro Principal c.1900', 'Teatro Principal de Zaragoza (1799), reformado en 1870 por Ricardo Magdalena, a quien se debe la fachada que aqu‚îú¬° aparece. A la izquierda, el inmueble del n‚î¨‚ïë 61, donde estaba radicada la redacci‚îú‚îÇn, imprenta y administraci‚îú‚îÇn de El Diario de Zaragoza, adem‚îú√≠s del Colegio de San Jos‚îú¬Æ con su aulario para "Se‚îú‚ñíoritos" y para "Se‚îú‚ñíoritas".', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65179100, -0.87941600, '0101000020E61000004888F2052D24ECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750439809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750439809.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750439809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23602, 'Plazuela de la Ver‚îú‚îÇnica 1949', 'Al final de la original calle de la Ver‚îú‚îÇnica, donde desemboca en la de Pedro Joaqu‚îú¬°n Soler (a la izquierda, fuera de plano), se encontraba la recoleta plazuela de la Ver‚îú‚îÇnica, un espacio caracter‚îú¬°stico del antiguo Casco Viejo, a resguardo de cierzo, con solanera invernal, y fresquera en verano. Las obras de ampliaci‚îú‚îÇn de las calles de la Ver‚îú‚îÇnica y de Pedro Joaqu‚îú¬°n Soler, supusieron su extinci‚îú‚îÇn. De derecha a izquierda, los antiguos edificios de los n‚îú‚ïëmeros 1, 2-3, y 4 de la desaparecida plaza. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65148700, -0.87742500, '0101000020E61000006B2BF697DD13ECBF74620FED63D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817801109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817801109.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817801109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23604, 'Coso Medio 1930', '"Calle del Coso". Imagen tomada desde cierta altura en un edificio del Coso. Al fondo, la Plaza de la Constituci‚îú‚îÇn. A la izquierda la calle Don Jaime.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65162300, -0.87934600, '0101000020E610000010CAFB389A23ECBF2429E96168D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877543319.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877543319.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877543319/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23606, 'Calle Pardo Sastr‚îú‚îÇn 1949', 'Archivo Municipal de Zaragoza. Archivo Mora. 1949. "Calle de Pardo Sastr‚îú‚îÇn (antes calle del Romero)." Esta calle comunica la calle Coso con la de la Ver‚îú‚îÇnica. Antes, se denomin‚îú‚îÇ calle de San Crist‚îú‚îÇbal (siglo XIX), y luego del Romero (siglo XX). La imagen est‚îú√≠ tomada en direcci‚îú‚îÇn al Coso. Al fondo, manzana entre las calles de Santa Catalina, a la izquierda, y Juan Porcell, a la derecha. El edificio que aparece se corresponde con el entonces n‚î¨‚ïë 94 del Coso, en cuyos bajos se encontraba la antigua farmacia de Gabriel Faci Abad.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65180700, -0.87855200, '0101000020E610000088BB7A15191DECBFE5266A696ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14929037688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14929037688.webp', 'https://www.flickr.com/photos/zaragozaantigua/14929037688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23610, 'Coso Medio c.1900', 'Archivo Municipal. Hauser y Menet (Madrid). 1897-1900. "Zaragoza. El Coso." Fotograf‚îú¬°a utilizada por la casa Editorial "Hauser y Menet" para postal impresa. En la imagen, el Coso Medio capturado desde la plaza de la Constituci‚îú‚îÇn. A la izquierda, el Teatro Principal. Circulan tranv‚îú¬°as a propulsi‚îú‚îÇn de sangre. La postal fue escrita y fechada en Almaz‚îú√≠n (Soria), el 24-11-1903, con el texto "De no recibir telegrama despu‚îú¬Æs de esta postal, es seguro que ma‚îú‚ñíana 25 a las 10 de la noche tendr‚îú√≠ el placer de abrazarte tu padre." Lleva sello postal de 10 c‚îú¬Æntimos (de Alfonso XIII ni‚îú‚ñío) matasellado.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65177700, -0.87967800, '0101000020E61000008E57207A5226ECBF7BA4C16D6DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15436958430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15436958430.webp', 'https://www.flickr.com/photos/zaragozaantigua/15436958430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23611, 'Calle Porcell 1957', 'Vista de la calle Porcell en direcci‚îú‚îÇn Sur, donde se encuentra con San Miguel, al fondo. A la izquierda, el n‚î¨‚ïë 7 de la calle, perteneciente al Colegio de Santa Ana, que se extend‚îú¬°a hasta el Coso. Luego, el n‚î¨‚ïë 17 de San Miguel, de 1923. Enfrente, el n‚î¨‚ïë 16 de San Miguel, de los a‚îú‚ñíos 30 del s.XX. A la derecha, la fachada lateral de la central el‚îú¬Æctrica que llegaba hasta la calle Jer‚îú‚îÇnimo Blancas. Por tener s‚îú‚îÇlo una altura, y ese tejado a doble vertiente, el sol penetra en la calle Porcell e ilumina a dos ni‚îú‚ñías paseantes, como ya nunca m‚îú√≠s lo har‚îú√≠ cuando la central sea piqueteada y sustituida por el actual bloque de seis alturas, poco tiempo despu‚îú¬Æs. Cierra el recorrido el edificio-almac‚îú¬Æn de la derecha. La calle parece m‚îú√≠s ancha, con sus aceras de juguete, sus recios bordillos, y ese adoquinado tan inc‚îú‚îÇmodo para zapatos de alto tac‚îú‚îÇn. Fuente: "Zaragoza viva" (1969)', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.65095700, -0.87941000, '0101000020E6100000C0CFB8702024ECBF170D198F52D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15671790810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15671790810.webp', 'https://www.flickr.com/photos/zaragozaantigua/15671790810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23612, 'Coso Medio 1937', 'Desfile de la Tercera Bandera de Falange, proveniente del frente de la Sierra de Alcubierre, que llegaba a descansar a los acuartelamientos de la ciudad. Al fondo, cartel de la Imprenta de Heraldo de Arag‚îú‚îÇn, en el n‚î¨‚ïë 100 del Coso (aunque la sede central ya estaba en Independencia n‚î¨‚ïë 29), en la manzana entre las calles de Santa Catalina (justo a su izquierda) y de Porcell. Fuente: www.facebook.com/photo.php?fbid=869755063057693&set=o...', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65173400, -0.87958300, '0101000020E61000001EC3633F8B25ECBF7BD80B056CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704855718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704855718.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704855718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23614, 'Pedro Joaqu‚îú¬°n Soler 1951', 'Imagen de la calle Pedro Joaqu‚îú¬°n Soler capturada desde el Coso Medio, cuando eran muy otros los edificios que la flaqueaban, as‚îú¬° como su anchura. Al fondo, los edificios de la calle de la Ver‚îú‚îÇnica. A la derecha quedaba la plazuela de la Ver‚îú‚îÇnica. Sobre todos estos elementos, iluminada, una torre de la Iglesia del Sagrado Coraz‚îú‚îÇn de la plaza de San Pedro Nolasco. Fuente visual: Archivo Municipal. Archivo Mora. Junio 1951.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65115500, -0.87773400, '0101000020E6100000DECA129D6516ECBF3ED00A0C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18048230774.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18048230774.webp', 'https://www.flickr.com/photos/zaragozaantigua/18048230774/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23618, 'Teatro Principal 1962', 'Foto: Gerardo Sancho Ramo. Fachada del Teatro Principal de Zaragoza en el n‚îú‚ïëmero 57 del Coso Medio, ornada con motivo alusivo a la celebraci‚îú‚îÇn de las fiestas patronales, en este caso como sede de la Semana Nacional de la Jota. Fuente: AMZ.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65179100, -0.87929200, '0101000020E6100000444DF4F92823ECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22218601886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22218601886.webp', 'https://www.flickr.com/photos/zaragozaantigua/22218601886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23624, 'Coso Medio 1902', 'Imagen capturada desde la altura de la antigua calle de los Sitios, con una vista del soleado tramo medio del Coso en sus n‚îú‚ïëmeros impares, desde el Teatro Principal y el Banco de Espa‚îú‚ñía hasta la calle de Espartero. Sobresalen, emergiendo sobre el fondo, la torre de la iglesia parroquial de la Mar‚îú¬°a Magdalena, y la torre del Seminario Sacerdotal de San Carlos. Fuente visual: Gu‚îú¬°a de Zaragoza 1902.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65171600, -0.87947700, '0101000020E6100000B3B112F3AC24ECBFD5230D6E6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35136734572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35136734572.webp', 'https://www.flickr.com/photos/zaragozaantigua/35136734572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23626, 'Coso Medio 1949', 'Imagen capturada en el arranque del tramo medio del Coso a la altura del Teatro Principal, donde figura en cartel la exitosa revista "Melod‚îú¬°as del Danubio" de la compa‚îú‚ñí‚îú¬°a Los Vieneses de Artur Kaps, donde destacaba el c‚îú‚îÇmico Franz Joham. De procedencia austr‚îú¬°aca, las giras de esta compa‚îú‚ñí‚îú¬°a estaban determinadas desde 1940 por el progresivo alejamiento f‚îú¬°sico de la Europa dominada directamente por el R‚îú¬Ægimen nazi (Kaps y Joham eran jud‚îú¬°os), de forma que en 1942 acabaron recalando en Espa‚îú‚ñía, en Barcelona, donde iniciaron una longeva carrera art‚îú¬°stica especialmente exitosa en las dos d‚îú¬Æcadas posteriores, impulsada de forma popular en el nuevo medio televisivo. Centra la escena el coche 158, un Topolino en servicio en la l‚îú¬°nea 1. Bajo Arag‚îú‚îÇn del tranv‚îú¬°a, reci‚îú¬Æn circulando en direcci‚îú‚îÇn a Miguel Servet, antes de que se habilitara el bucle que rodear‚îú¬°a el Teatro Principal y trasladar‚îú¬°a el inicio de l‚îú¬°nea a su parte trasera, en la calle de Valent‚îú¬°n Zabala. Al fondo y a la izquierda, "el Palomar" del Casino Mercantil. Fuente visual: Colecci‚îú‚îÇn particular.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65171600, -0.87947700, '0101000020E6100000B3B112F3AC24ECBFD5230D6E6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47052703411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47052703411.webp', 'https://www.flickr.com/photos/zaragozaantigua/47052703411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23627, 'Coso Medio c.1895', 'In‚îú¬Ædita imagen capturada en altura desde la umbr‚îú¬°a del inmueble del n‚î¨‚ïë 72 del Coso Medio, esquinero con la calle de los Sitios, con una buena panor‚îú√≠mica del soleado tramo de los n‚îú‚ïëmeros impares, desde el 61, a la izquierda, inmediato al Teatro Principal, cuya fachada presenta el aspecto dado por la reforma dise‚îú‚ñíada en 1870 por Ricardo Magdalena, y hasta el fondo a la derecha, donde se destaca luminoso el antiguo n‚î¨‚ïë 1 en el arranque de la calle de Baldomero Espartero. Sobre el firme, tendido tranviario de las l‚îú¬°neas del Bajo Arag‚îú‚îÇn y de Circunvalaci‚îú‚îÇn, con servicio de coches traccionados por caballer‚îú¬°as.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65171900, -0.87948500, '0101000020E610000069520ABABD24ECBF469737876BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48060025631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48060025631.webp', 'https://www.flickr.com/photos/zaragozaantigua/48060025631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23630, 'Coso Medio c.1900', 'Imagen de detalle centrada en el inmueble del n‚î¨‚ïë 61 del tramo medio del Coso, propiedad de Luis Is‚îú√≠bal, secretario de la C‚îú√≠mara de Comercio de Zaragoza, donde estaba radicada la redacci‚îú‚îÇn, imprenta y administraci‚îú‚îÇn de "El Diario de Zaragoza. Peri‚îú‚îÇdico independiente", pionero del periodismo en Zaragoza desde 1797, adem‚îú√≠s de sucursal de "La Moda Elegante" y "La Ilustraci‚îú‚îÇn Espa‚îú‚ñíola". En 1908 este peri‚îú‚îÇdico fue redenominado "Diario de Avisos de Zaragoza", desapareciendo de esta forma la hist‚îú‚îÇrica cabecera. El edificio tambi‚îú¬Æn acog‚îú¬°a, en la planta superior, el Colegio de San Jos‚îú¬Æ con su aulario para "Se‚îú‚ñíoritos" y para "Se‚îú‚ñíoritas". A la derecha y fuera de plano, el Teatro Principal de Zaragoza. Este caser‚îú‚îÇn, reliquia habitacional de la antigua Zaragoza, posiblemente de los siglos XVI-XVII, fue derribado durante los prodigiosos a‚îú‚ñíos sesenta y sustituido por un horror de nueve alturas, construido para darle un toque m‚îú√≠s moderno a este tramo del Coso.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65189500, -0.87959200, '0101000020E6100000EB573A1F9E25ECBF85B69C4B71D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50096544887.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50096544887.webp', 'https://www.flickr.com/photos/zaragozaantigua/50096544887/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23632, 'Coso Medio 1962', 'Imagen capturada en el Coso Medio, con el tel‚îú‚îÇn de fondo edilicio entre las calles de Eusebio Blasco y San Vicente de Pa‚îú‚ïël, durante el transcurso del "Gran Preg‚îú‚îÇn de Fiestas" celebrado la ma‚îú‚ñíana del 7 de octubre de 1962. Destaca en primer t‚îú¬Ærmino y a caballo el pregonero Ignacio Moreno y su paje a pie, disfrazados con h‚îú√≠bitos neomedievales, seguidos de los maceros, timbaleros u trompetas municipales, una furgoneta con publicidad de "Mistol", y una de las carrozas que formaban parte de la nutrida comitiva (la titulada "Boa", con "se‚îú‚ñíoritas" hispanoamericanas). Sobre el adoquinado firme, v‚îú¬°as del tranv‚îú¬°a incluyendo el ramal de la l‚îú¬°nea 13 "San Jos‚îú¬Æ" que curvea hacia la terminal de la calle de Valent‚îú¬°n Zabala.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65162300, -0.87917400, '0101000020E6100000C9CA2F833122ECBF2429E96168D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51669267856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51669267856.webp', 'https://www.flickr.com/photos/zaragozaantigua/51669267856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23633, 'Teatro romano siglo I', 'Recreaci‚îú‚îÇn infogr‚îú√≠fica del teatro romano de Caesaraugusta. Imagen utilizada en la promoci‚îú‚îÇn de un documental de 2022 sobre las estructuras en la ingenier‚îú¬°a romana.', 50, NULL, 99, 'Siglo XIX', 'CENTRO', 41.65214700, -0.87779000, '0101000020E6100000D72FD80DDB16ECBF9E978A8D79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52502955167.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52502955167.webp', 'https://www.flickr.com/photos/zaragozaantigua/52502955167/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23951, 'Teatro Romano 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Mayo 1972. El Teatro Romano de Caesaraugusta fue uno de los mayores de toda Hispania (capacidad para 6.000 espectadores en una urbe de unos 18.000 habitantes). Edificado en ‚îú¬Æpoca de Tiberio (14-37) y finalizado en ‚îú¬Æpoca de Claudio (41-54), siguiendo el modelo del Teatro Marcelo de Roma. Su estructura, formada por anillos conc‚îú¬Æntricos reforzados por muros radiales, est‚îú√≠ construida en aglomerado de hormig‚îú‚îÇn de cal y canto y recubierta con placas de piedra caliza. Al no apoyar su grader‚îú¬°o en ninguna colina, se cre‚îú‚îÇ un sistema de galer‚îú¬°as abovedadas que permite la circulaci‚îú‚îÇn interior. Es el ‚îú‚ïënico teatro peninsular con una fosa bajo el escenario para acceso de los actores en ciertos momentos de la obra. Conserva buena parte de sus estructuras, como la cavea, la orchestra, el balteus, hyposcenium, la cripta y los espacios entre los muros radiales de la cavea. Su ‚îú¬Æpoca de mayor esplendor corresponde a las dinast‚îú¬°as Julio-Claudia y Flavia (siglo I). En el siglo III es abandonado, expoliado y sus ruinas se reaprovechan como cimientos de viviendas posteriores, e incluso aparecen restos de una necr‚îú‚îÇpolis visig‚îú‚îÇtica. Como teatro, permaneci‚îú‚îÇ oculto bajo el urbanismo de la ciudad. Fue redescubierto en 1972, cuando un vecino alert‚îú‚îÇ a la prensa de la existencia de restos arqueol‚îú‚îÇgicos en una obra en construcci‚îú‚îÇn. La imagen, durante la difusi‚îú‚îÇn del fenomenal hallazgo, tomada desde un edificio de la vecina calle San Jorge. Al fondo, tras la valla, la calle Ver‚îú‚îÇnica.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65248100, -0.87760200, '0101000020E610000024EF1CCA5015ECBF7521567F84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710649739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710649739.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710649739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23967, 'Calle de la Ver‚îú‚îÇnica 1974', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Diciembre 1974. La Caja de Ahorros de Zaragoza, Arag‚îú‚îÇn y Rioja ten‚îú¬°a intenci‚îú‚îÇn de construir en el "solar" entre San Jorge y la Ver‚îú‚îÇnica su nueva sede central, pero la s‚îú‚ïëbita aparici‚îú‚îÇn de un teatro romano de apenas capacidad para 6.000 espectadores desaconsej‚îú‚îÇ mantener el proyecto constructivo. La entidad de ahorro se busc‚îú‚îÇ otro sitio, que pronto encontr‚îú‚îÇ en un no mal lugar. Mientras, el solar del hallazgo fue enmurado, y los muros customizados con publicidad corporativa, adem‚îú√≠s de los entonces ya ilegales cristales rotos en el borde superior para evitar el acceso. En la imagen, vista desde la calle de la Ver‚îú‚îÇnica del muro tras el que est‚îú√≠ el teatro romano. A la izquierda, sobresale una de las torres de la iglesia de San Pedro Nolasco. A la derecha, la calle Pedro Joaqu‚îú¬°n Soler.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65188700, -0.87787600, '0101000020E61000007B2FBE688F17ECBF02D8800871D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15062502798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15062502798.webp', 'https://www.flickr.com/photos/zaragozaantigua/15062502798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23982, 'Teatro Romano 2002', 'Jos‚îú¬Æ Miguel Marco. Octubre 2002. Imagen desde globo aerost‚îú√≠tico del entorno del antiguo Teatro Romano de la ciudad, con las obras comenzadas para convertir en realidad el proyecto museogr‚îú√≠fico asociado que ser‚îú√≠ inaugurado al a‚îú‚ñío siguiente, incluyendo la cobertura del conjunto. Fotograf‚îú¬°a realizada con la Plaza de San Pedro Nolasco al fondo, la calle Pedro Joaqu‚îú¬°n Soler a la derecha, y los ‚îú√≠rboles, en primer plano, de la calle de la Ver‚îú‚îÇnica.', 2002, 2002, 2002, 'Siglo XXI', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15354244452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15354244452.webp', 'https://www.flickr.com/photos/zaragozaantigua/15354244452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24014, 'Teatro romano 2001', 'Vista del teatro romano de Zaragoza, antes de su musealizaci‚îú‚îÇn, inaugurada en 2003. Al fondo, calle de San Jorge y el Pilar. Fuente: Agencia EFE.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24283729469.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24283729469.webp', 'https://www.flickr.com/photos/zaragozaantigua/24283729469/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21629, 'Cabezo de Buenavista 1929', 'Dibujo del ilustrador turolense Manuel Bayo Mar‚îú¬°n donde se representa el monumento erigido en 1923 al rey Alfonso I en el Cabezo de Buenavista con la blanca escultura del Batallador tallada por Jos‚îú¬Æ Bueno, a la que en 1927 se a‚îú‚ñíadi‚îú‚îÇ la figura de un met‚îú√≠lico y oscuro le‚îú‚îÇn a sus pies. El suspirante monarca medieval aparece compungido y quejoso tras la reciente derrota pugil‚îú¬°stica de Paulino Uzcudun ("el Le‚îú‚ñíador vasco") ante el alem‚îú√≠n Max Schmeling en el Yankee Stadium (Nueva York). Al fondo, una veraniega y simp‚îú√≠tica luna llena ilumina el nocturno cielo sobre el Cabezo. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63366800, -0.89337000, '0101000020E6100000D847A7AE7C96ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37809897881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37809897881.webp', 'https://www.flickr.com/photos/zaragozaantigua/37809897881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24027, 'Manuel Machado 1931', 'Apenas diez d‚îú¬°as despu‚îú¬Æs de la proclamaci‚îú‚îÇn de la Segunda Rep‚îú‚ïëblica, tuvo lugar el estreno de la obra de teatro "La prima Fernanda" en el Teatro Reina Victoria de Madrid, una composici‚îú‚îÇn escrita por los hermanos Machado (Antonio, y Manuel), sobre un tema de actualidad: la corrupci‚îú‚îÇn pol‚îú¬°tica en el contexto de la etapa final de la Dictadura de Primo de Rivera. Fue un fracaso total, pues el experimento de juntar en verso, y en tono de "alta" comedia, la corrupci‚îú‚îÇn pol‚îú¬°tica en las instituciones, y las andanzas de la alta burgues‚îú¬°a implicada (por eso lo de "alta" comedia"), debi‚îú‚îÇ parecer demasiado para el cultivado p‚îú‚ïëblico de la ‚îú¬Æpoca. En la imagen, capturada en el escenario del Teatro Principal de Zaragoza a mediados de febrero de ese a‚îú‚ñío, aparece a la derecha el poeta Manuel Machado, que simula la lectura de esta obra a la compa‚îú‚ñí‚îú¬°a de Irene L‚îú‚îÇpez Heredia, encargada de su escenificaci‚îú‚îÇn. Inmediata a ‚îú¬Æl, Irene L‚îú‚îÇpez Heredia, con el protag‚îú‚îÇnico papel de "Fernanda". A su lado, el actor Mariano Urdia‚îú¬°n Asquerino, que encarnar‚îú√≠ a "Leopoldo", el burgu‚îú¬Æs metido en oscuros entresijos pol‚îú¬°ticos. Desde 1925 era padre de una ni‚îú‚ñía de nombre "Dulce Nombre de Mar‚îú¬°a", que a‚îú‚ñíos despu‚îú¬Æs ser‚îú¬°a conocida como Mar‚îú¬°a Asquerino. El tremendo c‚îú√≠nido, resignado y sin papel, como ausente. Fuente visual: Foto Mar‚îú¬°n Chivite, para ABC.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65179100, -0.87929200, '0101000020E6100000444DF4F92823ECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24797319632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24797319632.webp', 'https://www.flickr.com/photos/zaragozaantigua/24797319632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24058, 'Coso Medio 1931', 'Foto: Miguel Mar‚îú¬°n Chivite. Celebraciones por la llegada de la Segunda Rep‚îú‚ïëblica, el 14 de abril de 1931. Al fondo, la plaza de la Constituci‚îú‚îÇn. Fuente: Heraldo de Arag‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65171600, -0.87947700, '0101000020E6100000B3B112F3AC24ECBFD5230D6E6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31746954805.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31746954805.webp', 'https://www.flickr.com/photos/zaragozaantigua/31746954805/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24075, 'Calle Ver‚îú‚îÇnica c.1985', 'Vista de los restos del Teatro romano de Zaragoza en el solar entre la calle de La Ver‚îú‚îÇnica (izquierda) y la de San Jorge. Al fondo, calle de Don Jaime I.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65202000, -0.87791900, '0101000020E61000004D2F3196E917ECBF412B306475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36885817824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36885817824.webp', 'https://www.flickr.com/photos/zaragozaantigua/36885817824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24113, 'Calle de Don Jaime I 1908', 'Imagen capturada en la calle de Don Jaime I durante la visita del rey Alfonso XIII el d‚îú¬°a 14 de junio de ese a‚îú‚ñío a diversos eventos relacionados con el primer centenario del asedio franc‚îú¬Æs de 1808. En este caso se trata del descubrimiento de la l‚îú√≠pida conmemorativa del general Antonio Torres Gimeno por su actuaci‚îú‚îÇn el cuatro de agosto de 1808, ubicada en la fachada del inmueble del n‚î¨‚ïë 50 de la calle, en recuerdo del antiguo edificio en el que vivi‚îú‚îÇ el citado general y que fue derribado y reedificado a finales del siglo XIX, siendo ‚îú¬Æste propiedad de Antonio Hern‚îú√≠ndez Fajarn‚îú¬Æs, en cuyos bajos destaca la prestigiosa y gran joyer‚îú¬°a de Jos‚îú¬Æ Tarongi. A la izquierda, vista parcial del Gran Hotel de las Cuatro Naciones y del Universo.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65353100, -0.87820800, '0101000020E6100000F9BCE2A9471AECBF0AF65FE7A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52054175603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52054175603.webp', 'https://www.flickr.com/photos/zaragozaantigua/52054175603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24231, 'Calle de San Andr‚îú¬Æs 1947', 'Vista de la calle de San Andr‚îú¬Æs, con la de San Jorge al fondo, al paso de la comparsa de Gigantes y Cabezudos. Fuente: www.facebook.com/photo.php?fbid=10208729312283778&set...', 1947, 1947, 1947, 'Anos 40', 'CENTRO', 41.65280800, -0.87823100, '0101000020E610000004ABEAE5771AECBF994869368FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28142940636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28142940636.webp', 'https://www.flickr.com/photos/zaragozaantigua/28142940636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24352, 'San Andr‚îú¬Æs a‚îú‚ñíos 20', 'AYUNTAMIENTO ZARAGOZA/Archivo MORA. Finales d‚îú¬Æcada 1920. Iglesia de San Andr‚îú¬Æs (Ap‚îú‚îÇstol), sita en la calle del mismo nombre. Emplazada dentro del muro que delimitaba el barrio jud‚îú¬°o viejo de la ciudad, hay quien opina que fue concebida como sinagoga (menor) hasta que a comienzos del siglo XIII fue reconvertida a cat‚îú‚îÇlica y apost‚îú‚îÇlica parroquia. Muy vinculada a la Cofrad‚îú¬°a de Ganaderos, pr‚îú√≠cticamente se convirti‚îú‚îÇ en su gremial parroquia. De factura modesta, fue construida en ladrillo, siguiendo los est‚îú√≠ndares mud‚îú¬Æjares. Una ‚îú‚ïënica nave cubierta con crucer‚îú¬°a sencilla, testa recta y tres capillas de fondo, y con 5 capillas a cada lado, entre los contrafuertes laterales. En el siglo XVII la Contrarreforma la barroquiz‚îú‚îÇ en forma y estilo, como ilustra el t‚îú¬°mpano quebrado de la puerta de acceso. Ces‚îú‚îÇ sus actividades como parroquia en 1896, siendo derribada en 1930. Su patrimonio art‚îú¬°stico fue repartido entre varias iglesia de la ciudad, como la parroquia de S. Valero. En la imagen, vista de la Iglesia capturada desde el otro lado de la calle de San Andr‚îú¬Æs, sobre el tejadillo de las traseras del actual n‚î¨‚ïë 16 de D. Jaime. A su izquierda queda la Casa y Cofrad‚îú¬°a de Ganaderos de Zaragoza. En la actualidad todo ese espacio est‚îú√≠ ocupado por el enorme bloque de viviendas que chaflanea S. Andr‚îú¬Æs con Ver‚îú‚îÇnica, y llega hasta el Teatro Romano. Un buen mordisco.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65255300, -0.87848700, '0101000020E6100000C2C1DEC4901CECBF0EF450DB86D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14872754253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14872754253.webp', 'https://www.flickr.com/photos/zaragozaantigua/14872754253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24362, 'San Gil 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 24/12/66. Calle Est‚îú¬Æbanes de Zaragoza, desde Don Jaime. Vista de la torre de la iglesia de San Gil.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024671980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024671980.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024671980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22165, 'RS Jos‚îú¬Æ Antonio 1955', 'Imagen centrada en la capilla de la Residencia Sanitaria Jos‚îú¬Æ Antonio, dise‚îú‚ñíada por el arquitecto Fernando Garc‚îú¬°a Mercadal. Adosada a la izquierda del escalonado brazo edilicio que conectaba el original ambulatorio con el cuerpo principal del nuevo hospital, esta dependencia religiosa (modificada, por cierto, respecto a la que aparec‚îú¬°a en la maqueta del proyecto) representaba una leve concesi‚îú‚îÇn al clasicismo dentro del tono racionalista y funcional dise‚îú‚ñío global del conjunto, con su planta circular y llamativa c‚îú‚ïëpula, visible a distancia. Su espacio interior se articulaba en dos plantas, una cripta en el piso inferior, y la capilla propiamente dicha en el piso superior, de m‚îú√≠s altura y culminada por un espacio delimitado por una balaustrada soportada por un entablamiento sobre ocho columnas y cubierto por la c‚îú‚ïëpula. El altar fue ubicado en el prisma adosado a la izquierda, con verticales ventanales y tejado a dos aguas. Esta capilla fue derribada en una de las ampliaciones del complejo hospitalario, posiblemente la acometida por el Instituto Nacional de la Salud a principios de los a‚îú‚ñíos ochenta, cuando adem‚îú√≠s esta "Ciudad Sanitaria Jose Antonio" fue finalmente redenominada "Hospital Miguel Servet". Fuente visual: bancodeimagenesmedicina.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30866903308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30866903308.webp', 'https://www.flickr.com/photos/zaragozaantigua/30866903308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24375, 'Calle de San Andr‚îú¬Æs 1918', 'Imagen de la Iglesia de San Andr‚îú¬Æs (el Protocletos), en la calle del mismo nombre. Hay quien opina que originalmente fue sinagoga (menor) de la juder‚îú¬°a, hasta que a comienzos del s. XIII fue reconvertida a cat‚îú‚îÇlica parroquia, aunque tambi‚îú¬Æn menor, pues hac‚îú¬°a de iglesia gremial de la inmediata Cofrad‚îú¬°a de Ganaderos. Su f‚îú√≠brica era modesta, mud‚îú¬Æjar, en ladrillo. Una ‚îú‚ïënica nave cubierta con crucer‚îú¬°a sencilla, testa recta, tres capillas de fondo, y 5 capillas a cada lado. Su peque‚îú‚ñía torre, en ladrillo, con leves pa‚îú‚ñíos horizontales como leve decoraci‚îú‚îÇn, y remate en techillo inclinado de teja. En el s. XVII la Contrarreforma la barroquiz‚îú‚îÇ, como indica el peque‚îú‚ñío t‚îú¬°mpano quebrado de la puerta. Ces‚îú‚îÇ sus actividades confesionales en 1896, y en 1931 recibi‚îú‚îÇ la visita de la piqueta. Su patrimonio tangible tuvo vida movida, siendo una parte reutilizado, por ejemplo, en la nueva parroquia de San Valero (Delicias). Esta cercana imagen lateral de la iglesia ha sido capturada desde la propia calle de San Andr‚îú¬Æs, casi en la puerta de la Casa de Ganaderos (izquierda), que hab‚îú¬°a estrenado nueva sede en 1914 dise‚îú‚ñíada por Teodoro R‚îú¬°os. Entre iglesia y Casa, un portillo entreabierto anuncia el "Callej‚îú‚îÇn de salida a la calle de San Andr‚îú¬Æs" desde el trasero solar donde se levant‚îú‚îÇ la antigua Casa de la Infanta. Al otro lado de la estrecha calle, viviendas de la manzana de Don Jaime I. Al fondo, peque‚îú‚ñío alero volado de las viviendas de la calle de la Ver‚îú‚îÇnica. Una rama de palma, abandonada en un balc‚îú‚îÇn, dice que la Semana Santa Cat‚îú‚îÇlica ya ha tenido lugar. Fuente: Instituto Amatller de Arte Hisp‚îú√≠nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65255300, -0.87848700, '0101000020E6100000C2C1DEC4901CECBF0EF450DB86D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15894783705.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15894783705.webp', 'https://www.flickr.com/photos/zaragozaantigua/15894783705/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24387, 'San Juan y San Pedro c.1903', 'Cromolitograf‚îú¬°a de Agust‚îú¬°n Allu‚îú¬Æ para postal de la antigua torre parroquial mud‚îú¬Æjar de San Juan y San Pedro, basada en una imagen capturada desde la esquina de la calle Refugio con la calle de San Juan. Esta iglesia hab‚îú¬°a sido levantada en el siglo XIV, de factura modesta, en ladrillo y tapial, pero con una sobresaliente decoraci‚îú‚îÇn mud‚îú¬Æjar en su atalaya. En el XVII recibi‚îú‚îÇ su actualizaci‚îú‚îÇn formal barroca, como era la moda de la ‚îú¬Æpoca, y otros cambios estructuales. Originalmente de San Juan Bautista, o San Juan "el Viejo", para diferenciarla de la de San Juan del Puente, a‚îú‚ñíadi‚îú‚îÇ la denominaci‚îú‚îÇn de San Pedro cuando esa vecina parroquia fue desacralizada en el XVIII. Estaba considerada la quinta gran torre mud‚îú¬Æjar de la ciudad, tras la Magdalena, San Miguel, San Pablo, y San Gil. Fue demolida integralmente en la prodigiosa d‚îú¬Æcada de los 60, sustituida por otro bloque de viviendas m‚îú√≠s. Fuente visual: www.delcampe.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65334000, -0.87761700, '0101000020E6100000793C2D3F7015ECBF969526A5A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23674291889.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23674291889.webp', 'https://www.flickr.com/photos/zaragozaantigua/23674291889/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24399, 'San Juan y San Pedro 1966', 'Vista, desde el interior demolido, de la torre de la iglesia de San Juan y San Pedro, en la confluencia de la calle hom‚îú‚îÇnima con la del Refugio. El proceso de derribo de este edificio se inici‚îú‚îÇ a finales de mayo de 1966 y concluy‚îú‚îÇ con la eliminaci‚îú‚îÇn de su torre pocos meses despu‚îú¬Æs. A espaldas del fot‚îú‚îÇgrafo, la calle de San Juan y San Pedro, por la que se acced‚îú¬°a a la iglesia. Al fondo, a la derecha, traseras del patio del bloque de viviendas de San Jorge n‚î¨‚ïë 3.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65335300, -0.87755500, '0101000020E6100000F71E2E39EE14ECBF2BDF3312A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28123196534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28123196534.webp', 'https://www.flickr.com/photos/zaragozaantigua/28123196534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24402, 'Iglesia de San Gil 1969', 'Vista en altura de la iglesia de San Gil desde la calle de Don Jaime I, con la calle de los Est‚îú¬Æbanes a la derecha. Fuente: www.flickr.com/photos/114031783@N02/', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65279000, -0.87940100, '0101000020E6100000F33AE2900D24ECBFF3936A9F8ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29398562991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29398562991.webp', 'https://www.flickr.com/photos/zaragozaantigua/29398562991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24405, 'Calle Est‚îú¬Æbanes 2003', 'Foto: Javier Torres. Fachada de la iglesia de San Gil recayente a la calle de los Est‚îú¬Æbanes, con el muro producto de los derribos en 2002 de las edificaciones anexas, que luego ser‚îú√≠ rehabilitado. Fuente: www.facebook.com/photo.php?fbid=161205391009071&set=p...', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65283800, -0.87938000, '0101000020E610000016359886E123ECBF04CB113290D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30010083203.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30010083203.webp', 'https://www.flickr.com/photos/zaragozaantigua/30010083203/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24523, 'Calle de San Jorge 1929', 'Dibujo publicitario del local comercial que la Casa Guiral (desde 1940, Guiral Industrias El‚îú¬Æctricas S. A. o GIESA) abri‚îú‚îÇ en los bajos del gran edificio dise‚îú‚ñíado por el joven arquitecto Alberto Huerta Mar‚îú¬°n en la parcela ubicada entre las calles de San Andr‚îú¬Æs y de San Jorge, y construido a principios de la d‚îú¬Æcada. Esta tienda destacaba por su gran exposici‚îú‚îÇn de cristaler‚îú¬°a y por un interesante muestrario de "aparatos de fantas‚îú¬°a" vinculados al moderno mundo de la electricidad aplicada al sector dom‚îú¬Æstico. La referida "fantas‚îú¬°a" parece ser que despist‚îú‚îÇ a los impresores, pues la publicaron boca abajo, con las l‚îú√≠mparas ancladas en el suelo y los pesados motores pegados al techo. En GAZA, gratis et amore, le hemos dado la vuelta a la imagen para restaurar el sentido original que seguramente ten‚îú¬°a Joaqu‚îú¬°n Guiral cuando contrat‚îú‚îÇ esta publicidad. Al fondo, en el centro, ventanal en arco carpanel recayente a la calle de San Andr‚îú¬Æs. A la izquierda, la chaflanera puerta de ingreso correspondiente al n‚îú‚ïëmero 6-8 de la calle de San Jorge. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65299600, -0.87817500, '0101000020E61000000B462575021AECBF9C35785F95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39510007472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39510007472.webp', 'https://www.flickr.com/photos/zaragozaantigua/39510007472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24527, 'Calle de San Jorge 1991', 'Imagen centrada en el referencial chafl‚îú√≠n del n‚î¨‚ïë 17-19 de la calle de San Andr‚îú¬Æs (posiblemente donde antes estuviera la casa del conde de Montemar) realizado en 1922 seg‚îú‚ïën proyecto del arquitecto zaragozano Alberto Huerta Mar‚îú¬°n para Joaqu‚îú¬°n Guiral (desde 1940 GIESA, Guiral Industrias El‚îú¬Æctricas SA), de forma que la planta calle fue habilitada como gran local comercial de productos el‚îú¬Æctricos que inclu‚îú¬°an algunos de los fabricados, primero en la calle de Roda, luego en la planta del camino de San Jos‚îú¬Æ y finalmente en la de la calle de Miguel Servet. Las dos plantas superiores fueron dise‚îú‚ñíadas para uso residencial. Pocos a‚îú‚ñíos despu‚îú¬Æs, el edificio fue rehabilitado de forma integral, desapareciendo el original uso industrial.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.65299600, -0.87817500, '0101000020E61000000B462575021AECBF9C35785F95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43075811201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43075811201.webp', 'https://www.flickr.com/photos/zaragozaantigua/43075811201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24531, 'Calle de San Jorge c.1949', 'Imagen capturada desde cierta altura en el inmueble del n‚î¨‚ïë 3 de la calle de San Jorge, y centrado en el esquinero local comercial con la calle de San Andr‚îú¬Æs (a la izquierda) construido a principios de la d‚îú¬Æcada de los a‚îú‚ñíos 20 seg‚îú‚ïën proyecto del arquitecto zaragozano Alberto Huerta Mar‚îú¬°n, para dar salida a los productos el‚îú¬Æctricos de Joaqu‚îú¬°n Guiral (desde 1940 GIESA, Guiral Industrias El‚îú¬Æctricas SA), construidos primero en calle de Roda, luego en la temporal planta del camino de San Jos‚îú¬Æ, y finalmente en la nueva gran factor‚îú¬°a de la calle de Miguel Servet. Las dos plantas superiores fueron dise‚îú‚ñíadas para uso residencial. Una reforma posterior a‚îú‚ñíadi‚îú‚îÇ una planta extra y elimin‚îú‚îÇ la singular balaustrada que hasta entonces culminaba el edificio, A la derecha y al fondo, la calle de Don Jaime I.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65291300, -0.87817600, '0101000020E6100000213A048E041AECBF0E1137A792D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48414704521.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48414704521.webp', 'https://www.flickr.com/photos/zaragozaantigua/48414704521/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24866, 'Calle de Don Jaime I 1976', 'Imagen capturada desde la altura del inmueble del n‚î¨‚ïë 18 de la calle de Don Jaime I, con vista en perspectiva del denso tr‚îú√≠fico rodado que transitaba por esta c‚îú¬Æntrica v‚îú¬°a de la ciudad antigua, hasta con tres carriles de circulaci‚îú‚îÇn, y el detalle del carril bus ideado para tratar de dar fluidez al servicio de las l‚îú¬°neas de bus, como la n‚î¨‚ïë 32 "G‚îú√≠llego-Delicias", que hab‚îú¬°an sustituido a algunas de las hist‚îú‚îÇricas l‚îú¬°neas de tranv‚îú¬°a en el transporte p‚îú‚ïëblico. Este carril-bus ser‚îú¬°a eliminado despu‚îú¬Æs. La transici‚îú‚îÇn hacia la pacificaci‚îú‚îÇn del tr‚îú√≠fico en esta v‚îú¬°a todav‚îú¬°a sigue su curso.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65301800, -0.87863800, '0101000020E61000002CBB6070CD1DECBF84D9041896D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48088268623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48088268623.webp', 'https://www.flickr.com/photos/zaragozaantigua/48088268623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24917, 'Teatro romano 2003', 'Vista de las obras de rehabilitaci‚îú‚îÇn del Teatro romano en enero de 2003, con la calle de la Ver‚îú‚îÇnica al fondo. Fuente: Agencia EFE.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24375973250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24375973250.webp', 'https://www.flickr.com/photos/zaragozaantigua/24375973250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25066, 'Joan Manuel Serrat 1988', 'Foto: Eduardo Bayona. Teatro Principal de Zaragoza, 1988. Actuaci‚îú‚îÇn del cantante Joan Manuel Serrat (Barcelona, 1943). Nombrado Hijo Adoptivo de Zaragoza en 2016. Fuente: eduardo-elmundoengeneral.blogspot.com.es/2011/01/quizas-p...', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65204800, -0.87931300, '0101000020E610000022533E045523ECBF0BB6114F76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15040714676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15040714676.webp', 'https://www.flickr.com/photos/zaragozaantigua/15040714676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25088, 'J.A. Labordeta 1964', '"10 de marzo [1935] -cumplea‚îú‚ñíos feliz-. Nunca vuelven los infinitos d‚îú¬°as de la infancia..." (Jos‚îú¬Æ Antonio Labordeta, Diario de un n‚îú√≠ufrago). Fuente visual: foto Gerardo Sancho Ramo, capturada en el Teatro Principal, AMZ.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65199400, -0.87944100, '0101000020E6100000815EB8736124ECBF1898158A74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32066721273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32066721273.webp', 'https://www.flickr.com/photos/zaragozaantigua/32066721273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25151, 'Calle Ossau a‚îú‚ñíos 30', 'Acuarela de Ambrosio Ruste, mostrando la calle de Ossau, antes de ser ensanchada en los a‚îú‚ñíos cincuenta. Al fondo, la calle de Casto M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez. Fuente: L‚îú√≠minas de A. Ruste. AMZ 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65323900, -0.87942300, '0101000020E6100000E7340BB43B24ECBF62BCE6559DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31597069924.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31597069924.webp', 'https://www.flickr.com/photos/zaragozaantigua/31597069924/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25187, 'Calle de los Est‚îú¬Æbanes 1980', 'Dibujo realizado en el desemboque de la calle de Jos‚îú¬Æ Pellicer Ossau (antigua de las Moscas) en la de los Est‚îú¬Æbanes y centrado en el lado de la ep‚îú¬°stola de la iglesia parroquial de San Gil Abad, de donde emerge su torre. Al fondo, la calle de Don Jaime I y a la derecha, el final de la calle de Cinegio.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65299400, -0.87962500, '0101000020E6100000D9CEF753E325ECBFFB3DB14E95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53264457311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53264457311.webp', 'https://www.flickr.com/photos/zaragozaantigua/53264457311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25644, 'Calle Ver‚îú‚îÇnica 1966', 'AYUNTAMIENTO DE ZARAGOZA/Gerardo Sancho Ramo. 24/12/1966. Captura desde la calle Ver‚îú‚îÇnica del estado de las cosas en lo que hoy es la plaza Jos‚îú¬Æ Sinu‚îú¬Æs, entonces una manzana de viviendas. Al fondo, la calle Don Jaime I. A la izquierda, el edificio del Teatro Principal. Una unidad 200 de la L‚îú¬°nea 13 "San Jos‚îú¬Æ" del tranv‚îú¬°a, que apenas un a‚îú‚ñío despu‚îú¬Æs se unificar‚îú¬°a con la l‚îú¬°nea 11, "Parque", conformando la nueva L‚îú¬°nea 11 "Parque-San Jos‚îú¬Æ" (la ‚îú‚ïëltima en ser piqueteada, en enero de 1976). En el centro de la imagen, la manzana de viviendas delimitada por Don Jaime, Ver‚îú‚îÇnica (derecha), y la calle Valent‚îú¬°n Zabala (izquierda), est‚îú√≠ empezando a ser preparada para el derribo. A la derecha, el chafl‚îú√≠n del edificio que a‚îú‚ïën perdura en nuestro d‚îú¬°as anuncia el emboque con la calle San Andr‚îú¬Æs. De resultas de esta intervenci‚îú‚îÇn, la calle Ver‚îú‚îÇnica se vio acortada un tramo, la calle Valent‚îú¬°n Zabala desapareci‚îú‚îÇ, y hoy tenemos la Plaza Jos‚îú¬Æ Sinu‚îú¬Æs.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65207200, -0.87880400, '0101000020E6100000EB01F390291FECBF9351651877D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14666062227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14666062227.webp', 'https://www.flickr.com/photos/zaragozaantigua/14666062227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25645, 'Casa de Zaporta c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C‚îú¬°a. 1872-1879. Patio de la Casa de Zaporta, o de la Infanta.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65260900, -0.87750600, '0101000020E61000009D6681768714ECBFA20914B188D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679462819.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679462819.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679462819/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25646, 'San Gil c. 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C‚îú¬°a. 1860-1886. "Torre San Gil".', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65272900, -0.87924400, '0101000020E610000001892650C422ECBF4D13B69F8CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14843521426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14843521426.webp', 'https://www.flickr.com/photos/zaragozaantigua/14843521426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25655, 'Vista parroquia San Gil a‚îú‚ñíos 20', 'Miguel Faci Abad. 1920-25. "Zaragoza. Vista de la parroquia de San Gil." Desde las alturas del Casino Mercantil, ya de tarde, una vista panor‚îú√≠mica hacia el este, que comprende: San Juan y San Pedro, San Gil, la Magdalena, la sede de una entidad local de ahorro (sin su caracter‚îú¬°stico remate en linterna), San Pedro Nolasco, San Andr‚îú¬Æs, San Carlos Borromeo... Fuente visual: "Miguel y Gabriel Faci. Fot‚îú‚îÇgrafos fundadores de la Real Sociedad Fotogr‚îú√≠fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci‚îú‚îÇn Provincial de Zaragoza, 1999.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15339596309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15339596309.webp', 'https://www.flickr.com/photos/zaragozaantigua/15339596309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25656, 'Don Jaime I 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo de 1966 Por la calle Don Jaime I, espectacular riada-marabunta de circulaci‚îú‚îÇn rodada proveniente del Puente de las Piedras. En teor‚îú¬°a hab‚îú¬°a tres carriles, pero muy pl‚îú√≠sticos, y pod‚îú¬°an llegar a cuatro en algunos tramos. Vale que los coches eran m‚îú√≠s "latensardinen", no como los "panzer" de hoy en d‚îú¬°a, pero la tendencia era esta. La imagen est‚îú√≠ tomada en altura, desde un balc‚îú‚îÇn de los n‚îú‚ïëmeros pares, con visual inmediata de las calles San Jorge, a la derecha, M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez, a la izquierda, y la plaza de Ari‚îú‚ñío un poco m‚îú√≠s adelante, y a la izquierda tambi‚îú¬Æn.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65311100, -0.87849600, '0101000020E61000008F56B5A4A31CECBF35D4282499D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15562995082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15562995082.webp', 'https://www.flickr.com/photos/zaragozaantigua/15562995082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25658, 'Ver‚îú‚îÇnica-Zabala 1967', 'Archivo Municipal. Gerardo Sancho Ramo. 1967. Imagen del solar dejado por la manzana derribada entre las calles de la Ver‚îú‚îÇnica y de Zabala, desde la calle de Don Jaime I. Al fondo, el Teatro Principal. En medio, publicidad de una entidad local de ahorro. Este ser‚îú√≠ el emplazamiento de la plaza de Sinu‚îú¬Æs.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65230400, -0.87912600, '0101000020E6100000850662D9CC21ECBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15717640462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15717640462.webp', 'https://www.flickr.com/photos/zaragozaantigua/15717640462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25659, 'Calle de los Est‚îú¬Æbanes 1962', 'Foto: Joan Miquel i Quintilla. Confluencia de la calle de Don Jaime I (desde donde est‚îú√≠ realizada la imagen) y la calle de los Est‚îú¬Æbanes. La pared de la izquierda corresponde a la iglesia de San Gil Abad, y la construcci‚îú‚îÇn donde se ve el quiosco de prensa fue edificio anexo al templo, hoy retirado. Fuente visual: barcelonafotoantic.com/', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16785044566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16785044566.webp', 'https://www.flickr.com/photos/zaragozaantigua/16785044566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25660, 'San Jorge c.1925', 'Imagen levemente a‚îú¬Ærea de la confluencia de la calle San Jorge (izquierda) y San Andr‚îú¬Æs, en un entorno dominado (no solo visualmente) por el reciente edificio de la sede central de una ind‚îú¬°gena entidad de ahorro, levantado justo encima de la piqueteada primero, y llorada despu‚îú¬Æs (a lo aligator) Casa de Zaporta. A la izquierda, aunque invisible, sigue en pie la peque‚îú‚ñía iglesia de San Andr‚îú¬Æs; detr‚îú√≠s, lo mismo sucede con la original iglesia de San Pedro Nolasco. Unos pocos a‚îú‚ñíos despu‚îú¬Æs, ambas ser‚îú√≠n procesadas. Al fondo, la torre de la Magdalena con su particular atav‚îú¬°o barroco-neocl‚îú√≠sico. Fuente visual: Fundaci‚îú‚îÇn Telef‚îú‚îÇnica', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65285400, -0.87797400, '0101000020E610000030A017EE5C18ECBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16824948379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16824948379.webp', 'https://www.flickr.com/photos/zaragozaantigua/16824948379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25661, 'Casa de Zaporta 1860', '"Zaragoza, Patio de la Casa de los Infantes" (sic). Gabriel Zaporta pag‚îú‚îÇ su construcci‚îú‚îÇn en 1550 como casa familiar, en incomparables formas y estilo renacentista. En 1636 pas‚îú‚îÇ a ser propiedad de la familia Albi‚îú‚îÇn, y luego de los Franco. En los siglos XVII y XVIII sigui‚îú‚îÇ cambiando de manos. En el XIX, su enorme espacio fue tabicado para albergar arrendamientos y usos dispares: Liceo Art‚îú¬°stico y Literario, taller de carruajes, taller de carpinter‚îú¬°a y ebanister‚îú¬°a, f‚îú√≠brica de pianos... En 1871, era tal su degradaci‚îú‚îÇn, que su patio fue restaurado, antes de ser arrendado para sede del Casino Mon‚îú√≠rquico Liberal. En la imagen, aspecto parcial del patio central del palacio antes de esa restauraci‚îú‚îÇn, cuando estaba tabicado para delimitar estancias y salas m‚îú√≠s peque‚îú‚ñías. Fuente visual: Charles Clifford, en www.balclis.com/', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65266300, -0.87754700, '0101000020E6100000417E3672DD14ECBF952710768AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17241874332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17241874332.webp', 'https://www.flickr.com/photos/zaragozaantigua/17241874332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25665, 'Calle de Don Jaime I 1924', 'Imagen desde cierta altura del reciente n‚î¨‚ïë 14 (numeraci‚îú‚îÇn actual) de la calle Don Jaime I, chaflanero con el principio de la calle de la Ver‚îú‚îÇnica, que por la derecha se va culebreando hacia la plazuela del mismo nombre. Si en la imagen esta calle parece estrecha, habr‚îú¬°a que haberla visto antes del ensanchamiento realizado al hilo de la construcci‚îú‚îÇn de este nuevo edificio, proyectado por Teodoro R‚îú¬°os Balaguer en formas muy poco usuales para la ciudad. Quedaba sin realizar la parte recayente a la calle de San Andr‚îú¬Æs, cerrada con muro, que ser‚îú√≠ completada a finales de los a‚îú‚ñíos 40, en un estilo completamente diferente, con mucho predicamento local, regionalista, regimentalista. Enfrente, el n‚î¨‚ïë 2 de San Andr‚îú¬Æs, vecino de la iglesia del protocletos, que quedaba a su izquierda. A la izquierda, e inmediato, se deja entrever el solar del futuro n‚î¨‚ïë 16 de Don Jaime I. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1924, 1924, 1924, 'Anos 20', 'CENTRO', 41.65257100, -0.87907600, '0101000020E6100000145AD6FD6321ECBFB5A84F7287D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22513632202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22513632202.webp', 'https://www.flickr.com/photos/zaragozaantigua/22513632202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25666, 'Calle San F‚îú¬Ælix 1967', 'Calle de San F‚îú¬Ælix, previa al derribo del palacio de Ari‚îú‚ñío (derecha). Al fondo, el palacio de los Torrero y la calle de San Voto. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65375400, -0.87866000, '0101000020E610000020B58993FB1DECBF89D00836AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23154550272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23154550272.webp', 'https://www.flickr.com/photos/zaragozaantigua/23154550272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
